# Map escalation tags + scenario hints → plan key
_PLAN_AUTOSELECT = {
    '911/EMS': 'EMS_GENERAL',
    'POLICE': 'POLICE_GENERAL',
    'FIRE': 'FIRE_STRUCTURE',
    'SUICIDE_HOTLINE': 'CRISIS_HOTLINE',
}


def tactical_plan_for(escalation, scenario_text=''):
    """Return the best-fit plan key given an escalation tag + free-text hint."""
    s = (scenario_text or '').lower()
    if escalation == '911/EMS':
        if any(k in s for k in ('chest pain', 'cardiac', 'mi ', 'stemi', 'heart attack')):
            return 'EMS_CARDIAC'
        if any(k in s for k in ('trauma', 'gsw', 'stab', 'mvc', 'crash', 'fall')):
            return 'EMS_TRAUMA'
        if any(k in s for k in ('suicide', 'overdose', 'psych', 'mental')):
            return 'EMS_PSYCH'
        return 'EMS_GENERAL'
    if escalation == 'POLICE':
        if any(k in s for k in ('domestic', 'dv ', 'assault')):
            return 'POLICE_DV'
        if any(k in s for k in ('in progress', 'robbery', 'burglary', 'shooting',
                                 'shots fired', 'active')):
            return 'POLICE_INPROGRESS'
        return 'POLICE_GENERAL'
    if escalation == 'FIRE':
        if any(k in s for k in ('high rise', 'highrise', 'tower')):
            return 'FIRE_HIGH_RISE'
        if any(k in s for k in ('vehicle', 'car fire', 'truck fire')):
            return 'FIRE_VEHICLE'
        return 'FIRE_STRUCTURE'
    return _PLAN_AUTOSELECT.get(escalation, 'GENERAL')


# =============================================================================
# DISPATCH OUTBOX — per-unit inbox of dispatch packets sent by operator/AI
# =============================================================================
# Every "send to unit" produces a DispatchPacket appended to the unit's inbox.
# The unit-receiver page polls / streams the inbox and acknowledges packets.
# Packets carry the tactical plan + snapshot of the call transcript so the unit
# has everything they need without re-fetching the call session.
# =============================================================================

_DISPATCH_OUTBOX_PATH = os.path.join(
    os.path.dirname(os.path.abspath(__file__)),
    'dispatch_outbox.json')


class DispatchOutbox:
    """Persisted per-unit inbox of dispatch packets."""

    def __init__(self):
        self._lock = threading.Lock()
        self._by_unit = {}      # callsign → list[packet]
        self._subscribers = []  # callbacks(callsign, packet)
        self._load()

    def _load(self):
        try:
            if not os.path.exists(_DISPATCH_OUTBOX_PATH):
                return
            with open(_DISPATCH_OUTBOX_PATH, 'r', encoding='utf-8') as f:
                data = json.load(f)
            for cs, packets in (data.get('inboxes') or {}).items():
                self._by_unit[cs] = list(packets)
        except Exception as e:
            _cc_logger.warning(f'dispatch outbox load failed: {e}')

    def _save(self):
        try:
            payload = {'inboxes': self._by_unit}
            with open(_DISPATCH_OUTBOX_PATH, 'w', encoding='utf-8') as f:
                json.dump(payload, f, indent=2, default=str)
        except Exception as e:
            _cc_logger.warning(f'dispatch outbox save failed: {e}')

    def subscribe(self, cb):
        self._subscribers.append(cb)

    def _emit(self, callsign, packet):
        for cb in list(self._subscribers):
            try:
                cb(callsign, packet)
            except Exception as e:
                _cc_logger.error(f'dispatch outbox subscriber failed: {e}')

    def add(self, callsign, packet):
        with self._lock:
            inbox = self._by_unit.setdefault(callsign, [])
            inbox.append(packet)
            # Cap inbox size per unit
            if len(inbox) > 500:
                self._by_unit[callsign] = inbox[-500:]
        self._save()
        self._emit(callsign, packet)

    def list_for(self, callsign, only_pending=False):
        with self._lock:
            inbox = list(self._by_unit.get(callsign) or [])
        if only_pending:
            inbox = [p for p in inbox if p.get('status') in (None, 'pending', 'received')]
        return inbox

    def find(self, callsign, dispatch_id):
        with self._lock:
            for p in self._by_unit.get(callsign) or []:
                if p.get('dispatch_id') == dispatch_id:
                    return p
        return None

    def update_status(self, callsign, dispatch_id, status, by='unit', note=''):
        p = self.find(callsign, dispatch_id)
        if p is None:
            return None
        p['status'] = status
        p.setdefault('history', []).append({
            'ts': time.time(),
            'wall': datetime.now().strftime('%H:%M:%S'),
            'status': status,
            'by': by,
            'note': note,
        })
        self._save()
        self._emit(callsign, p)
        return p

    def all_units(self):
        with self._lock:
            return list(self._by_unit.keys())


# Module-level singleton
dispatch_outbox = DispatchOutbox()


# =============================================================================
# SYSTEM-WINDOW OPERATIONS (Windows-only, stdlib via ctypes)
# Used by AIdispatch to enumerate, observe, focus, and screenshot top-level
# windows on the host OS. The audit tab surfaces this so operator decisions
# (e.g. dispatching a call to a specific human-agent app) can target a
# concrete HWND. All side-effecting calls require the operator OS-control
# toggle to be ON — read-only enumeration and observation are always allowed.
# =============================================================================
class SystemWindowOps:
    """Top-level window enumeration + targeted operations for Win32 hosts."""

    # Win32 constants
    SW_RESTORE = 9
    SW_MINIMIZE = 6
    SW_MAXIMIZE = 3
    GW_OWNER = 4

    def __init__(self):
        self.is_windows = (sys.platform == 'win32')
        if self.is_windows:
            try:
                self._user32 = ctypes.windll.user32
                self._kernel32 = ctypes.windll.kernel32
                self._user32.GetWindowTextLengthW.argtypes = [ctypes.c_void_p]
                self._user32.GetWindowTextW.argtypes = [
                    ctypes.c_void_p, ctypes.c_wchar_p, ctypes.c_int]
                self._user32.IsWindowVisible.argtypes = [ctypes.c_void_p]
                self._user32.GetWindowThreadProcessId.argtypes = [
                    ctypes.c_void_p, ctypes.POINTER(ctypes.c_ulong)]
            except Exception as e:
                self.is_windows = False
                print(f"  [ERR] SystemWindowOps init: {e}")

    # ── Enumeration ────────────────────────────────────────────────
    def enumerate_top_level(self):
        """Return list of dicts: hwnd, title, pid, visible, rect."""
        if not self.is_windows:
            return []
        u = self._user32
        results = []
        ENUM_PROC = ctypes.WINFUNCTYPE(ctypes.c_bool, ctypes.c_void_p, ctypes.c_void_p)

        def _cb(hwnd, _lparam):
            try:
                if not u.IsWindowVisible(hwnd):
                    return True
                length = u.GetWindowTextLengthW(hwnd)
                if length <= 0:
                    return True
                buf = ctypes.create_unicode_buffer(length + 1)
                u.GetWindowTextW(hwnd, buf, length + 1)
                title = buf.value
                if not title:
                    return True
                pid = ctypes.c_ulong(0)
                u.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                rect = self._get_rect(hwnd)
                results.append({
                    'hwnd': int(hwnd) if hwnd else 0,
                    'title': title,
                    'pid': int(pid.value),
                    'rect': rect,
                })
            except Exception:
                pass
            return True

        try:
            u.EnumWindows(ENUM_PROC(_cb), 0)
        except Exception as e:
            print(f"  [ERR] EnumWindows: {e}")
        return results

    def _get_rect(self, hwnd):
        try:
            class RECT(ctypes.Structure):
                _fields_ = [('left', ctypes.c_long), ('top', ctypes.c_long),
                            ('right', ctypes.c_long), ('bottom', ctypes.c_long)]
            r = RECT()
            self._user32.GetWindowRect(hwnd, ctypes.byref(r))
            return (r.left, r.top, r.right, r.bottom)
        except Exception:
            return (0, 0, 0, 0)

    def get_foreground_info(self):
        if not self.is_windows:
            return {'hwnd': 0, 'title': ''}
        try:
            hwnd = self._user32.GetForegroundWindow()
            length = self._user32.GetWindowTextLengthW(hwnd)
            buf = ctypes.create_unicode_buffer(length + 1)
            self._user32.GetWindowTextW(hwnd, buf, length + 1)
            return {'hwnd': int(hwnd) if hwnd else 0, 'title': buf.value}
        except Exception:
            return {'hwnd': 0, 'title': ''}

    # ── Side-effecting actions (gated on operator OS-control toggle) ──
    def _os_control_allowed(self):
        try:
            return (CONFIG.get('os_control_enabled', False)
                    and os.environ.get('CS_OS_CONTROL_ENABLED', '0') == '1')
        except Exception:
            return False

    def focus(self, hwnd):
        """Bring window to foreground. Requires OS control."""
        if not self.is_windows or not self._os_control_allowed():
            return False
        try:
            self._user32.ShowWindow(hwnd, self.SW_RESTORE)
            return bool(self._user32.SetForegroundWindow(hwnd))
        except Exception as e:
            print(f"  [ERR] focus: {e}")
            return False

    def minimize(self, hwnd):
        if not self.is_windows or not self._os_control_allowed():
            return False
        try:
            return bool(self._user32.ShowWindow(hwnd, self.SW_MINIMIZE))
        except Exception:
            return False

    def maximize(self, hwnd):
        if not self.is_windows or not self._os_control_allowed():
            return False
        try:
            return bool(self._user32.ShowWindow(hwnd, self.SW_MAXIMIZE))
        except Exception:
            return False

    def screenshot_window(self, hwnd):
        """PIL screenshot of the rect of the given window. Read-only — no OS-control gate."""
        if not self.is_windows:
            return None
        try:
            l, t, r, b = self._get_rect(hwnd)
            if r - l < 4 or b - t < 4:
                return None
            return ImageGrab.grab(bbox=(l, t, r, b))
        except Exception as e:
            print(f"  [ERR] screenshot_window: {e}")
            return None

    def find_by_title(self, substring):
        """Read-only: return enumerated entries whose title contains substring (case-insensitive)."""
        s = substring.lower()
        return [w for w in self.enumerate_top_level() if s in w['title'].lower()]

# Module-level singleton — the operator owns this
system_windows = SystemWindowOps()


# =============================================================================
# DISPATCH WEB SERVER  —  caller UI + operator console + JSON API + SSE
# Stdlib only (http.server, socketserver). Bound to 127.0.0.1 by default so
# the host is never exposed; flip CC_HTTP_BIND=0.0.0.0 for LAN access.
# A 911-redirector or any external system can POST to /api/call to inject
# a real call. The operator console is token-gated; the token is printed
# on startup and shown in the Tk dashboard.
# =============================================================================
import http.server as _cc_http
import socketserver as _cc_socketserver
import urllib.parse as _cc_urlparse
import secrets as _cc_secrets
import html as _cc_html
import webbrowser as _cc_webbrowser

_CC_HTTP_HOST = os.environ.get('CC_HTTP_BIND', '127.0.0.1')
_CC_HTTP_PORT = int(os.environ.get('CC_HTTP_PORT', '8765'))
_CC_OPERATOR_TOKEN = os.environ.get('CC_OPERATOR_TOKEN') or _cc_secrets.token_urlsafe(16)


def _cc_unit_token(callsign):
    """Deterministic per-unit token derived from operator token + callsign.
    Stable across restarts when the operator token is fixed via env var."""
    h = hashlib.sha256(
        (_CC_OPERATOR_TOKEN + '|' + (callsign or '')).encode('utf-8')
    ).hexdigest()
    return h[:24]


