def _cc_render_base(title, head_extra, body, with_token=True):
    """Substitute placeholders without touching curly braces in body/head_extra
    (so embedded JS object literals survive untouched). Note: the template
    still uses {{ / }} for literal CSS braces; we halve them here.

    The footer nav links inherit the operator token via the {nav_q}
    placeholder so clicking HUB/CONSOLE/etc. doesn't dump the user on an
    "Auth required" page. Pages that should never include the token (the
    public homepage / auth-required stub) pass with_token=False.
    """
    out = _CC_HTML_BASE
    out = out.replace('{title}', _cc_html.escape(title))
    out = out.replace('{head_extra}', head_extra or '')
    out = out.replace('{body}', body or '')
    nav_q = (f'?token={_cc_urlparse.quote(_CC_OPERATOR_TOKEN)}'
             if with_token else '')
    out = out.replace('{nav_q}', nav_q)
    out = out.replace('{{', '{').replace('}}', '}')
    return out


def _cc_action_class(action):
    a = (action or '').upper()
    if 'EMERGENCY' in a or 'ESCALATE' in a:
        return 'emer'
    if 'DISPATCH' in a:
        return 'disp'
    if 'DISMISS' in a or 'BLOCK' in a or 'CLOSE' in a:
        return 'dim'
    return 'good'


def _cc_urgency_color(urgency):
    u = max(0, min(10, int(urgency or 0)))
    if u <= 4:
        t = u / 4.0
        r = int(0x33 + (0xff - 0x33) * t); g = 0xcc
        b = int(0x88 - (0x88 - 0x33) * t)
    else:
        t = (u - 4) / 6.0
        r = 0xff
        g = int(0xcc - (0xcc - 0x33) * t)
        b = int(0x33 - (0x33 - 0x22) * t)
    return f'#{r:02x}{g:02x}{b:02x}'


def _cc_render_homepage():
    """Caller-facing landing page. Anyone redirected here can place a call."""
    body = """
    <h1>Emergency Dispatch — Connect Now</h1>
    <p class="dim">If this is a life-threatening emergency, please describe what is
    happening as clearly as possible. An AI dispatch agent will be assigned
    instantly and will route you to the right responder.</p>
    <div class="panel" style="background:#1f0d1d; border:2px solid #aa2233">
      <h2 style="color:#ffbbcc; margin-bottom:6px">📞 Live Voice Call</h2>
      <p class="dim" style="margin:6px 0 12px">Speak directly to the dispatch AI. Hold to talk; the AI will transcribe, decide, and answer back out loud.</p>
      <button id="voicebtn" class="primary" style="background:#aa2233; padding:14px 22px; font-size:1.1em">Start Voice Call</button>
    </div>
    <div class="panel" style="background:#0d1f1d; border:2px solid #2a8a55">
      <h2 style="color:#bbffcc; margin-bottom:6px">💬 Text 911 (silent)</h2>
      <p class="dim" style="margin:6px 0 12px">If you can't speak safely — texts only. The dispatcher reads
        every message in real time and can text back. Use this if a voice
        call would put you in danger.</p>
      <button id="text911btn" class="primary" style="background:#2a8a55; padding:14px 22px; font-size:1.1em">Open Text 911 Thread</button>
    </div>
    <div class="panel">
      <h2>Quick reason</h2>
      <div class="quick-grid">
        <button class="q-emer"    data-q="medical"   data-text="Medical emergency — I need help now">🚑  Medical / Injury</button>
        <button class="q-violence" data-q="violence" data-text="Someone is being violent — I need police">🛡  Violence / Police</button>
        <button class="q-fire"    data-q="fire"      data-text="There is a fire — please send fire department">🔥  Fire</button>
        <button class="q-suicide" data-q="suicide"   data-text="I need to talk to someone, I am in crisis">🤝  Crisis / Suicide</button>
        <button class="q-tech"    data-q="tech"      data-text="Technical issue, not life-threatening">🛠  Technical / Other</button>
        <button class="q-other"   data-q="info"      data-text="Just need information">❓  Information</button>
      </div>
    </div>
    <div class="panel">
      <h2>Place a call</h2>
      <form id="callform">
        <div class="row">
          <div><label>Your phone (optional)</label>
               <input name="phone" id="phone" placeholder="+1 555 000 1234" autocomplete="tel"></div>
        </div>
        <label style="margin-top:12px; display:block">What is happening?</label>
        <textarea name="text" id="text" required
                  placeholder="Describe the situation in your own words..."></textarea>
        <div class="row" style="margin-top:12px">
          <button type="submit" class="primary">Connect to Dispatch AI</button>
        </div>
      </form>
    </div>
    <p class="dim small">Bound to localhost. Your transcript stays on this machine.
    A unique call number will be generated for your reference.</p>
    <script>
      document.querySelectorAll('button[data-q]').forEach(b => {
        b.onclick = (e) => {
          e.preventDefault();
          document.getElementById('text').value = b.dataset.text;
          document.getElementById('callform').requestSubmit();
        };
      });
      // Capture precise location and post it to the new session.
      // Best-effort: failure is silent (IP geolocation is the fallback).
      function shareLocation(callId) {
        if (!('geolocation' in navigator)) return;
        navigator.geolocation.getCurrentPosition((pos) => {
          fetch('/api/call/' + encodeURIComponent(callId) + '/location', {
            method:'POST', headers:{'content-type':'application/json'},
            body: JSON.stringify({
              lat: pos.coords.latitude,
              lon: pos.coords.longitude,
              accuracy_m: pos.coords.accuracy,
              source: 'browser'
            })
          });
        }, (err) => console.warn('geolocation denied:', err.message),
        {enableHighAccuracy: true, timeout: 8000, maximumAge: 60000});
      }
      document.getElementById('callform').onsubmit = async (e) => {
        e.preventDefault();
        const phone = document.getElementById('phone').value || 'web-' + Math.random().toString(36).slice(2,8);
        const text  = document.getElementById('text').value;
        const r = await fetch('/api/call', {
          method:'POST', headers:{'content-type':'application/json'},
          body: JSON.stringify({phone, text})
        });
        const j = await r.json();
        if (j.call_id) {
          shareLocation(j.call_id);
          location.href = '/call/' + encodeURIComponent(j.call_id);
        } else alert('Failed: ' + (j.error || 'unknown'));
      };
      document.getElementById('voicebtn').onclick = async () => {
        const phone = document.getElementById('phone').value || 'voice-' + Math.random().toString(36).slice(2,8);
        const r = await fetch('/api/call', {
          method:'POST', headers:{'content-type':'application/json'},
          body: JSON.stringify({phone, text: '[voice call placed]'})
        });
        const j = await r.json();
        if (j.call_id) {
          shareLocation(j.call_id);
          location.href = '/voice/' + encodeURIComponent(j.call_id);
        } else alert('Failed: ' + (j.error || 'unknown'));
      };
      document.getElementById('text911btn').onclick = async () => {
        const phone = document.getElementById('phone').value || 'sms-' + Math.random().toString(36).slice(2,8);
        const r = await fetch('/api/text911/start', {
          method:'POST', headers:{'content-type':'application/json'},
          body: JSON.stringify({phone})
        });
        const j = await r.json();
        if (j.call_id) {
          shareLocation(j.call_id);
          location.href = '/text911/' + encodeURIComponent(j.call_id);
        } else alert('Failed: ' + (j.error || 'unknown'));
      };
    </script>
    """
    return _cc_render_base('Emergency Dispatch', '', body)


def _cc_render_call_page(sess):
    decisions = sess.get('decisions') or []
    last = decisions[-1] if decisions else None
    agg = (last or {}).get('aggregate') or {}
    action = (last or {}).get('action') or 'pending'
    response = (last or {}).get('response') or 'Connecting you now...'
    escalation = (last or {}).get('escalation') or '—'
    cls = _cc_action_class(action)
    transcript_html = ''
    for ch in sess.get('chunks', []):
        transcript_html += f'<div class="dim small">you said:</div><div>{_cc_html.escape(ch)}</div>'
    call_id_safe = _cc_urlparse.quote(sess['call_id'], safe='')
    loc = sess.get('location') or {}
    loc_text = _cc_html.escape(_cc_geo_blurb(loc)) if loc else 'unknown'
    loc_class = 'good' if (loc and loc.get('source') == 'browser') else (
        'warn' if loc else 'dim')
    body = f"""
    <h1>Call Connected</h1>
    <div class="panel">
      <div class="row">
        <div><div class="dim small">CALL NUMBER</div>
             <div class="mono" style="font-size:1.5em">{_cc_html.escape(sess['call_number'])}</div></div>
        <div><div class="dim small">DISPATCH AI</div>
             <div style="font-size:1.5em">{_cc_html.escape(sess['ai_id'])}</div></div>
        <div><div class="dim small">STATUS</div>
             <div><span class="pill {cls}">{_cc_html.escape(sess.get('status','?'))}</span></div></div>
      </div>
    </div>
    <div class="panel">
      <h2>📍 Your Location <span class="pill {loc_class}" id="locpill">{loc_text}</span></h2>
      <p class="dim small" id="locnote">
        {'Precise location shared.' if loc and loc.get('source') == 'browser'
          else 'Tap the button below to share your precise location with dispatch — this helps responders reach you faster.'}
      </p>
      <button id="locbtn" class="primary">📍 Share my precise location</button>
    </div>
    <div class="panel">
      <h2>Current routing decision</h2>
      <p><strong class="{cls}">{_cc_html.escape(action)}</strong>
         — escalation: <strong>{_cc_html.escape(str(escalation))}</strong></p>
      <p>{_cc_html.escape(response)}</p>
      <div class="row dim small">
        <div>intent: {_cc_html.escape(str(agg.get('intent','?')))}</div>
        <div>urgency: {agg.get('urgency', 0)}</div>
        <div>psych: {_cc_html.escape(str(agg.get('psych_state','?')))}</div>
        <div>confidence: {agg.get('confidence', 0)}</div>
      </div>
    </div>
    <div class="panel">
      <h2>Continue talking</h2>
      <p class="dim small">Prefer to actually speak? <a href="/voice/{call_id_safe}">📞 Switch to voice call</a></p>
      <form id="speakform">
        <textarea id="more" placeholder="Add more information..."></textarea>
        <div class="row" style="margin-top:8px">
          <button type="submit" class="primary">Send</button>
          <button type="button" id="hangup" class="danger">Hang Up</button>
        </div>
      </form>
    </div>
    <div class="panel">
      <h2>Transcript</h2>
      {transcript_html or '<p class="dim">no chunks yet</p>'}
    </div>
    <script>
      const callId = {json.dumps(sess['call_id'])};
      document.getElementById('speakform').onsubmit = async (e) => {{
        e.preventDefault();
        const t = document.getElementById('more').value;
        if (!t) return;
        await fetch('/api/call/' + encodeURIComponent(callId) + '/chunk', {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{text: t}})
        }});
        location.reload();
      }};
      document.getElementById('hangup').onclick = async () => {{
        await fetch('/api/call/' + encodeURIComponent(callId) + '/end', {{method:'POST'}});
        location.href = '/';
      }};
      document.getElementById('locbtn').onclick = () => {{
        const note = document.getElementById('locnote');
        if (!('geolocation' in navigator)) {{
          note.textContent = 'This browser cannot provide precise location.';
          return;
        }}
        note.textContent = 'Requesting permission...';
        navigator.geolocation.getCurrentPosition((pos) => {{
          fetch('/api/call/' + encodeURIComponent(callId) + '/location', {{
            method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{
              lat: pos.coords.latitude, lon: pos.coords.longitude,
              accuracy_m: pos.coords.accuracy, source: 'browser'
            }})
          }}).then(() => {{ note.textContent = 'Precise location shared with dispatch.'; }});
        }}, (err) => {{
          note.textContent = 'Location denied: ' + err.message;
        }}, {{enableHighAccuracy: true, timeout: 10000}});
      }};
      // Auto-refresh every 3s while call is active
      if ({json.dumps(sess.get('status') == 'active')}) {{
        setTimeout(() => location.reload(), 3000);
      }}
    </script>
    """
    return _cc_render_base(f"Call {sess['call_number']}", '', body)


def _cc_render_voice_page(sess):
    """Live voice-call page. Browser-native:
       - getUserMedia + MediaRecorder for audio capture
       - SpeechRecognition for in-browser STT (Chrome/Edge), with audio-upload
         fallback to /api/call/<id>/audio (server-side STT if available)
       - SpeechSynthesis for AI reply playback (any modern browser)
       - SSE stream subscribed to push the AI's response the moment it lands
    """
    cid = sess['call_id']
    cn  = sess.get('call_number', '')
    body = f"""
    <h1>📞 Voice Call — {_cc_html.escape(cn)}</h1>
    <div class="panel" id="callbar">
      <div class="row">
        <div><div class="dim small">DISPATCH AI</div><div style="font-size:1.4em">{_cc_html.escape(sess['ai_id'])}</div></div>
        <div><div class="dim small">CALL #</div><div class="mono" style="font-size:1.4em">{_cc_html.escape(cn)}</div></div>
        <div><div class="dim small">STATUS</div><div id="statlbl"><span class="pill good">connecting...</span></div></div>
        <div><div class="dim small">MIC</div><div id="miclbl"><span class="pill dim">idle</span></div></div>
        <div><div class="dim small">LOCATION</div><div id="loclbl"><span class="pill dim">acquiring...</span></div></div>
      </div>
    </div>
    <div class="panel" style="text-align:center">
      <button id="talkbtn" class="primary" style="padding:30px 50px; font-size:1.4em; border-radius:50%; background:#226644; min-width:220px">
        🎤<br>Hold to Talk
      </button>
      <div class="dim small" style="margin-top:8px">
        Hold the button (or press <strong>Space</strong>) and speak. Release to send.
      </div>
      <div style="margin-top:14px">
        <label class="small dim"><input type="checkbox" id="ttson" checked> AI speaks responses out loud</label>
        <label class="small dim" style="margin-left:14px"><input type="checkbox" id="autodetect" checked> Auto end-of-utterance</label>
      </div>
      <div style="margin-top:10px; display:flex; align-items:center; justify-content:center; gap:10px">
        <label class="small dim" for="rate-slider">TTS speed:</label>
        <input type="range" id="rate-slider" min="0.8" max="1.6" step="0.05" value="1.20" style="width:200px; vertical-align:middle">
        <span class="small dim" id="rate-label">1.20×</span>
      </div>
      <script>
        (function(){{
          var s=document.getElementById('rate-slider'), l=document.getElementById('rate-label');
          if(s&&l){{ s.addEventListener('input',function(){{ l.textContent = parseFloat(s.value).toFixed(2)+'×'; }}); }}
        }})();
      </script>
    </div>
    <div class="panel">
      <h3>Transcript</h3>
      <div id="log" style="max-height:50vh; overflow-y:auto"></div>
    </div>
    <div class="row">
      <button id="hangup" class="danger" style="padding:14px">Hang Up</button>
      <button id="textfallback">Switch to text only</button>
    </div>
    <script>
      const callId = {json.dumps(cid)};
      const logEl = document.getElementById('log');
      const stat = document.getElementById('statlbl');
      const mic  = document.getElementById('miclbl');
      const talk = document.getElementById('talkbtn');

      function append(role, text, cls) {{
        const d = document.createElement('div');
        d.style.padding = '6px 10px';
        d.style.margin = '4px 0';
        d.style.borderLeft = '3px solid ' + (role==='you'?'#66ccff':'#ffaa33');
        d.style.background = '#161636';
        d.innerHTML = '<div class="dim small">' + role + '</div><div>' + text.replace(/</g,'&lt;') + '</div>';
        if (cls) d.classList.add(cls);
        logEl.appendChild(d);
        logEl.scrollTop = logEl.scrollHeight;
      }}
      function setStat(t, c) {{ stat.innerHTML = '<span class="pill ' + (c||'good') + '">' + t + '</span>'; }}
      function setMic(t, c) {{ mic.innerHTML = '<span class="pill ' + (c||'dim') + '">' + t + '</span>'; }}

      // ── In-browser STT (Web Speech API) ──
      const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
      let recognition = null;
      let recognizing = false;
      let lastChunk = '';
      if (SR) {{
        recognition = new SR();
        recognition.continuous = true;
        recognition.interimResults = true;
        recognition.lang = navigator.language || 'en-US';
        recognition.onresult = (ev) => {{
          let final = '';
          for (let i = ev.resultIndex; i < ev.results.length; i++) {{
            const r = ev.results[i];
            if (r.isFinal) final += r[0].transcript + ' ';
          }}
          if (final.trim()) {{
            lastChunk = final.trim();
            append('you', lastChunk);
            sendChunk(lastChunk);
          }}
        }};
        recognition.onerror = (e) => {{ setMic('error: ' + e.error, 'emer'); }};
        recognition.onend = () => {{ recognizing = false; setMic('idle'); }};
      }}

      // ── Background continuous audio recorder ──
      // Runs in parallel with SpeechRecognition so we get BOTH the live
      // transcript AND the raw audio file at hangup. Even Chrome/Edge
      // users now get an .webm artifact saved server-side. Audio is
      // chunked every 5s so we don't lose everything if the page closes
      // unexpectedly.
      let mediaRecorder = null;
      let chunks = [];
      let bgRecorder = null;
      async function ensureRecorder() {{
        if (mediaRecorder) return mediaRecorder;
        const stream = await navigator.mediaDevices.getUserMedia({{audio: true}});
        mediaRecorder = new MediaRecorder(stream);
        mediaRecorder.ondataavailable = (e) => {{ if (e.data && e.data.size) chunks.push(e.data); }};
        mediaRecorder.onstop = async () => {{
          const blob = new Blob(chunks, {{type: mediaRecorder.mimeType || 'audio/webm'}});
          chunks = [];
          if (blob.size < 800) {{ setMic('idle'); return; }}
          setMic('uploading...', 'warn');
          const buf = await blob.arrayBuffer();
          const b64 = btoa(String.fromCharCode(...new Uint8Array(buf)));
          const r = await fetch('/api/call/' + encodeURIComponent(callId) + '/audio', {{
            method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{audio_b64: b64, mime: blob.type}})
          }});
          const j = await r.json();
          if (j.transcript) {{
            append('you', j.transcript + ' (server STT)');
            // The audio endpoint already feeds the chunk to the call.
          }} else {{
            append('you', '(audio sent — no server STT available; using clip only)');
          }}
          setMic('idle');
        }};
        return mediaRecorder;
      }}
      async function startBgRecorder() {{
        if (bgRecorder) return;
        try {{
          const stream = await navigator.mediaDevices.getUserMedia({{audio: true}});
          bgRecorder = new MediaRecorder(stream, {{mimeType: 'audio/webm'}});
          bgRecorder.ondataavailable = async (e) => {{
            if (!e.data || e.data.size < 800) return;
            try {{
              const buf = await e.data.arrayBuffer();
              const b64 = btoa(String.fromCharCode(...new Uint8Array(buf)));
              // Send-and-forget: failure here doesn't break the call
              fetch('/api/call/' + encodeURIComponent(callId) + '/audio', {{
                method:'POST', headers:{{'content-type':'application/json'}},
                body: JSON.stringify({{audio_b64: b64, mime: 'audio/webm', bg: true}})
              }}).catch(()=>{{}});
            }} catch (e) {{}}
          }};
          // Emit a chunk every 5s so we don't lose audio on page close
          bgRecorder.start(5000);
        }} catch (e) {{
          console.warn('bg recorder failed:', e);
        }}
      }}

      // ── Send a transcribed chunk to the AI ──
      async function sendChunk(text) {{
        await fetch('/api/call/' + encodeURIComponent(callId) + '/chunk', {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{text}})
        }});
      }}

      // ── Hold-to-talk ──
      let holding = false;
      async function startTalking() {{
        if (holding) return;
        holding = true;
        talk.style.background = '#aa2233';
        setMic('listening...', 'good');
        if (recognition && !recognizing) {{
          try {{ recognition.start(); recognizing = true; }} catch (e) {{}}
        }} else if (!recognition) {{
          // browser has no SR — fall back to recording audio
          const mr = await ensureRecorder();
          chunks = [];
          mr.start();
        }}
      }}
      function stopTalking() {{
        if (!holding) return;
        holding = false;
        talk.style.background = '#226644';
        if (recognition && recognizing) {{ try {{ recognition.stop(); }} catch (e) {{}} }}
        if (!recognition && mediaRecorder && mediaRecorder.state === 'recording') {{
          mediaRecorder.stop();
          setMic('processing...', 'warn');
        }}
      }}
      talk.addEventListener('mousedown', startTalking);
      talk.addEventListener('mouseup', stopTalking);
      talk.addEventListener('mouseleave', stopTalking);
      talk.addEventListener('touchstart', (e) => {{ e.preventDefault(); startTalking(); }}, {{passive:false}});
      talk.addEventListener('touchend', (e) => {{ e.preventDefault(); stopTalking(); }});
      window.addEventListener('keydown', (e) => {{ if (e.code === 'Space' && !e.repeat) {{ e.preventDefault(); startTalking(); }} }});
      window.addEventListener('keyup', (e) => {{ if (e.code === 'Space') {{ e.preventDefault(); stopTalking(); }} }});

      // ── TTS for AI replies ────────────────────────────────────────────
      // The voice page is a real phone call — speech rate is bumped so the
      // dispatcher AI doesn't sound sluggish. Emergency replies get a small
      // additional boost (1.30 vs 1.20) and slightly higher pitch so they
      // feel urgent. We always cancel() the prior utterance before speaking
      // the next decision, so the caller hears the most current information
      // (not stale lines from earlier chunks).
      let _voicesCache = [];
      function _pickVoice() {{
        try {{
          const v = window.speechSynthesis.getVoices();
          if (!v || !v.length) return null;
          _voicesCache = v;
          // Prefer a clear English voice. Microsoft/Google are usually best on Win/Chrome.
          const order = ['Microsoft Aria', 'Microsoft Jenny', 'Microsoft Guy',
                         'Google US English', 'Samantha', 'Alex', 'Daniel'];
          for (const name of order) {{
            const m = v.find(x => x.name && x.name.includes(name));
            if (m) return m;
          }}
          return v.find(x => (x.lang||'').startsWith('en')) || v[0];
        }} catch (e) {{ return null; }}
      }}
      // Voices load asynchronously in some browsers
      if ('speechSynthesis' in window) {{
        try {{ window.speechSynthesis.getVoices(); }} catch(e) {{}}
        window.speechSynthesis.onvoiceschanged = _pickVoice;
      }}
      function speak(text, isEmergency) {{
        if (!document.getElementById('ttson').checked) return;
        if (!('speechSynthesis' in window)) return;
        try {{
          // Always cancel queued utterances so the AI stays current
          window.speechSynthesis.cancel();
          const u = new SpeechSynthesisUtterance(text);
          // Operator-controlled rate via slider; emergency adds +0.10
          const slider = document.getElementById('rate-slider');
          const baseRate = slider ? parseFloat(slider.value) : 1.20;
          u.rate  = isEmergency ? Math.min(1.6, baseRate + 0.10) : baseRate;
          u.pitch = isEmergency ? 1.10 : 1.00;
          u.volume = 1.0;
          const voice = _pickVoice();
          if (voice) u.voice = voice;
          window.speechSynthesis.speak(u);
        }} catch (e) {{}}
      }}

      // ── SSE: push AI replies as they happen ──
      // No token needed for the public stream of THIS call only.
      const es = new EventSource('/api/call/' + encodeURIComponent(callId) + '/stream');
      es.addEventListener('decision', ev => {{
        const m = JSON.parse(ev.data);
        const isEmer = (m.action || '').includes('EMERGENCY')
                    || (m.action || '').includes('ESCALATE');
        if (m.action) setStat(m.action, isEmer ? 'emer' : ((m.action || '').includes('DISPATCH') ? 'disp' : 'good'));
        if (m.response) {{
          append('ai', m.response);
          speak(m.response, isEmer);
        }}
      }});
      es.addEventListener('end', ev => {{
        setStat('ended', 'dim');
        es.close();
      }});
      es.onerror = () => {{}};

      // ── Hang up / fallback ──
      document.getElementById('hangup').onclick = async () => {{
        // Flush the background recorder so the last audio chunk lands
        // before the session is closed and artifacts saved.
        try {{
          if (bgRecorder && bgRecorder.state === 'recording') {{
            bgRecorder.requestData();
            bgRecorder.stop();
            // Brief settle so the final ondataavailable fires
            await new Promise(r => setTimeout(r, 250));
          }}
        }} catch (e) {{}}
        await fetch('/api/call/' + encodeURIComponent(callId) + '/end', {{method:'POST'}});
        location.href = '/';
      }};
      document.getElementById('textfallback').onclick = () => {{
        location.href = '/call/' + encodeURIComponent(callId);
      }};

      // Permission warm-up + start the background recorder for audio archive
      if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {{
        navigator.mediaDevices.getUserMedia({{audio: true}})
          .then((s) => {{
            s.getTracks().forEach(t=>t.stop());
            setStat('connected', 'good');
            // Kick off background continuous recorder so the operator
            // gets a full audio archive even when SpeechRecognition is
            // doing the live STT.
            startBgRecorder();
          }})
          .catch(() => {{ setStat('mic blocked', 'emer'); }});
      }} else {{
        setStat('no mic API', 'emer');
      }}

      // ── Location: request precise fix immediately, fall back to IP geo ──
      function setLoc(t, c) {{
        document.getElementById('loclbl').innerHTML =
          '<span class="pill ' + (c||'dim') + '">' + t + '</span>';
      }}
      if ('geolocation' in navigator) {{
        navigator.geolocation.getCurrentPosition((pos) => {{
          fetch('/api/call/' + encodeURIComponent(callId) + '/location', {{
            method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{
              lat: pos.coords.latitude, lon: pos.coords.longitude,
              accuracy_m: pos.coords.accuracy, source: 'browser'
            }})
          }});
          setLoc(`pinned ±${{Math.round(pos.coords.accuracy)}}m`, 'good');
        }}, (err) => {{
          setLoc('IP geolocation only', 'warn');
        }}, {{enableHighAccuracy: true, timeout: 8000}});
      }} else {{
        setLoc('IP geolocation only', 'warn');
      }}

      if (!SR) {{
        const note = document.createElement('div');
        note.className = 'dim small';
        note.style.marginTop = '8px';
        note.innerHTML = 'Browser has no built-in speech recognition. Audio will be uploaded for server-side processing instead.';
        document.getElementById('callbar').appendChild(note);
      }}
    </script>
    """
    return _cc_render_base(f"Voice Call {cn}", '', body)


def _cc_render_text911_page(sess):
    """Caller-facing silent SMS-style emergency thread. Same dispatch
    pipeline as voice; user types short messages, AI replies inline."""
    cid = sess.get('call_id') or ''
    body = f"""
    <h1>💬 Text 911 — Silent Thread</h1>
    <p class="dim small">
      Type your situation in short messages. The dispatcher reads every word.
      Your messages and the AI's replies are saved as evidence.
      Stay quiet — every keystroke counts.
    </p>
    <div class="panel">
      <div class="row" style="align-items:center; margin-bottom:6px">
        <div><b>Call #</b> {_cc_html.escape(sess.get('call_number') or '—')}</div>
        <div><b>AI</b> {_cc_html.escape(sess.get('ai_id') or '—')}</div>
        <div style="margin-left:auto"><span id="status" class="pill dim">connecting...</span></div>
      </div>
      <div id="thread" style="background:#0a0e16; border:2px solid var(--gold);
                              padding:10px; min-height:280px;
                              max-height:55vh; overflow-y:auto;
                              font-family:monospace; line-height:1.6"></div>
    </div>
    <div class="panel">
      <textarea id="msg" rows="3" style="width:100%"
                placeholder="What's happening? Address? Who's there?"
                autofocus></textarea>
      <div class="row" style="margin-top:8px">
        <button class="primary" id="send-btn" style="background:#2a8a55; flex:1">Send</button>
        <button class="danger"  id="end-btn"  style="background:#aa2233">End Thread</button>
      </div>
      <div class="dim small" style="margin-top:6px">Press Ctrl+Enter to send. Your location is shared automatically.</div>
    </div>
    <script>
      const callId = {json.dumps(cid)};
      const thread = document.getElementById('thread');
      const status = document.getElementById('status');
      function esc(s) {{
        return (s||'').replace(/[&<>]/g, c => ({{'&':'&amp;','<':'&lt;','>':'&gt;'}})[c]);
      }}
      function addMsg(side, text, ts) {{
        const div = document.createElement('div');
        const ttl = new Date().toTimeString().slice(0,8);
        div.innerHTML = side === 'me'
          ? `<div style="text-align:right; margin:4px 0; color:#bbffcc">
               <span style="background:#0a4d2a; padding:6px 10px;
                            border-radius:10px; display:inline-block; max-width:80%">${{esc(text)}}</span>
               <span class="dim small" style="margin-left:6px">${{ttl}}</span>
             </div>`
          : `<div style="margin:4px 0; color:#fff8d6">
               <span class="dim small">[${{ttl}}] AI →</span>
               <span style="background:#1a2a4a; padding:6px 10px;
                            border-radius:10px; display:inline-block; max-width:80%">${{esc(text)}}</span>
             </div>`;
        thread.appendChild(div);
        thread.scrollTop = thread.scrollHeight;
      }}
      // Share GPS location automatically
      if (navigator.geolocation) {{
        navigator.geolocation.getCurrentPosition(p => {{
          fetch('/api/call/' + encodeURIComponent(callId) + '/location', {{
            method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{
              lat: p.coords.latitude, lon: p.coords.longitude,
              accuracy_m: p.coords.accuracy, source: 'browser'
            }})
          }}).then(() => {{ status.textContent = 'location shared'; status.className='pill good'; }});
        }}, e => {{ status.textContent = 'no GPS — IP only'; status.className='pill warn'; }},
        {{ enableHighAccuracy:true, timeout:8000 }});
      }}
      async function send() {{
        const inp = document.getElementById('msg');
        const text = (inp.value||'').trim();
        if (!text) return;
        addMsg('me', text);
        inp.value = '';
        const r = await fetch('/api/text911/' + encodeURIComponent(callId) + '/send', {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{text}})
        }});
        const j = await r.json();
        if (j.reply) addMsg('ai', j.reply);
        if (j.escalation && j.escalation !== 'NON_EMERGENCY') {{
          status.textContent = 'DISPATCHED: ' + j.escalation;
          status.className='pill emer';
        }}
      }}
      document.getElementById('send-btn').onclick = send;
      document.getElementById('msg').addEventListener('keydown', e => {{
        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {{ e.preventDefault(); send(); }}
      }});
      document.getElementById('end-btn').onclick = async () => {{
        await fetch('/api/call/' + encodeURIComponent(callId) + '/end', {{method:'POST'}});
        status.textContent = 'thread ended';
        status.className='pill dim';
      }};
      // Poll for AI replies / dispatcher comms via SSE
      try {{
        const es = new EventSource('/api/call/' + encodeURIComponent(callId) + '/stream');
        es.addEventListener('hello', () => {{
          if (status.className === 'pill dim') {{ status.textContent='connected'; status.className='pill good'; }}
        }});
        es.addEventListener('decision', ev => {{
          try {{
            const m = JSON.parse(ev.data);
            // Skip the replay event so we don't double-render the first reply
            if (m.replay) return;
            if (m.response) addMsg('ai', m.response);
          }} catch (e) {{}}
        }});
      }} catch (e) {{}}
    </script>
    """
    return _cc_render_base('Text 911', '', body, with_token=False)


# =============================================================================
# HUB + 22 INDIVIDUAL BROWSER ROUTES
# Every Tk tab/window gets a dedicated URL so operators can drag tabs between
# browser windows freely.
# =============================================================================
_HUB_ROUTES = [
    # (path, title, description, category)
    ('/console',         '🛡 Operator Console',    'CAD-style 3-pane: incidents · detail · units + map.', 'dispatch'),
    ('/livecalls',       '🟢 Live Calls Floor',    'Caller cards prioritizing what each caller said.', 'dispatch'),
    ('/audit',           '🔍 Dispatch Audit',      'Full per-call AI reasoning + decision timeline.', 'dispatch'),
    ('/map',             '🗺  Caller Map',         'Full-screen world map of every active call.', 'dispatch'),
    ('/phone',           '📞 Caller Phone',        'Place a call directly from the browser.', 'dispatch'),
    ('/',                '💬 Caller Home',         'Public page — voice + text 911 entry points.', 'dispatch'),
    ('/units',           '🚑 Unit Roster',          'Fleet status + add/remove units.', 'dispatch'),
    ('/timeline',        '📜 Incident Timeline',   'CAD timeline for the latest active incident.', 'dispatch'),
    ('/dispatch',        '📡 Dispatch Sender',     'Send tactical packets + transcripts to units.', 'dispatch'),
    ('/dispatch/inboxes','📟 Unit Inboxes',        'Per-unit dispatch receivers + tokens.',          'dispatch'),
    # Network monitor surfaces
    ('/netmon',          '⬢ Network Monitor',     'Connection forensics overview.', 'forensics'),
    ('/netmon/connections',     '🔗 Connections',         'All tracked dispatch connections.', 'forensics'),
    ('/netmon/location',  '📍 Location Verify',     'Multi-method location verification.', 'forensics'),
    ('/netmon/deductions','🚨 Deductions',          'Security deduction feed.', 'forensics'),
    ('/netmon/alerts',    '⚠  Alerts',              'Alert feed.', 'forensics'),
    ('/netmon/geoip',     '🌐 GeoIP Cache',         'Cached IP geolocations.', 'forensics'),
    ('/netmon/services',  '🛠  Services',           'Service resolver (IP→provider).', 'forensics'),
    ('/netmon/detectors', '🔬 Detectors',           'Active detector subsystems.', 'forensics'),
    # Internals (consciousness simulator)
    ('/internals',         '🧠 Simulator Internals', 'Consciousness simulator dashboard.', 'internals'),
    ('/internals/overview','📊 Overview',            'C-score, Phi, Omega, entities.', 'internals'),
    ('/internals/entities','👥 Entities',            'All consciousness entities.', 'internals'),
    ('/internals/modules', '🧩 Modules',             'Specialist modules + GW state.', 'internals'),
    ('/internals/thought', '💭 Thought Stream',      'Live cognition trace.', 'internals'),
    ('/internals/chat',    '💬 Chat',                'Talk to the simulator.', 'internals'),
    ('/internals/callcenter','📋 Call Center Firehose','Raw call-center trace stream.', 'internals'),
]


def _cc_render_hub(token):
    """The hub: a tile grid of every browser route. Operator opens whichever
    in whichever tabs they want; the browser handles the layout."""
    cards = []
    by_cat = {}
    for path, title, desc, cat in _HUB_ROUTES:
        by_cat.setdefault(cat, []).append((path, title, desc))
    cat_titles = {
        'dispatch':  '★  DISPATCH OPERATIONS',
        'forensics': '✦  NETWORK FORENSICS',
        'internals': '🧠  SIMULATOR INTERNALS',
    }
    sections = []
    for cat in ('dispatch', 'forensics', 'internals'):
        items = by_cat.get(cat) or []
        if not items:
            continue
        tile_html = []
        for path, title, desc in items:
            href = f'{path}?token={_cc_html.escape(token)}'
            tile_html.append(
                f'<a href="{href}" target="_blank" '
                f'   style="display:block; text-decoration:none; color:inherit;">'
                f'<div class="panel light" style="margin:0; cursor:pointer; '
                f'    border-left: 6px solid var(--red);">'
                f'<div style="font-size:1.05em; font-weight:bold; '
                f'           color:var(--head-light)">{title}</div>'
                f'<div class="dim small" style="margin-top:6px">{desc}</div>'
                f'<div class="dim small mono" style="margin-top:8px">{path}</div>'
                f'</div></a>')
        sections.append(
            f'<h2>{cat_titles[cat]}</h2>'
            f'<div style="display:grid; grid-template-columns:'
            f' repeat(auto-fill, minmax(280px, 1fr)); gap:14px;">'
            f'{"".join(tile_html)}</div>')
    body = (f'<h1>AIdispatch — Operations Hub</h1>'
            f'<p class="dim">Each link below opens in a new browser tab. '
            f'Drag tabs between browser windows to lay out your workspace '
            f'across multiple monitors.</p>'
            f'{"".join(sections)}')
    return _cc_render_base('AIdispatch Hub', '', body)


def _cc_render_simple_iframe_page(title, src_path, head_extra=''):
    """Tiny shell that just embeds another page in an iframe so it can be
    its own browser tab. Useful for quick standalone surfaces that wrap
    existing rendering logic."""
    body = (f'<h1>{_cc_html.escape(title)}</h1>'
            f'<iframe src="{src_path}" style="width:100%; height:80vh; '
            f'        border:2px solid var(--gold); background:#fff"></iframe>')
    return _cc_render_base(title, head_extra, body)


def _cc_render_units_page(token):
    """Standalone unit roster page — full-screen units table + add form."""
    body = f"""
    <h1>🚑 Unit Roster</h1>
    <p class="dim">Live fleet status. Refresh every 3 seconds.</p>
    <div class="panel">
      <table id="roster"><thead><tr>
        <th>Callsign</th><th>Type</th><th>Status</th><th>Assigned Call</th>
        <th>Base</th><th>Current</th><th>ETA</th>
      </tr></thead><tbody></tbody></table>
    </div>
    <div class="panel">
      <h2>Add Unit</h2>
      <div class="row">
        <input id="add-callsign" placeholder="callsign (e.g. Medic 7)">
        <select id="add-type">
          <option value="EMS">EMS</option>
          <option value="POLICE">POLICE</option>
          <option value="FIRE">FIRE</option>
        </select>
        <input id="add-lat" placeholder="base lat" value="37.7749">
        <input id="add-lon" placeholder="base lon" value="-122.4194">
        <button class="primary" onclick="addUnit()">Add</button>
      </div>
    </div>
    <script>
      const TOK = {json.dumps(token)};
      async function refresh() {{
        const r = await fetch('/api/units?token=' + TOK);
        const j = await r.json();
        const tbody = document.querySelector('#roster tbody');
        tbody.innerHTML = '';
        for (const u of (j.units || []).sort((a,b)=>a.callsign.localeCompare(b.callsign))) {{
          const cls = u.status === 'AVAILABLE' ? 'good'
                    : u.status === 'ON_SCENE' ? 'disp'
                    : u.status === 'EN_ROUTE' || u.status === 'DISPATCHED' ? 'warn'
                    : u.status === 'OUT_OF_SERVICE' ? 'dim' : '';
          const tr = document.createElement('tr');
          tr.innerHTML = `<td class="mono">${{u.callsign}}</td>
                          <td>${{u.unit_type}}</td>
                          <td><span class="pill ${{cls}}">${{u.status}}</span></td>
                          <td class="mono small">${{u.assigned_call||'—'}}</td>
                          <td class="small">${{u.base_lat.toFixed(3)}}, ${{u.base_lon.toFixed(3)}}</td>
                          <td class="small">${{u.cur_lat.toFixed(3)}}, ${{u.cur_lon.toFixed(3)}}</td>
                          <td class="small">${{u.eta_s?Math.round(u.eta_s)+'s':'—'}}</td>`;
          tbody.appendChild(tr);
        }}
      }}
      async function addUnit() {{
        const callsign = document.getElementById('add-callsign').value.trim();
        if (!callsign) return;
        await fetch('/api/units/add?token=' + TOK, {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{
            callsign,
            unit_type: document.getElementById('add-type').value,
            base_lat: parseFloat(document.getElementById('add-lat').value || '0'),
            base_lon: parseFloat(document.getElementById('add-lon').value || '0'),
          }})}});
        document.getElementById('add-callsign').value = '';
        refresh();
      }}
      refresh(); setInterval(refresh, 3000);
    </script>
    """
    return _cc_render_base('Unit Roster', '', body)


def _cc_render_dispatch_page(token, preselect_call_id=None):
    """Operator dispatch sender: pick a call, pick units, choose a plan,
    optionally attach transcript, and send. Posts to /api/call/<id>/dispatch_unit."""
    pre = json.dumps(preselect_call_id or '')
    body = f"""
    <h1>📡 Dispatch Sender</h1>
    <p class="dim">Compose a tactical packet and send it to one or more units.
       Each packet carries the plan, instructions, and (optionally) the
       full call transcript so far.</p>

    <div class="row" style="display:grid; grid-template-columns:1.1fr 1fr; gap:14px">
      <div class="panel">
        <h2>1 · Active call</h2>
        <select id="call-select" style="width:100%; padding:8px; font-size:1em"></select>
        <div id="call-meta" class="small dim" style="margin-top:8px"></div>
        <div id="call-loc" class="small dim" style="margin-top:4px"></div>
        <div style="margin-top:10px">
          <label class="small dim"><input type="checkbox" id="attach-tx" checked> Attach call transcript so far</label>
        </div>
        <div id="tx-preview" class="mono small"
             style="margin-top:8px; max-height:160px; overflow:auto;
                    background:#fff; border:1px solid var(--gold);
                    padding:8px; white-space:pre-wrap"></div>
      </div>

      <div class="panel">
        <h2>2 · Recipients</h2>
        <div class="row" style="margin-bottom:6px">
          <label class="small dim"><input type="radio" name="utype" value="" checked> All</label>
          <label class="small dim"><input type="radio" name="utype" value="EMS"> EMS</label>
          <label class="small dim"><input type="radio" name="utype" value="POLICE"> POLICE</label>
          <label class="small dim"><input type="radio" name="utype" value="FIRE"> FIRE</label>
        </div>
        <div id="unit-grid"
             style="display:grid; grid-template-columns:repeat(auto-fill,minmax(160px,1fr));
                    gap:6px; max-height:320px; overflow:auto; background:#fff;
                    border:1px solid var(--gold); padding:8px;">
        </div>
        <div class="small dim" style="margin-top:6px">Tip: nearest available unit is highlighted.</div>
      </div>
    </div>

    <div class="panel" style="margin-top:14px">
      <h2>3 · Tactical plan</h2>
      <div class="row">
        <select id="plan-select" style="flex:1; padding:6px; font-size:1em"></select>
        <button onclick="autoPlan()" title="Recompute plan from call's escalation">Auto</button>
      </div>
      <div id="plan-preview"
           style="margin-top:10px; background:#fff; border-left:6px solid var(--red);
                  padding:10px;"></div>
      <div style="margin-top:10px">
        <label class="small dim">Custom add-on tactics (one per line)</label>
        <textarea id="custom-tactics" rows="3"
                  style="width:100%; font-family:monospace"
                  placeholder="e.g. Stage at corner of Oak & Main"></textarea>
      </div>
    </div>

    <div class="panel" style="margin-top:14px">
      <h2>4 · Operator note</h2>
      <textarea id="op-message" rows="3" style="width:100%"
                placeholder="Free-form instructions for the units..."></textarea>
      <div class="row" style="margin-top:10px; align-items:center">
        <label class="small dim">Priority override:</label>
        <select id="prio">
          <option value="">(use call priority)</option>
          <option value="1">1 — routine</option>
          <option value="2">2 — urgent</option>
          <option value="3">3 — emergency</option>
          <option value="4">4 — code 3</option>
          <option value="5">5 — life threat</option>
        </select>
        <button class="primary" onclick="sendDispatch()" style="margin-left:auto">📡 Send Dispatch</button>
        <button onclick="window.location='/console?token={_cc_html.escape(token)}'">Back to Console</button>
      </div>
      <div id="result" class="mono small" style="margin-top:10px"></div>
    </div>

    <script>
      const TOK = {json.dumps(token)};
      const PRESEL = {pre};
      let SESSIONS = {{}};
      let UNITS = [];
      let PLANS = {{}};

      async function loadCalls() {{
        const r = await fetch('/api/sessions?token='+TOK);
        const j = await r.json();
        SESSIONS = {{}};
        const sel = document.getElementById('call-select');
        sel.innerHTML = '';
        const sessions = (j.sessions || []).sort((a,b)=>(b.started_epoch||0)-(a.started_epoch||0));
        for (const s of sessions) {{
          SESSIONS[s.call_id] = s;
          const opt = document.createElement('option');
          opt.value = s.call_id;
          opt.textContent = (s.call_number || s.call_id) + '  '
                          + (s.phone||'—') + '  '
                          + (s.escalation||'—') + '  '
                          + '['+ (s.status||'—') +']';
          sel.appendChild(opt);
        }}
        if (PRESEL && SESSIONS[PRESEL]) sel.value = PRESEL;
        else if (sessions.length) sel.value = sessions[0].call_id;
        onCallChange();
      }}

      async function loadUnits() {{
        const r = await fetch('/api/units?token='+TOK);
        const j = await r.json();
        UNITS = j.units || [];
        renderUnits();
      }}

      async function loadPlans() {{
        const r = await fetch('/api/plans?token='+TOK);
        const j = await r.json();
        PLANS = j.plans || {{}};
        const sel = document.getElementById('plan-select');
        sel.innerHTML = '';
        for (const k of Object.keys(PLANS)) {{
          const opt = document.createElement('option');
          opt.value = k; opt.textContent = PLANS[k].title || k;
          sel.appendChild(opt);
        }}
        sel.addEventListener('change', renderPlan);
        renderPlan();
      }}

      function haversineKm(a,b,c,d) {{
        const R=6371, toR=x=>x*Math.PI/180;
        const dl=toR(c-a), dn=toR(d-b);
        const x=Math.sin(dl/2)**2 + Math.cos(toR(a))*Math.cos(toR(c))*Math.sin(dn/2)**2;
        return R*2*Math.atan2(Math.sqrt(x), Math.sqrt(1-x));
      }}

      function renderUnits() {{
        const sess = SESSIONS[document.getElementById('call-select').value];
        const filt = document.querySelector('input[name=utype]:checked').value;
        const tgtLat = sess?.location?.lat, tgtLon = sess?.location?.lon;
        let nearest = null, nearestD = 1e9;
        const list = UNITS.filter(u => !filt || u.unit_type === filt);
        for (const u of list) {{
          if (u.status==='AVAILABLE' && tgtLat && tgtLon) {{
            const d = haversineKm(u.base_lat, u.base_lon, tgtLat, tgtLon);
            if (d < nearestD) {{ nearestD = d; nearest = u.callsign; }}
          }}
        }}
        const grid = document.getElementById('unit-grid');
        grid.innerHTML = '';
        for (const u of list) {{
          const id = 'u_' + u.callsign.replace(/\\W/g,'_');
          const isNearest = (u.callsign === nearest);
          const cls = u.status === 'AVAILABLE' ? 'good'
                    : u.status === 'ON_SCENE' ? 'disp'
                    : (u.status === 'EN_ROUTE' || u.status === 'DISPATCHED') ? 'warn'
                    : 'dim';
          const lbl = document.createElement('label');
          lbl.style.cssText = 'display:block; padding:4px 6px; cursor:pointer;'
                            + (isNearest ? ' background:#ffe699; border:1px solid var(--gold);' : '');
          lbl.innerHTML = `<input type="checkbox" id="${{id}}" data-cs="${{u.callsign}}" ${{isNearest?'checked':''}}>
                           <span class="mono">${{u.callsign}}</span>
                           <span class="pill ${{cls}}" style="margin-left:4px">${{u.status}}</span>
                           <span class="dim small">${{u.unit_type}}</span>`;
          grid.appendChild(lbl);
        }}
      }}

      function renderPlan() {{
        const k = document.getElementById('plan-select').value;
        const p = PLANS[k]; if (!p) return;
        document.getElementById('plan-preview').innerHTML =
          `<div style="font-weight:bold; color:var(--head)">${{p.title}}</div>
           <div class="small" style="margin-top:6px"><b>Approach:</b> ${{p.approach||''}}</div>
           <div class="small" style="margin-top:6px"><b>Safety:</b><ul>` +
              (p.safety||[]).map(x=>'<li>'+x+'</li>').join('') + `</ul></div>
           <div class="small"><b>Tactics:</b><ol>` +
              (p.tactics||[]).map(x=>'<li>'+x+'</li>').join('') + `</ol></div>
           <div class="small"><b>Confirm:</b><ul>` +
              (p.questions||[]).map(x=>'<li>'+x+'</li>').join('') + `</ul></div>
           <div class="small"><b>Freq:</b> ${{(p.frequencies||[]).join(' · ')}}</div>`;
      }}

      function autoPlan() {{
        const s = SESSIONS[document.getElementById('call-select').value];
        if (!s) return;
        const esc = (s.escalation||'').toString();
        const sample = (s.chunks||[]).slice(0,5).join(' ').toLowerCase();
        let pick = 'GENERAL';
        if (esc === '911/EMS') {{
          pick = /chest|cardiac|stemi|heart attack/.test(sample) ? 'EMS_CARDIAC'
               : /trauma|gsw|stab|mvc|crash|fall/.test(sample)    ? 'EMS_TRAUMA'
               : /suicide|overdose|psych/.test(sample)            ? 'EMS_PSYCH'
               : 'EMS_GENERAL';
        }} else if (esc === 'POLICE') {{
          pick = /domestic|dv |assault/.test(sample) ? 'POLICE_DV'
               : /in progress|robbery|burglary|shooting|shots fired|active/.test(sample) ? 'POLICE_INPROGRESS'
               : 'POLICE_GENERAL';
        }} else if (esc === 'FIRE') {{
          pick = /high rise|highrise|tower/.test(sample) ? 'FIRE_HIGH_RISE'
               : /vehicle|car fire|truck fire/.test(sample) ? 'FIRE_VEHICLE'
               : 'FIRE_STRUCTURE';
        }} else if (esc === 'SUICIDE_HOTLINE') {{
          pick = 'CRISIS_HOTLINE';
        }}
        document.getElementById('plan-select').value = pick;
        renderPlan();
      }}

      function onCallChange() {{
        const s = SESSIONS[document.getElementById('call-select').value];
        if (!s) {{ document.getElementById('call-meta').textContent = 'No active call.'; return; }}
        const escTag = (s.escalation||'—');
        document.getElementById('call-meta').innerHTML =
          `<b>${{s.call_number||s.call_id}}</b> &middot; ${{s.phone||'—'}} &middot; AI=${{s.ai_id||'—'}} &middot;
           <span class="pill warn">${{escTag}}</span> priority=${{s.last_priority||0}}`;
        const loc = s.location || {{}};
        document.getElementById('call-loc').textContent =
          loc.lat ? `📍 ${{loc.city||'?'}}, ${{loc.regionName||'?'}} (${{loc.lat.toFixed(4)}}, ${{loc.lon.toFixed(4)}}) src=${{loc.source||'?'}}`
                  : '📍 location pending';
        // Build transcript preview from chunks + decisions
        const chunks = s.chunks || [];
        const decisions = s.decisions || [];
        const tx = chunks.map((c,i) => {{
          const ts = decisions[i]?.received_at || '?';
          const ai = decisions[i]?.response || '';
          return `[${{ts}}] CALLER: ${{c}}` + (ai ? `\\n[${{ts}}] AI    : ${{ai}}` : '');
        }}).join('\\n');
        document.getElementById('tx-preview').textContent = tx || '(no transcript yet)';
        autoPlan();
        renderUnits();
      }}

      async function sendDispatch() {{
        const cid = document.getElementById('call-select').value;
        if (!cid) {{ alert('No call selected'); return; }}
        const callsigns = Array.from(document.querySelectorAll('#unit-grid input[type=checkbox]:checked'))
                              .map(el => el.dataset.cs);
        if (!callsigns.length) {{ alert('Select at least one unit'); return; }}
        const customRaw = document.getElementById('custom-tactics').value;
        const custom = customRaw.split('\\n').map(s=>s.trim()).filter(Boolean);
        const body = {{
          callsigns,
          plan_key: document.getElementById('plan-select').value,
          message: document.getElementById('op-message').value || '',
          attach_transcript: document.getElementById('attach-tx').checked,
          custom_tactics: custom.length ? custom : null,
          priority: document.getElementById('prio').value || null,
        }};
        const r = await fetch('/api/call/'+encodeURIComponent(cid)+'/dispatch_unit?token='+TOK, {{
          method: 'POST',
          headers: {{'content-type':'application/json'}},
          body: JSON.stringify(body),
        }});
        const j = await r.json();
        if (r.ok && j.ok) {{
          document.getElementById('result').innerHTML =
            `<span class="pill good">SENT</span> dispatch_id=<b>${{j.dispatch.dispatch_id}}</b> → ${{callsigns.join(', ')}}`;
        }} else {{
          document.getElementById('result').innerHTML =
            `<span class="pill warn">FAILED</span> ${{JSON.stringify(j)}}`;
        }}
      }}

      document.getElementById('call-select').addEventListener('change', onCallChange);
      document.querySelectorAll('input[name=utype]').forEach(el => el.addEventListener('change', renderUnits));
      (async () => {{ await loadPlans(); await loadUnits(); await loadCalls(); }})();
      // Live refresh
      setInterval(loadCalls, 5000);
      setInterval(loadUnits, 5000);
    </script>
    """
    return _cc_render_base('Dispatch Sender', '', body)


def _cc_render_unit_receiver_page(callsign, operator_token):
    """Per-unit receiver: shows the unit's inbox and lets them ack / reply."""
    utok = _cc_unit_token(callsign)
    body = f"""
    <h1>📟 Unit Receiver — <span class="mono">{_cc_html.escape(callsign)}</span></h1>
    <p class="dim">Live dispatch inbox. New tactical packets stream in via SSE.
       Unit may acknowledge, change status, or reply with a free-form note.</p>

    <div class="panel">
      <div class="row" style="align-items:center">
        <div><b>Unit token:</b> <span class="mono">{_cc_html.escape(utok)}</span></div>
        <div class="dim small">Save this URL — it's the unit's private endpoint.</div>
        <div style="margin-left:auto">
          <span id="conn" class="pill dim">connecting...</span>
        </div>
      </div>
    </div>

    <div id="inbox" style="margin-top:14px"></div>

    <script>
      const CALLSIGN = {json.dumps(callsign)};
      const UTOK = {json.dumps(utok)};
      const TOK  = {json.dumps(operator_token)};
      const auth = '?utoken=' + encodeURIComponent(UTOK);
      const inboxEl = document.getElementById('inbox');
      let PACKETS = {{}};   // dispatch_id → packet

      function priorityBadge(n) {{
        const cls = n >= 4 ? 'warn' : (n >= 3 ? 'disp' : 'dim');
        return `<span class="pill ${{cls}}">PRIO ${{n||0}}</span>`;
      }}

      function statusBadge(s) {{
        const cls = (s==='cleared') ? 'good'
                  : (s==='on_scene'||s==='en_route') ? 'disp'
                  : (s==='received') ? 'warn'
                  : (s==='declined') ? 'warn'
                  : 'dim';
        return `<span class="pill ${{cls}}">${{(s||'pending').toUpperCase()}}</span>`;
      }}

      function renderPacket(p) {{
        const exists = document.getElementById('p_' + p.dispatch_id);
        const html = `
          <div class="panel" id="p_${{p.dispatch_id}}"
               style="border-left:6px solid ${{p.priority>=4?'var(--red)':'var(--gold)'}};
                      margin-bottom:14px;">
            <div class="row" style="align-items:center">
              <div style="font-size:1.1em; font-weight:bold; color:var(--head)">
                ${{p.plan?.title || 'Dispatch'}} — ${{p.call_number||p.call_id}}
              </div>
              <div style="margin-left:auto">
                ${{priorityBadge(p.priority)}} ${{statusBadge(p.status)}}
              </div>
            </div>
            <div class="small dim">Dispatch ${{p.dispatch_id}} · Sent ${{p.sent_at}} by ${{p.sent_by}} · Phone ${{p.phone||'—'}} · AI ${{p.ai_id||'—'}}</div>
            <div class="small" style="margin-top:6px">
              📍 ${{p.location?.lat ? (p.location.city||'?')+', '+(p.location.regionName||'?')+' ('+p.location.lat.toFixed(4)+','+p.location.lon.toFixed(4)+')' : 'location pending'}}
              ${{p.location?.address ? ' &middot; ' + p.location.address : ''}}
            </div>
            ${{p.message ? `<div style="margin-top:8px; background:#fff8d6; border:1px solid var(--gold); padding:8px"><b>OPS NOTE:</b> ${{escapeHtml(p.message)}}</div>` : ''}}
            <div class="row" style="margin-top:8px; gap:14px">
              <div style="flex:1">
                <h3 style="margin:6px 0">Tactical Plan</h3>
                <div class="small"><b>Approach:</b> ${{escapeHtml(p.plan?.approach||'')}}</div>
                <div class="small" style="margin-top:6px"><b>Safety</b><ul>${{(p.plan?.safety||[]).map(x=>'<li>'+escapeHtml(x)+'</li>').join('')}}</ul></div>
                <div class="small"><b>Tactics</b><ol>${{(p.plan?.tactics||[]).map(x=>'<li>'+escapeHtml(x)+'</li>').join('')}}</ol></div>
                <div class="small"><b>Confirm</b><ul>${{(p.plan?.questions||[]).map(x=>'<li>'+escapeHtml(x)+'</li>').join('')}}</ul></div>
                <div class="small"><b>Frequencies:</b> ${{(p.plan?.frequencies||[]).map(escapeHtml).join(' · ')}}</div>
              </div>
              <div style="flex:1">
                <h3 style="margin:6px 0">Call Transcript (.txt)</h3>
                <pre class="mono small" style="background:#fff; border:1px solid var(--gold);
                       padding:8px; max-height:280px; overflow:auto; white-space:pre-wrap">${{escapeHtml(p.transcript || '(no transcript attached)')}}</pre>
                <button onclick="downloadTx('${{p.dispatch_id}}')">⬇ Download .txt</button>
              </div>
            </div>
            <div class="row" style="margin-top:10px; flex-wrap:wrap">
              <button class="primary" onclick="ack('${{p.dispatch_id}}','received')">✓ Received</button>
              <button onclick="ack('${{p.dispatch_id}}','en_route')">🚓 En Route</button>
              <button onclick="ack('${{p.dispatch_id}}','on_scene')">📍 On Scene</button>
              <button class="primary" onclick="ack('${{p.dispatch_id}}','cleared')">✓ Cleared</button>
              <button class="danger" onclick="ack('${{p.dispatch_id}}','declined')">✕ Decline</button>
            </div>
            <div style="margin-top:10px">
              <input id="reply_${{p.dispatch_id}}" placeholder="Reply to dispatcher..." style="width:75%">
              <button onclick="reply('${{p.dispatch_id}}')">Send</button>
            </div>
            <div id="hist_${{p.dispatch_id}}" style="margin-top:10px"></div>
          </div>`;
        if (exists) exists.outerHTML = html;
        else inboxEl.insertAdjacentHTML('afterbegin', html);
        renderHistory(p);
      }}

      function renderHistory(p) {{
        const el = document.getElementById('hist_' + p.dispatch_id);
        if (!el) return;
        const hist = (p.history||[]).map(h =>
          `<div class="small dim mono">[${{h.wall}}] ${{h.status.toUpperCase()}} by ${{h.by}} ${{h.note?'· '+escapeHtml(h.note):''}}</div>`
        ).join('');
        const replies = (p.replies||[]).map(r =>
          `<div class="small mono" style="color:#0a4d2a">[${{r.wall}}] ${{r.from}} → ${{escapeHtml(r.text)}}</div>`
        ).join('');
        el.innerHTML = (hist || replies)
          ? `<div style="border-top:1px dashed var(--gold); padding-top:6px">${{hist}}${{replies}}</div>` : '';
      }}

      function escapeHtml(s) {{
        return (s||'').toString().replace(/[&<>"']/g, c =>
          ({{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}})[c]);
      }}

      async function ack(did, status) {{
        const note = (status==='declined' ? prompt('Reason?') || '' : '');
        const r = await fetch('/api/unit/'+encodeURIComponent(CALLSIGN)
                  +'/dispatch/'+encodeURIComponent(did)+'/ack'+auth, {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{status, note, by: CALLSIGN}}),
        }});
        const j = await r.json();
        if (j.dispatch) {{ PACKETS[did] = j.dispatch; renderPacket(j.dispatch); }}
      }}
      async function reply(did) {{
        const inp = document.getElementById('reply_' + did);
        const text = (inp.value||'').trim();
        if (!text) return;
        await fetch('/api/unit/'+encodeURIComponent(CALLSIGN)
                  +'/dispatch/'+encodeURIComponent(did)+'/reply'+auth, {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{text}}),
        }});
        inp.value = '';
      }}
      function downloadTx(did) {{
        const p = PACKETS[did]; if (!p) return;
        const blob = new Blob([p.transcript||''], {{type:'text/plain'}});
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = (p.call_number||p.call_id||'call') + '_dispatch.txt';
        document.body.appendChild(a); a.click(); a.remove();
      }}

      async function bootstrap() {{
        const r = await fetch('/api/unit/'+encodeURIComponent(CALLSIGN)+'/inbox'+auth);
        const j = await r.json();
        for (const p of (j.inbox || []).sort((a,b)=>(b.sent_at_ts||0)-(a.sent_at_ts||0))) {{
          PACKETS[p.dispatch_id] = p;
          renderPacket(p);
        }}
      }}

      function startStream() {{
        const es = new EventSource('/api/unit/'+encodeURIComponent(CALLSIGN)+'/inbox/stream'+auth);
        es.addEventListener('hello', () => {{
          document.getElementById('conn').className='pill good';
          document.getElementById('conn').textContent='live';
        }});
        es.addEventListener('packet', ev => {{
          const p = JSON.parse(ev.data);
          PACKETS[p.dispatch_id] = p;
          renderPacket(p);
        }});
        es.onerror = () => {{
          document.getElementById('conn').className='pill warn';
          document.getElementById('conn').textContent='reconnecting...';
          setTimeout(startStream, 2000);
          es.close();
        }};
      }}

      bootstrap().then(startStream);
    </script>
    """
    return _cc_render_base('Unit Receiver — ' + callsign, '', body)


def _cc_render_inboxes_index_page(token):
    """Operator view: every unit's receiver page + per-unit token URL."""
    rows = []
    for u in unit_roster.snapshot():
        cs = u['callsign']
        utok = _cc_unit_token(cs)
        href_op = f'/unit/{_cc_urlparse.quote(cs)}?token={_cc_html.escape(token)}'
        href_unit = f'/unit/{_cc_urlparse.quote(cs)}?utoken={utok}'
        rows.append(
            f'<tr>'
            f'<td class="mono">{_cc_html.escape(cs)}</td>'
            f'<td>{_cc_html.escape(u["unit_type"])}</td>'
            f'<td><span class="pill">{_cc_html.escape(u["status"])}</span></td>'
            f'<td><a href="{href_op}" target="_blank">Open (operator)</a></td>'
            f'<td class="mono small">{href_unit}</td>'
            f'</tr>')
    body = f"""
    <h1>📟 Unit Inboxes</h1>
    <p class="dim">Each unit has a private receiver page. Open with the
       operator token to inspect, or hand the unit token URL to the field unit.</p>
    <div class="panel">
      <table>
        <thead><tr>
          <th>Callsign</th><th>Type</th><th>Status</th>
          <th>Open</th><th>Unit URL (private)</th>
        </tr></thead>
        <tbody>{''.join(rows)}</tbody>
      </table>
    </div>
    <div class="panel">
      <h2>Live activity</h2>
      <div id="activity" class="mono small"></div>
    </div>
    <script>
      const TOK = {json.dumps(token)};
      async function refresh() {{
        const r = await fetch('/api/dispatch/inboxes?token='+TOK);
        const j = await r.json();
        const lines = (j.inboxes||[]).map(b =>
          `${{b.callsign.padEnd(12)}}  pending=${{b.pending}}  total=${{b.total}}  last=${{b.last_status||'—'}}  @${{b.last_sent_at||'—'}}`);
        document.getElementById('activity').innerHTML =
          lines.length ? lines.map(l=>'<div>'+l+'</div>').join('') : '<i class="dim">No dispatches yet.</i>';
      }}
      refresh(); setInterval(refresh, 3000);
    </script>
    """
    return _cc_render_base('Unit Inboxes', '', body)


def _cc_render_livecalls_page(token):
    """Standalone Live Calls Floor in its own browser tab."""
    body = f"""
    <h1>🟢 Live Calls Floor</h1>
    <div id="floor" class="floor"><div class="empty">No active calls.</div></div>
    <script>
      const TOK = {json.dumps(token)};
      let SESS = {{}};
      function fmtElapsed(epoch) {{
        if (!epoch) return '--:--';
        const s = Math.max(0, Math.floor(Date.now()/1000 - epoch));
        return String(Math.floor(s/60)).padStart(2,'0')+':'+String(s%60).padStart(2,'0');
      }}
      function escHtml(s) {{ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }}
      function render() {{
        const active = Object.values(SESS).filter(s => s.status === 'active');
        const el = document.getElementById('floor');
        if (!active.length) {{ el.innerHTML = '<div class="empty">No active calls.</div>'; return; }}
        el.style.display = 'grid';
        el.style.gridTemplateColumns = 'repeat(auto-fill, minmax(360px, 1fr))';
        el.style.gap = '14px';
        el.innerHTML = '';
        for (const s of active) {{
          const agg = s.last_aggregate || {{}};
          const u = agg.urgency || 0;
          const intent = (agg.intent||'?').toUpperCase();
          const a = s.last_action || '...';
          const last = (s.chunks||[]).slice(-1)[0] || '(awaiting transcript...)';
          const utier = u >= 8 ? 'emer' : u >= 5 ? 'disp' : 'good';
          const atier = (a.includes('EMERGENCY')||a.includes('ESCALATE')) ? 'emer' : a.includes('DISPATCH') ? 'disp' : 'good';
          const card = document.createElement('div');
          card.className = 'panel light';
          card.style.cssText = 'cursor:pointer; padding:0; margin:0; min-height:200px;';
          card.innerHTML = `
            <div style="padding:10px 14px; display:flex; justify-content:space-between; border-bottom:1px solid var(--border-light)">
              <div><div class="mono" style="font-weight:bold; color:var(--head-light)">☎ ${{escHtml(s.phone)}}</div>
                   <div class="dim small mono">CALL # ${{escHtml(s.call_number||'—')}}</div></div>
              <div style="text-align:right">
                <div class="mono" style="color:var(--red); font-weight:bold">⏱ ${{fmtElapsed(s.started_epoch)}}</div>
                <span class="pill ${{utier}}">★ U${{u}} · ${{escHtml(intent)}}</span></div></div>
            <div style="padding:10px 14px; background:var(--paper2); border-bottom:1px solid var(--border-light)">
              <div class="dim small" style="font-style:italic">CALLER SAID:</div>
              <div style="color:var(--blue-dark); font-weight:bold; font-family:'Cambria',serif">"${{escHtml(last)}}"</div></div>
            <div style="padding:8px 14px; display:flex; justify-content:space-between">
              <span class="pill ${{atier}}">AI → ${{escHtml(a.slice(0,30))}}</span>
              <span class="dim small mono">${{escHtml(s.ai_id)}}</span></div>`;
          card.onclick = () => window.open('/audit/'+encodeURIComponent(s.call_id)+'?token='+TOK, '_blank');
          el.appendChild(card);
        }}
      }}
      fetch('/api/sessions?token='+TOK).then(r=>r.json()).then(j=>{{
        for (const s of j.sessions||[]) SESS[s.call_id] = s;
        render();
      }});
      const es = new EventSource('/api/stream?token='+TOK);
      es.addEventListener('session', ev => {{
        const m = JSON.parse(ev.data);
        SESS[m.session.call_id] = m.session;
        render();
      }});
      setInterval(render, 1000);
    </script>
    """
    return _cc_render_base('Live Calls', '', body)


def _cc_render_audit_page(token, call_id=None):
    """Standalone full-screen Dispatch Audit page."""
    cid_js = json.dumps(call_id) if call_id else 'null'
    body = f"""
    <h1>🔍 Dispatch Audit</h1>
    <div class="panel">
      <div class="row">
        <input id="cid-input" placeholder="call_id (or leave blank for newest)" value="{_cc_html.escape(call_id or '')}">
        <button onclick="loadByInput()">Load</button>
      </div>
    </div>
    <div id="content" class="dim">Pick a call.</div>
    <script>
      const TOK = {json.dumps(token)};
      let CID = {cid_js};
      function loadByInput() {{
        CID = document.getElementById('cid-input').value.trim() || null;
        load();
      }}
      async function load() {{
        let cid = CID;
        if (!cid) {{
          const r = await fetch('/api/sessions?token='+TOK);
          const j = await r.json();
          const active = (j.sessions||[]).filter(s => s.status === 'active');
          if (!active.length) {{ document.getElementById('content').innerHTML = '<div class="dim">No active calls.</div>'; return; }}
          cid = active[active.length-1].call_id;
          CID = cid;
          document.getElementById('cid-input').value = cid;
        }}
        const r = await fetch('/api/session/' + encodeURIComponent(cid) + '?token=' + TOK);
        const s = await r.json();
        const decisions = s.decisions || [];
        const html = decisions.map((d, i) => {{
          const agg = d.aggregate || {{}};
          const tag = (d.action||'').includes('EMERGENCY') ? 'emer' : (d.action||'').includes('DISPATCH') ? 'disp' : 'good';
          return `<div class="panel">
            <strong>chunk #${{i}}</strong> @ ${{d.received_at||''}}
            <div>caller: <em>"${{(d.chunk||'').replace(/</g,'&lt;')}}"</em></div>
            <div>aggregate: intent=${{agg.intent||'?'}} U${{agg.urgency||0}} psych=${{agg.psych_state||'?'}}</div>
            <div><span class="pill ${{tag}}">${{d.action}}</span> priority=${{d.priority}} → ${{d.escalation||'—'}}</div>
            <div>response: "${{(d.response||'').replace(/</g,'&lt;')}}"</div>
            <div class="dim small">latency: ${{(d.latency_ms||0).toFixed(2)}}ms · think: ${{(d.think_ms||0).toFixed(2)}}ms</div>
            <div>${{(d.reasoning||[]).map(r=>'<div class="dim small">· '+r+'</div>').join('')}}</div>
          </div>`;
        }}).join('');
        document.getElementById('content').innerHTML = `
          <div class="panel">
            <div><strong>${{s.ai_id}}</strong> · call # ${{s.call_number}} · ${{s.phone}}</div>
            <div>status: ${{s.status}} · units: ${{(s.assigned_units||[]).join(', ')||'—'}}</div>
          </div>
          ${{html}}`;
      }}
      load();
      const es = new EventSource('/api/stream?token='+TOK);
      es.addEventListener('session', ev => {{
        const m = JSON.parse(ev.data);
        if (CID && m.session.call_id === CID) load();
      }});
    </script>
    """
    return _cc_render_base('Dispatch Audit', '', body)


def _cc_render_map_page(token):
    """Full-screen Caller Map standalone page."""
    head_extra = """
    <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"
          integrity="sha256-p4NxAoJBhIIN+hmNHrzRCf9tD/miZyoHS5obTRR9BMY=" crossorigin="">
    <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"
            integrity="sha256-20nQCchB9co0qIjJZRGuk2/Z9VM+kNiyxNV1lvTlZBo=" crossorigin=""></script>
    <style>#map{height:80vh;border:2px solid var(--gold)}</style>
    """
    body = f"""
    <h1>🗺  Caller Map</h1>
    <div class="row" style="align-items:center; margin-bottom:8px">
      <span class="dim small">Red pins = callers · Blue diamonds = units · Green = on scene · Amber = en route</span>
      <span style="margin-left:auto"></span>
      <label class="small dim"><input type="checkbox" id="auto-fit" checked> Auto-fit to active calls</label>
      <button id="rebase-btn" title="Right-click map for context menu, or click an active call below"
              onclick="rebaseToActive()" style="background:var(--gold)">🚒 Rebase Fleet to Active Call</button>
      <button onclick="dispatchToActive()" style="background:#0a4d2a; color:#fff">📡 Auto-Dispatch Active Call</button>
      <button onclick="resetFleet()" title="Reset fleet to default San Francisco coordinates">↺ Reset Fleet</button>
    </div>
    <div id="map"></div>
    <div class="dim small" style="margin-top:6px">
      Tip: <b>Right-click the map</b> to rebase the fleet to that point. Right-click a unit to inspect.
    </div>
    <div id="status" class="mono small" style="margin-top:6px"></div>
    <script>
      const TOK = {json.dumps(token)};
      const map = L.map('map', {{worldCopyJump: true}}).setView([39.5, -98.5], 4);
      L.tileLayer('https://{{s}}.tile.openstreetmap.org/{{z}}/{{x}}/{{y}}.png', {{
        maxZoom: 19, attribution: '© OpenStreetMap'
      }}).addTo(map);
      const PINS = {{}};
      const UPINS = {{}};
      let LAST_ACTIVE = null;
      let HAS_FIT = false;

      function setStatus(text, ok=true) {{
        const el = document.getElementById('status');
        el.innerHTML = `<span class="pill ${{ok?'good':'warn'}}">${{ok?'OK':'!!'}}</span> ${{text}}`;
        clearTimeout(setStatus._t);
        setStatus._t = setTimeout(()=>el.innerHTML='', 6000);
      }}

      // Right-click context menu: rebase fleet to clicked point
      map.on('contextmenu', async (e) => {{
        const lat = e.latlng.lat, lon = e.latlng.lng;
        if (!confirm(`Rebase the entire fleet to (${{lat.toFixed(4)}}, ${{lon.toFixed(4)}})?`)) return;
        const r = await fetch('/api/units/rebase?token='+TOK, {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{lat, lon, radius_km: 8.0}})
        }});
        const j = await r.json();
        if (r.ok) setStatus(`Rebased ${{j.moved}} units to (${{lat.toFixed(4)}}, ${{lon.toFixed(4)}})`);
        else      setStatus('Rebase failed: ' + JSON.stringify(j), false);
        refresh();
      }});

      async function rebaseToActive() {{
        if (!LAST_ACTIVE) {{ setStatus('No active call with location yet', false); return; }}
        const r = await fetch('/api/units/rebase?token='+TOK, {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{call_id: LAST_ACTIVE.call_id, radius_km: 8.0}})
        }});
        const j = await r.json();
        if (r.ok) setStatus(`Rebased ${{j.moved}} units near ${{LAST_ACTIVE.call_number||LAST_ACTIVE.call_id}}`);
        else      setStatus('Rebase failed', false);
        refresh();
      }}

      async function dispatchToActive() {{
        if (!LAST_ACTIVE) {{ setStatus('No active call selected', false); return; }}
        const r = await fetch('/api/call/'+encodeURIComponent(LAST_ACTIVE.call_id)+'/dispatch_unit?token='+TOK, {{
          method:'POST', headers:{{'content-type':'application/json'}},
          body: JSON.stringify({{
            area_only: true, radius_km: 50, max_units_per_type: 3,
            attach_transcript: true, by: 'map-operator'
          }})
        }});
        const j = await r.json();
        if (r.ok && j.ok) {{
          const recipients = (j.dispatch.recipients||[]).join(', ');
          setStatus(`Dispatched: ${{recipients||'(none in area)'}}  plan=${{j.dispatch.plan_key||j.dispatch.plan?.key||'?'}}`);
        }} else {{
          setStatus('Dispatch failed: ' + JSON.stringify(j), false);
        }}
      }}

      async function resetFleet() {{
        if (!confirm('Reset every unit to its default San Francisco base?')) return;
        const r = await fetch('/api/units/reset?token='+TOK, {{method:'POST'}});
        const j = await r.json();
        if (r.ok) {{
          // Clear in-memory pin cache so removed/relocated diamonds disappear
          for (const cs of Object.keys(UPINS)) {{
            map.removeLayer(UPINS[cs]);
            delete UPINS[cs];
          }}
          HAS_FIT = false;
          setStatus(`Reset ${{j.reset||0}} units to defaults`);
          refresh();
        }} else {{
          setStatus('Reset failed: ' + JSON.stringify(j), false);
        }}
      }}

      async function refresh() {{
        const r1 = await fetch('/api/sessions?token='+TOK);
        const j1 = await r1.json();
        const seen = new Set();
        const fitPoints = [];
        const active = (j1.sessions || []).filter(x => x.status === 'active');
        for (const s of active) {{
          const loc = s.location || {{}};
          if (!loc.lat && !loc.lon) continue;
          seen.add(s.call_id);
          const ll = [loc.lat, loc.lon];
          fitPoints.push(ll);
          LAST_ACTIVE = s;
          const popup = `<strong>${{s.ai_id||''}}</strong> · ${{s.call_number||''}}<br>
                         phone: ${{s.phone||'—'}}<br>
                         action: ${{s.last_action||''}}<br>
                         loc src: ${{loc.source||'?'}}<br>
                         <button onclick="window.open('/dispatch?token=${{TOK}}&call=${{encodeURIComponent(s.call_id)}}','_blank')">📡 Send to Units</button>`;
          if (PINS[s.call_id]) {{
            PINS[s.call_id].setLatLng(ll);
            PINS[s.call_id].setPopupContent(popup);
          }} else {{
            PINS[s.call_id] = L.circleMarker(ll, {{
              radius: 12, color: '#b22234', fillColor: '#bf0a30', fillOpacity: 0.7
            }}).addTo(map).bindPopup(popup);
          }}
        }}
        for (const id of Object.keys(PINS)) {{
          if (!seen.has(id)) {{ map.removeLayer(PINS[id]); delete PINS[id]; }}
        }}
        // Units
        const r2 = await fetch('/api/units?token='+TOK);
        const j2 = await r2.json();
        const seenU = new Set();
        for (const u of j2.units || []) {{
          // Render every unit with a real fix; skip only the (0,0) sentinel
          if ((u.cur_lat === 0 && u.cur_lon === 0)
              || u.cur_lat == null || u.cur_lon == null) continue;
          seenU.add(u.callsign);
          const ll = [u.cur_lat, u.cur_lon];
          fitPoints.push(ll);
          const color = u.status === 'EN_ROUTE' ? '#ffaa33'
                      : u.status === 'ON_SCENE' ? '#00ff88'
                      : u.status === 'AVAILABLE' ? '#3c3b6e'
                      : '#888';
          const html = `<div style="width:18px;height:18px;background:${{color}};
                         transform:rotate(45deg);border:2px solid #fff"></div>`;
          const popup = `<strong>${{u.callsign}}</strong> ${{u.unit_type}}<br>
                         status: ${{u.status}}<br>
                         <a target="_blank" href="/unit/${{encodeURIComponent(u.callsign)}}?token=${{TOK}}">📟 Open Receiver</a>`;
          if (UPINS[u.callsign]) {{
            UPINS[u.callsign].setLatLng(ll);
            UPINS[u.callsign].setPopupContent(popup);
          }} else {{
            UPINS[u.callsign] = L.marker(ll, {{
              icon: L.divIcon({{html, iconSize: [18,18], iconAnchor: [9,9]}})
            }}).addTo(map).bindPopup(popup);
          }}
        }}
        for (const cs of Object.keys(UPINS)) {{
          if (!seenU.has(cs)) {{ map.removeLayer(UPINS[cs]); delete UPINS[cs]; }}
        }}

        // Auto-fit on first data load (or whenever active calls exist and the
        // view is still the default America view)
        if (document.getElementById('auto-fit').checked && fitPoints.length > 0 && !HAS_FIT) {{
          const bounds = L.latLngBounds(fitPoints);
          map.fitBounds(bounds, {{padding:[40,40], maxZoom:13}});
          HAS_FIT = true;
        }}
      }}
      refresh(); setInterval(refresh, 3000);
    </script>
    """
    return _cc_render_base('Caller Map', head_extra, body)


def _cc_render_timeline_page(token, call_id=None):
    """Standalone CAD timeline view for a single call."""
    cid_js = json.dumps(call_id) if call_id else 'null'
    body = f"""
    <h1>📜 Incident Timeline</h1>
    <div class="panel">
      <div class="row">
        <input id="cid-input" placeholder="call_id (blank = newest active)" value="{_cc_html.escape(call_id or '')}">
        <button onclick="loadByInput()">Load</button>
      </div>
    </div>
    <div id="content" class="dim">Pick a call.</div>
    <script>
      const TOK = {json.dumps(token)};
      let CID = {cid_js};
      function loadByInput() {{ CID = document.getElementById('cid-input').value.trim() || null; load(); }}
      async function load() {{
        let cid = CID;
        if (!cid) {{
          const r = await fetch('/api/sessions?token='+TOK);
          const j = await r.json();
          const active = (j.sessions||[]).filter(s => s.status === 'active');
          if (!active.length) {{ document.getElementById('content').innerHTML = '<div class="dim">No active calls.</div>'; return; }}
          cid = active[active.length-1].call_id;
          CID = cid;
          document.getElementById('cid-input').value = cid;
        }}
        const r = await fetch('/api/timeline/' + encodeURIComponent(cid) + '?token=' + TOK);
        const j = await r.json();
        const events = j.timeline || [];
        const html = events.map(ev => {{
          const cls = ev.type.includes('UNIT_ON_SCENE') ? 'good'
                    : ev.type.includes('DISPATCH')||ev.type.includes('ASSIGNED') ? 'disp'
                    : ev.type.includes('CALL_ENDED') ? 'dim' : '';
          const detail = Object.keys(ev).filter(k=>!['ts','wall','type'].includes(k))
            .map(k=>k+'='+String(ev[k]).slice(0,40)).join(' · ');
          return `<tr><td class="mono small">${{ev.wall||''}}</td>
                      <td><span class="pill ${{cls}}">${{ev.type}}</span></td>
                      <td class="small">${{detail}}</td></tr>`;
        }}).join('');
        document.getElementById('content').innerHTML = `<div class="panel">
          <table style="width:100%"><thead><tr><th>Time</th><th>Event</th><th>Detail</th></tr></thead>
          <tbody>${{html||'<tr><td colspan=3 class=dim>no events</td></tr>'}}</tbody></table></div>`;
      }}
      load();
      const es = new EventSource('/api/stream?token='+TOK);
      es.addEventListener('session', ev => {{
        const m = JSON.parse(ev.data);
        if (CID && m.session.call_id === CID) load();
      }});
    </script>
    """
    return _cc_render_base('Incident Timeline', '', body)


def _cc_render_internals_page(token, tab=None):
    """Stub page for the internals tabs. Each tab name routes to a section
    that pulls relevant data via /api/health + /api/sessions; full simulator
    state is only available in the Tk window."""
    title = (tab or 'overview').title().replace('_', ' ')
    body = f"""
    <h1>🧠 Simulator Internals — {_cc_html.escape(title)}</h1>
    <p class="dim">For full live access to the consciousness simulator
       (Symbols, Memory, Neuron Groups, Charts, Screen) the Tk Internals
       window provides richer data. The browser surface here gives you a
       lightweight live view.</p>
    <div class="panel" id="content">Loading...</div>
    <script>
      const TOK = {json.dumps(token)};
      const TAB = {json.dumps(tab or 'overview')};
      async function load() {{
        const r = await fetch('/api/health');
        const h = await r.json();
        const r2 = await fetch('/api/sessions?token='+TOK);
        const j2 = await r2.json();
        document.getElementById('content').innerHTML = `
          <table style="width:100%">
            <tr><th>Health</th><td>${{h.status}}</td></tr>
            <tr><th>Active Sessions</th><td>${{h.active_sessions}}</td></tr>
            <tr><th>Total Sessions</th><td>${{h.total_sessions}}</td></tr>
            <tr><th>Units Total</th><td>${{h.units_total||0}}</td></tr>
            <tr><th>Units Available</th><td>${{h.units_available||0}}</td></tr>
            <tr><th>Units Busy</th><td>${{h.units_busy||0}}</td></tr>
          </table>
          <p class="dim small">Tab requested: <code>${{TAB}}</code></p>
          <p class="dim small">Open the desktop Tk window for full
             ${{TAB}} details.</p>`;
      }}
      load(); setInterval(load, 5000);
    </script>
    """
    return _cc_render_base('Internals', '', body)


def _cc_render_netmon_page(token, tab=None):
    """Network monitor surface (overview or specific tab)."""
    tab_name = (tab or 'connections').replace('_', ' ').title()
    body = f"""
    <h1>⬢ Network Monitor — {_cc_html.escape(tab_name)}</h1>
    <p class="dim">Connection forensics + threat audit.
       Streaming via /api/stream.</p>
    <div class="panel" id="content">Loading...</div>
    <script>
      const TOK = {json.dumps(token)};
      const TAB = {json.dumps(tab or 'connections')};
      async function load() {{
        const r = await fetch('/api/sessions?token='+TOK);
        const j = await r.json();
        const conns = (j.sessions||[]).filter(s=>s.status==='active');
        if (TAB === 'connections') {{
          document.getElementById('content').innerHTML = `
            <table style="width:100%"><thead><tr>
              <th>AI</th><th>Call#</th><th>Phone</th><th>Source</th>
              <th>City</th><th>Country</th><th>Action</th>
            </tr></thead><tbody>
            ${{conns.map(s=>{{
              const loc = s.location || {{}};
              return '<tr><td>'+s.ai_id+'</td><td>'+s.call_number+'</td>'+
                     '<td>'+s.phone+'</td><td>'+(loc.source||'—')+'</td>'+
                     '<td>'+(loc.city||'—')+'</td><td>'+(loc.country||'—')+'</td>'+
                     '<td>'+(s.last_action||'—')+'</td></tr>';
            }}).join('')||'<tr><td colspan=7 class=dim>no active connections</td></tr>'}}
            </tbody></table>`;
        }} else {{
          document.getElementById('content').innerHTML =
            '<p class="dim">Tab \\\"'+TAB+'\\\" \\u2014 ' + conns.length + ' active connection(s).' +
            ' Open the desktop Tk Network Monitor window for full forensics.</p>';
        }}
      }}
      load(); setInterval(load, 3000);
      const es = new EventSource('/api/stream?token='+TOK);
      es.addEventListener('session', () => load());
    </script>
    """
    return _cc_render_base('Network Monitor', '', body)


def _cc_render_console(token):
    """Operator console: live floor + per-session detail. SSE-driven."""
    head_extra = """
    <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"
          integrity="sha256-p4NxAoJBhIIN+hmNHrzRCf9tD/miZyoHS5obTRR9BMY=" crossorigin="">
    <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"
            integrity="sha256-20nQCchB9co0qIjJZRGuk2/Z9VM+kNiyxNV1lvTlZBo=" crossorigin=""></script>
    <style>
      #map { height: 380px; border-radius: 6px; }
      .leaflet-popup-content { color: #111; font-family: Consolas, monospace; }
      .pin-emer { filter: drop-shadow(0 0 6px #ff5566); }
      .pin-disp { filter: drop-shadow(0 0 6px #ffaa33); }
      .pin-good { filter: drop-shadow(0 0 4px #00ff88); }
    </style>
    """
    body = f"""
    <h1>AIdispatch — CAD Operator Console</h1>
    <p class="dim small">CAD-style three-pane layout: incidents queue · incident detail
       (ANI/ALI + timeline + comms) · units &amp; map. Live SSE stream.</p>
    <!-- ANI/ALI strip — stays pinned at the top when a call is selected -->
    <div class="panel" id="ani-ali-strip" style="display:none">
      <div class="row" style="align-items:flex-end">
        <div><div class="dim small">CALL #</div>
             <div class="mono" id="aa-callnum" style="font-size:1.4em">—</div></div>
        <div><div class="dim small">PHONE (ANI)</div>
             <div class="mono" id="aa-phone">—</div></div>
        <div><div class="dim small">CALLBACK</div>
             <div class="mono" id="aa-callback">—</div></div>
        <div><div class="dim small">SERVICE ADDRESS (ALI)</div>
             <div id="aa-address">—</div></div>
        <div><div class="dim small">CLASS OF SERVICE</div>
             <div id="aa-cos">—</div></div>
        <div><div class="dim small">LOCATION CONFIDENCE</div>
             <div id="aa-confidence">—</div></div>
        <div><div class="dim small">DISPATCH AI</div>
             <div id="aa-ai">—</div></div>
        <div><div class="dim small">INCIDENT STATUS</div>
             <div id="aa-status"><span class="pill">—</span></div></div>
      </div>
    </div>
    <!-- Map -->
    <div class="panel">
      <h2>🗺  CAD Map <span class="pill dim" id="map-count">0 located</span>
                     <span class="pill" id="map-units">0 units</span></h2>
      <p class="dim small">Red markers = caller pins. Blue diamonds = units. Click any to inspect.</p>
      <div id="map"></div>
    </div>
    <!-- Live Floor (bubble layout, kept) -->
    <div class="panel">
      <h2>Live Floor <span id="active-count" class="pill good">0 active</span></h2>
      <div id="floor" class="floor">
        <div class="empty">No active calls. A dispatch AI is fabricated only when a real call is received.</div>
      </div>
    </div>
    <!-- Three-pane CAD layout: incidents | detail | units -->
    <div class="grid" style="grid-template-columns: 1fr 2fr 1fr;">
      <div class="panel">
        <h3>📋 Active Incidents</h3>
        <table id="sessions-table"><thead>
          <tr><th>AI</th><th>Phone</th><th>U</th><th>Action</th><th>Units</th></tr>
        </thead><tbody></tbody></table>
      </div>
      <div class="panel">
        <h3>🔍 Incident Detail</h3>
        <div id="detail" class="dim">Click a row to inspect.</div>
      </div>
      <div class="panel">
        <h3>🚑 Unit Roster <span class="pill" id="roster-count">0/0</span></h3>
        <table id="roster-table"><thead>
          <tr><th>Callsign</th><th>Type</th><th>Status</th></tr>
        </thead><tbody></tbody></table>
        <div style="margin-top:12px"><h4>Add Unit</h4>
          <div class="row">
            <input id="add-callsign" placeholder="callsign" style="flex:2">
            <select id="add-type">
              <option value="EMS">EMS</option>
              <option value="POLICE">POLICE</option>
              <option value="FIRE">FIRE</option>
            </select>
          </div>
          <div class="row" style="margin-top:6px">
            <input id="add-lat" placeholder="lat">
            <input id="add-lon" placeholder="lon">
            <button class="primary" onclick="addUnit()">Add</button>
          </div>
        </div>
      </div>
    </div>
    <script>
      const TOK = {json.dumps(token)};
      let SESS = {{}};
      let UNITS = {{}};
      let SELECTED = null;
      const UNIT_MARKERS = {{}};

      const elFloor = document.getElementById('floor');
      const elTable = document.querySelector('#sessions-table tbody');
      const elDetail = document.getElementById('detail');
      const elCount = document.getElementById('active-count');

      function colorFor(u) {{
        u = Math.max(0, Math.min(10, u|0));
        if (u <= 4) {{ const t=u/4; return `rgb(${{0x33+(0xff-0x33)*t}},204,${{0x88-(0x88-0x33)*t}})`; }}
        const t=(u-4)/6; return `rgb(255,${{0xcc-(0xcc-0x33)*t}},${{0x33-(0x33-0x22)*t}})`;
      }}
      function ringFor(a) {{
        a = a||'';
        if (a.includes('EMERGENCY')||a.includes('ESCALATE')) return '#ff5566';
        if (a.includes('DISPATCH')) return '#ffaa33';
        if (a.includes('DISMISS')||a.includes('BLOCK')||a.includes('CLOSE')) return '#666688';
        return '#66ccff';
      }}

      function fmtElapsed(epoch) {{
        if (!epoch) return '--:--';
        const s = Math.max(0, Math.floor(Date.now()/1000 - epoch));
        return String(Math.floor(s/60)).padStart(2,'0') + ':' +
               String(s%60).padStart(2,'0');
      }}
      function escHtml(s) {{
        return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
      }}
      function renderFloor() {{
        const active = Object.values(SESS).filter(s => s.status === 'active');
        elCount.textContent = active.length + ' active';
        if (!active.length) {{
          elFloor.innerHTML = '<div class="empty">No active calls. A dispatch AI is fabricated only when a real call is received.</div>';
          return;
        }}
        // Caller-card layout: caller's voice gets the most real estate.
        // Hierarchy (most → least prominent):
        //   1. Caller's most recent line (large, central)
        //   2. Phone + call number (top-left)
        //   3. Urgency + intent + elapsed clock (top-right)
        //   4. AI action (bottom)
        //   5. AI id (smallest, footer)
        elFloor.innerHTML = '';
        elFloor.style.display = 'grid';
        elFloor.style.gridTemplateColumns = 'repeat(auto-fill, minmax(360px, 1fr))';
        elFloor.style.gap = '14px';
        for (const s of active) {{
          const agg = s.last_aggregate || {{}};
          const u = agg.urgency || 0;
          const intent = (agg.intent || '?').toUpperCase();
          const psych = agg.psych_state || '?';
          const a = s.last_action || 'analyzing...';
          const phone = s.phone || '?';
          const callNum = s.call_number || '—';
          const chunks = s.chunks || [];
          const lastSaid = chunks.length ? chunks[chunks.length - 1] : '(awaiting transcript...)';
          const elapsed = fmtElapsed(s.started_epoch);
          const fillColor = colorFor(u);
          const ringColor = ringFor(a);
          const urgencyTier = u >= 8 ? 'emer' : u >= 5 ? 'disp' : 'good';
          const actionTier = (a.includes('EMERGENCY') || a.includes('ESCALATE'))
            ? 'emer' : a.includes('DISPATCH') ? 'disp' : 'good';

          const card = document.createElement('div');
          card.className = 'panel light';
          card.style.cssText = 'cursor:pointer; padding:0; margin:0; ' +
                               'border-left: 6px solid ' + fillColor + '; ' +
                               'border-top: 2px solid ' + ringColor + ';' +
                               'min-height: 200px; display:flex; flex-direction:column;';
          card.innerHTML = `
            <div style="padding:10px 14px 8px; display:flex; justify-content:space-between; align-items:flex-start;
                         border-bottom: 1px solid var(--border-light);">
              <div>
                <div class="mono" style="font-size:1.15em; font-weight:bold; color:var(--head-light);">☎ ${{escHtml(phone)}}</div>
                <div class="dim small mono">CALL # ${{escHtml(callNum)}}</div>
              </div>
              <div style="text-align:right;">
                <div class="mono" style="color: var(--red); font-size:1.15em; font-weight:bold;">⏱ ${{elapsed}}</div>
                <span class="pill ${{urgencyTier}}" style="margin-top:4px">★ U${{u}} · ${{escHtml(intent)}}</span>
              </div>
            </div>
            <div style="flex:1; padding:10px 14px; background: var(--paper2); border-bottom: 1px solid var(--border-light);">
              <div class="dim small" style="font-style:italic; margin-bottom:4px;">CALLER SAID:</div>
              <div style="color: var(--blue-dark); font-size:1.08em; font-weight:bold; line-height:1.35;
                          font-family: 'Cambria','Georgia',serif;">"${{escHtml(lastSaid)}}"</div>
            </div>
            <div style="padding:8px 14px; display:flex; justify-content:space-between; align-items:center;">
              <div>
                <div style="font-weight:bold; font-family:'Cambria',serif;">
                  <span class="pill ${{actionTier}}">AI → ${{escHtml(a.slice(0,30))}}</span>
                </div>
                <div class="dim small" style="margin-top:4px">
                  ${{chunks.length}} chunk · ${{(s.decisions||[]).length}} dec · psych: ${{escHtml(psych)}}
                </div>
              </div>
              <div class="dim small mono" style="font-style:italic">${{escHtml(s.ai_id)}}</div>
            </div>`;
          card.onclick = () => select(s.call_id);
          elFloor.appendChild(card);
        }}
      }}
      function renderTable() {{
        const all = Object.values(SESS).sort((a,b)=> (a.status==='active'?0:1) - (b.status==='active'?0:1)
                                                    || ((b.started_epoch||0) - (a.started_epoch||0)));
        elTable.innerHTML = '';
        for (const s of all) {{
          const agg = s.last_aggregate || {{}};
          const u = agg.urgency || 0;
          const ucls = u >= 9 ? 'emer' : u >= 5 ? 'disp' : 'good';
          const units = (s.assigned_units || []).length;
          const tr = document.createElement('tr');
          if (s.call_id === SELECTED) tr.style.background = '#222266';
          tr.innerHTML = `<td>${{s.ai_id}} ${{s.status==='active'?'●':'○'}}</td>
                          <td class="small">${{(s.phone||'').slice(-7)}}</td>
                          <td><span class="pill ${{ucls}}">U${{u}}</span></td>
                          <td class="small">${{(s.last_action||'...').slice(0,16)}}</td>
                          <td>${{units?'<span class="pill disp">'+units+'</span>':'<span class="dim">—</span>'}}</td>`;
          tr.style.cursor = 'pointer';
          tr.onclick = () => select(s.call_id);
          elTable.appendChild(tr);
        }}
      }}
      function fmtDecision(d, i) {{
        const agg = d.aggregate || {{}};
        const layers = (d.layers||[]).map(L =>
          L.error ? `<div class="layer-row err">${{L.layer}} ERROR: ${{L.error}}</div>`
                  : `<div class="layer-row">
                      <div>${{L.layer}}</div><div>w=${{L.weight}}</div>
                      <div>intent=${{L.intent}}</div><div>U${{L.urgency}}</div>
                      <div>psych=${{L.psych}}</div><div>conf=${{L.confidence}}</div>
                    </div>`).join('');
        const cls = (d.action||'').includes('EMERGENCY') ? 'emer'
                  : (d.action||'').includes('DISPATCH') ? 'disp' : 'good';
        const reasons = (d.reasoning||[]).map(r=>`<div class="reason">· ${{r}}</div>`).join('');
        return `<div class="panel" style="background:#161636">
          <strong>chunk #${{i}}</strong> @ ${{d.received_at||''}}
          <div class="small">said: <em>${{(d.chunk||'').replace(/</g,'&lt;')}}</em></div>
          <div class="small dim">5-LAYER VOTES</div>
          ${{layers}}
          <div class="small">→ aggregate: intent=${{agg.intent||'?'}} urgency=${{agg.urgency||0}}
               psych=${{agg.psych_state||'?'}} conf=${{agg.confidence||0}}</div>
          <div class="small dim">archive: key=${{JSON.stringify(d.archive_key_used)}} via ${{d.fallback_reason}}</div>
          <div><span class="pill ${{cls}}">${{d.action||'—'}}</span>
               priority=${{d.priority||0}} esc=${{d.escalation||'—'}}</div>
          <div class="small">response: "${{(d.response||'').replace(/</g,'&lt;')}}"</div>
          <div class="small dim">latency: ${{(d.latency_ms||0).toFixed(2)}} ms</div>
          ${{reasons}}
        </div>`;
      }}
      function fmtTimeline(events) {{
        if (!events || !events.length) return '<div class="dim">no events</div>';
        return '<table style="width:100%"><thead><tr><th>Time</th><th>Event</th><th>Detail</th></tr></thead><tbody>' +
          events.slice().reverse().map(ev => {{
            const cls = ev.type.includes('UNIT_ON_SCENE') ? 'good'
                      : ev.type.includes('DISPATCH') || ev.type.includes('ASSIGNED') ? 'disp'
                      : ev.type.includes('CALL_ENDED') ? 'dim'
                      : ev.type.includes('COMMS') ? 'warn' : '';
            const detail = Object.keys(ev).filter(k => !['ts','wall','type'].includes(k))
              .map(k => `<span class="dim small">${{k}}=</span>${{String(ev[k]).slice(0,40)}}`).join(' · ');
            return `<tr><td class="mono small">${{ev.wall}}</td>
                        <td><span class="pill ${{cls}}">${{ev.type}}</span></td>
                        <td class="small">${{detail}}</td></tr>`;
          }}).join('') + '</tbody></table>';
      }}
      function fmtComms(msgs) {{
        if (!msgs || !msgs.length) return '<div class="dim">no comms yet</div>';
        return msgs.slice().reverse().map(m =>
          `<div class="small"><span class="dim">${{m.wall}}</span>
            <span class="pill ${{m.dir==='OUT'?'disp':'good'}}">${{m.dir}}</span>
            <strong>${{m.from}}→${{m.to}}:</strong> ${{(m.text||'').replace(/</g,'&lt;')}}</div>`).join('');
      }}
      function fmtAssignedUnits(callsigns) {{
        if (!callsigns || !callsigns.length)
          return '<div class="dim small">no units assigned yet</div>';
        return callsigns.map(cs => {{
          const u = UNITS[cs] || {{}};
          const cls = u.status === 'ON_SCENE' ? 'good'
                    : u.status === 'EN_ROUTE' ? 'disp'
                    : u.status === 'AVAILABLE' ? 'dim' : 'warn';
          return `<span class="pill ${{cls}}"><strong>${{cs}}</strong> ${{u.status||'?'}}${{u.eta_s?' (ETA '+Math.round(u.eta_s)+'s)':''}}</span>`;
        }}).join(' ');
      }}
      function fmtTranscript(chunks, decisions) {{
        if (!chunks || !chunks.length)
          return '<div class="dim small">no caller speech yet</div>';
        const esc = s => (s||'').toString().replace(/[&<>]/g, c =>
          ({{'&':'&amp;','<':'&lt;','>':'&gt;'}})[c]);
        return chunks.map((c, i) => {{
          const d = decisions[i] || {{}};
          const ts = d.received_at || '?';
          const reply = d.response ? `<div class="small" style="margin-left:14px; color:#0a4d2a">[${{ts}}] AI    : ${{esc(d.response)}}</div>` : '';
          return `<div class="small"><span class="dim">[${{ts}}]</span>
                  <strong>CALLER:</strong> ${{esc(c)}}</div>${{reply}}`;
        }}).reverse().join('');
      }}
      function expandAllSections(open) {{
        const el = document.getElementById('detail');
        if (!el) return;
        const prefs = {{}};
        for (const d of el.querySelectorAll('details.incident-section')) {{
          d.open = !!open;
          prefs[d.getAttribute('data-key')] = !!open;
        }}
        try {{ localStorage.setItem('cc_section_prefs', JSON.stringify(prefs)); }} catch (e) {{}}
      }}
      async function downloadIncidentTxt() {{
        if (!SELECTED) return;
        const r = await fetch('/api/call/'+encodeURIComponent(SELECTED)+'/transcript.txt?token='+TOK);
        if (!r.ok) {{ alert('No transcript available yet'); return; }}
        const text = await r.text();
        const s = SESS[SELECTED] || {{}};
        const fname = (s.call_number||SELECTED).replace(/[^A-Za-z0-9_-]/g,'_') + '.txt';
        const blob = new Blob([text], {{type:'text/plain'}});
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = fname;
        document.body.appendChild(a); a.click(); a.remove();
      }}
      function renderDetail() {{
        const s = SESS[SELECTED];
        const strip = document.getElementById('ani-ali-strip');
        if (!s) {{
          elDetail.innerHTML = '<div class="dim">Click a row to inspect.</div>';
          strip.style.display = 'none';
          return;
        }}
        const loc = s.location || {{}};
        // Update ANI/ALI strip
        strip.style.display = 'block';
        document.getElementById('aa-callnum').textContent = s.call_number || '—';
        document.getElementById('aa-phone').textContent = s.phone || '—';
        document.getElementById('aa-callback').textContent = s.phone || '—';
        const locParts = [loc.city, loc.regionName, loc.country].filter(Boolean);
        const locText = locParts.length ? locParts.join(', ') : '—';
        const coordText = (loc.lat||loc.lon) ? ` (${{(loc.lat||0).toFixed(4)}}, ${{(loc.lon||0).toFixed(4)}})` : '';
        document.getElementById('aa-address').textContent = locText + coordText;
        document.getElementById('aa-cos').textContent =
          s.phone && s.phone.startsWith('web-') ? 'WIRELESS / VoIP' :
          s.phone && s.phone.startsWith('voice-') ? 'WIRELESS / VoIP' :
          s.phone && s.phone.startsWith('tk-') ? 'WIRELINE / TEST' : 'WIRELESS';
        const conf = loc.source === 'browser' ? 'HIGH (GPS)' :
                     loc.source === 'maxmind' ? 'MEDIUM (MaxMind)' :
                     loc.source === 'ip-api' ? 'LOW (IP)' : 'UNKNOWN';
        document.getElementById('aa-confidence').innerHTML =
          `<span class="pill ${{loc.source==='browser'?'good':loc.source?'warn':'dim'}}">${{conf}}</span>`;
        document.getElementById('aa-ai').textContent = s.ai_id || '—';
        const statusCls = s.status === 'active' ? 'emer' : 'dim';
        const channel = s.channel || 'voice';
        const channelBadge = channel === 'text'
          ? '<span class="pill" style="background:#2a8a55; color:#fff; margin-left:4px">💬 TEXT-911</span>'
          : (channel === 'voice' ? '<span class="pill dim" style="margin-left:4px">📞 voice</span>' : '');
        document.getElementById('aa-status').innerHTML =
          `<span class="pill ${{statusCls}}">${{s.status||'—'}}</span>${{channelBadge}}`;

        const locStr = loc.lat || loc.lon
          ? `${{locText}} (${{(loc.lat||0).toFixed(4)}}, ${{(loc.lon||0).toFixed(4)}}) `
            + `<span class="pill ${{loc.source==='browser'?'good':'warn'}}">${{loc.source||'?'}}${{loc.accuracy_m?' ±'+Math.round(loc.accuracy_m)+'m':''}}</span>`
          : '<span class="dim">unknown</span>';
        const mapsLink = (loc.lat||loc.lon)
          ? ` <a href="https://www.openstreetmap.org/?mlat=${{loc.lat}}&mlon=${{loc.lon}}#map=16/${{loc.lat}}/${{loc.lon}}" target="_blank">open</a>`
          : '';
        elDetail.innerHTML = `
          <div class="row">
            <div><div class="dim small">AI</div><div>${{s.ai_id}}</div></div>
            <div><div class="dim small">Call #</div><div class="mono">${{s.call_number||'—'}}</div></div>
            <div><div class="dim small">Phone</div><div>${{s.phone}}</div></div>
            <div><div class="dim small">Status</div><div>${{s.status}}</div></div>
            <div><div class="dim small">Decisions</div><div>${{(s.decisions||[]).length}}</div></div>
          </div>
          <div style="margin-top:8px"><div class="dim small">📍 LOCATION</div><div>${{locStr}}${{mapsLink}}</div></div>
          <div class="row" style="margin-top:8px; flex-wrap:wrap">
            <button onclick="expandAllSections(true)" class="ghost">⊕ Expand all</button>
            <button onclick="expandAllSections(false)" class="ghost">⊖ Collapse all</button>
            <button onclick="downloadIncidentTxt()" title="Save this incident as a .txt to your Desktop">⬇ Download .txt</button>
          </div>
          <details class="incident-section" data-key="assigned" open>
            <summary>🚨 Assigned Units <span class="dim small">(${{(s.assigned_units||[]).length}})</span></summary>
            <div>${{fmtAssignedUnits(s.assigned_units || [])}}</div>
          </details>
          <details class="incident-section" data-key="timeline" open>
            <summary>📜 Incident Timeline <span class="dim small">(${{(s.timeline||[]).length}} events)</span></summary>
            <div class="timeline">${{fmtTimeline(s.timeline || [])}}</div>
          </details>
          <details class="incident-section" data-key="comms">
            <summary>📞 Comms Log <span class="dim small">(${{(s.comms||[]).length}})</span></summary>
            <div class="timeline" style="max-height:200px">${{fmtComms(s.comms || [])}}</div>
            <div class="row" style="margin-top:8px">
              <input id="comms-text" placeholder="message to units..." style="flex:3">
              <button onclick="sendComms('OUT')">Send OUT (→Unit)</button>
              <button onclick="sendComms('IN')" class="ghost">Log IN (←Unit)</button>
            </div>
            <div class="row" style="margin-top:6px">
              <input id="note-text" placeholder="operator note...">
              <button onclick="addNote()">Add Note</button>
            </div>
          </details>
          <details class="incident-section" data-key="transcript">
            <summary>📝 Caller Transcript <span class="dim small">(${{(s.chunks||[]).length}} chunks)</span></summary>
            <div class="timeline" style="max-height:240px">${{fmtTranscript(s.chunks||[], s.decisions||[])}}</div>
          </details>
          <details class="incident-section" data-key="decisions">
            <summary>🧠 Decision Timeline (AI Reasoning) <span class="dim small">(${{(s.decisions||[]).length}})</span></summary>
            <div class="timeline">${{(s.decisions||[]).map(fmtDecision).join('') || '<div class="dim">no decisions yet</div>'}}</div>
          </details>
          <div class="row" style="margin-top:12px">
            <button class="primary" onclick="judge(true)">Confirm ✓</button>
            <button class="danger" onclick="judge(false)">Override ✗</button>
            <button onclick="endCall()">End Call</button>
            <button onclick="markFalseAlarm()" style="background:var(--amber); color:var(--blue-dark)">⚠ False Alarm</button>
            <button class="primary" onclick="openDispatch()" style="background:#0a4d2a">📡 Send to Units</button>
            ${{(loc.lat||loc.lon)?`<button onclick="map.setView([${{loc.lat}},${{loc.lon}}], 14)">Center map</button>`:''}}
          </div>`;
        // Restore the operator's per-section expanded/collapsed preference
        try {{
          const prefs = JSON.parse(localStorage.getItem('cc_section_prefs')||'{{}}');
          for (const d of elDetail.querySelectorAll('details.incident-section')) {{
            const k = d.getAttribute('data-key');
            if (k in prefs) d.open = !!prefs[k];
            d.addEventListener('toggle', () => {{
              const p = JSON.parse(localStorage.getItem('cc_section_prefs')||'{{}}');
              p[k] = d.open;
              localStorage.setItem('cc_section_prefs', JSON.stringify(p));
            }});
          }}
        }} catch (e) {{}}
      }}
      async function markFalseAlarm() {{
        if (!SELECTED) return;
        if (!confirm('Mark this call as a false alarm and recall any dispatched units?')) return;
        await fetch('/api/call/'+encodeURIComponent(SELECTED)+'/false_alarm?token='+TOK,
          {{method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{by: 'operator'}})}});
      }}
      function openDispatch() {{
        if (!SELECTED) return;
        const url = '/dispatch?token=' + TOK + '&call=' + encodeURIComponent(SELECTED);
        window.open(url, '_blank');
      }}
      // Comms + notes
      async function sendComms(direction) {{
        if (!SELECTED) return;
        const text = document.getElementById('comms-text').value.trim();
        if (!text) return;
        await fetch('/api/session/'+encodeURIComponent(SELECTED)+'/comms?token='+TOK,
          {{method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{dir: direction, text}})}});
        document.getElementById('comms-text').value = '';
      }}
      async function addNote() {{
        if (!SELECTED) return;
        const text = document.getElementById('note-text').value.trim();
        if (!text) return;
        await fetch('/api/session/'+encodeURIComponent(SELECTED)+'/note?token='+TOK,
          {{method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{text, by: 'operator'}})}});
        document.getElementById('note-text').value = '';
      }}
      // Unit roster
      async function refreshUnits() {{
        try {{
          const r = await fetch('/api/units?token='+TOK);
          const j = await r.json();
          UNITS = {{}};
          for (const u of j.units || []) UNITS[u.callsign] = u;
          renderRoster();
          updateMap();
          if (SELECTED) renderDetail();
        }} catch (e) {{ console.warn('refreshUnits failed:', e); }}
      }}
      function renderRoster() {{
        const tbody = document.querySelector('#roster-table tbody');
        tbody.innerHTML = '';
        const units = Object.values(UNITS);
        const avail = units.filter(u => u.status === 'AVAILABLE').length;
        document.getElementById('roster-count').textContent = avail + '/' + units.length;
        units.sort((a,b) => a.callsign.localeCompare(b.callsign));
        for (const u of units) {{
          const cls = u.status === 'AVAILABLE' ? 'good'
                    : u.status === 'ON_SCENE' ? 'disp'
                    : u.status === 'EN_ROUTE' || u.status === 'DISPATCHED' ? 'warn'
                    : u.status === 'OUT_OF_SERVICE' ? 'dim' : '';
          const tr = document.createElement('tr');
          tr.innerHTML = `<td class="mono small">${{u.callsign}}</td>
                          <td class="small">${{u.unit_type}}</td>
                          <td><span class="pill ${{cls}}">${{u.status}}</span></td>`;
          if (u.assigned_call) {{
            tr.style.cursor = 'pointer';
            tr.onclick = () => select(u.assigned_call);
          }}
          tbody.appendChild(tr);
        }}
      }}
      async function addUnit() {{
        const callsign = document.getElementById('add-callsign').value.trim();
        const unit_type = document.getElementById('add-type').value;
        const base_lat = parseFloat(document.getElementById('add-lat').value || '0');
        const base_lon = parseFloat(document.getElementById('add-lon').value || '0');
        if (!callsign) return;
        await fetch('/api/units/add?token='+TOK,
          {{method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{callsign, unit_type, base_lat, base_lon}})}});
        document.getElementById('add-callsign').value = '';
        refreshUnits();
      }}
      function select(id) {{ SELECTED = id; renderDetail(); }}
      async function judge(ok) {{
        if (!SELECTED) return;
        await fetch('/api/session/'+encodeURIComponent(SELECTED)+'/judge?token='+TOK,
          {{method:'POST', headers:{{'content-type':'application/json'}},
            body: JSON.stringify({{confirmed: ok}})}});
      }}
      async function endCall() {{
        if (!SELECTED) return;
        await fetch('/api/call/'+encodeURIComponent(SELECTED)+'/end?token='+TOK, {{method:'POST'}});
      }}

      // ── Map (Leaflet) ──
      const map = L.map('map', {{worldCopyJump: true}}).setView([20, 0], 2);
      L.tileLayer('https://{{s}}.tile.openstreetmap.org/{{z}}/{{x}}/{{y}}.png', {{
        maxZoom: 19,
        attribution: '© OpenStreetMap contributors'
      }}).addTo(map);
      const MARKERS = {{}};   // call_id → leaflet marker
      const CIRCLES = {{}};   // call_id → leaflet accuracy circle

      function pinHtml(s) {{
        const u = (s.last_aggregate||{{}}).urgency || 0;
        const a = s.last_action || '...';
        const cls = a.includes('EMERGENCY') || a.includes('ESCALATE') ? 'pin-emer'
                  : a.includes('DISPATCH') ? 'pin-disp' : 'pin-good';
        const fill = colorFor(u);
        const ring = ringFor(a);
        return '<div class="' + cls + '" style="width:30px;height:30px;border-radius:50%;'
             + 'background:' + fill + ';border:3px solid ' + ring + ';'
             + 'display:flex;align-items:center;justify-content:center;'
             + 'color:#fff;font:bold 11px monospace">U' + u + '</div>';
      }}
      function popupHtml(s) {{
        const loc = s.location || {{}};
        const agg = s.last_aggregate || {{}};
        return '<strong>' + s.ai_id + '</strong> · ' + (s.call_number||'') + '<br>'
             + 'phone: ' + (s.phone||'?') + '<br>'
             + 'intent: ' + (agg.intent||'?') + ' · U' + (agg.urgency||0) + '<br>'
             + 'action: <strong>' + (s.last_action||'...') + '</strong><br>'
             + 'loc: ' + (loc.city||'?') + ', ' + (loc.country||'?') + '<br>'
             + 'src: ' + (loc.source||'?') + (loc.accuracy_m ? ' ±'+Math.round(loc.accuracy_m)+'m' : '');
      }}
      function updateMap() {{
        const located = Object.values(SESS).filter(s =>
          s.status === 'active' && s.location &&
          (s.location.lat || s.location.lon));
        document.getElementById('map-count').textContent = located.length + ' located';
        const seen = new Set();
        for (const s of located) {{
          seen.add(s.call_id);
          const ll = [s.location.lat, s.location.lon];
          if (MARKERS[s.call_id]) {{
            MARKERS[s.call_id].setLatLng(ll);
            MARKERS[s.call_id].setPopupContent(popupHtml(s));
            MARKERS[s.call_id].setIcon(L.divIcon({{
              html: pinHtml(s), className: '', iconSize: [30, 30], iconAnchor: [15, 15]
            }}));
          }} else {{
            const m = L.marker(ll, {{
              icon: L.divIcon({{html: pinHtml(s), className: '', iconSize: [30, 30], iconAnchor: [15, 15]}})
            }}).addTo(map);
            m.bindPopup(popupHtml(s));
            m.on('click', () => select(s.call_id));
            MARKERS[s.call_id] = m;
          }}
          // Accuracy circle (browser-volunteered fixes only — IP geo is ~50km, drown the map)
          const acc = s.location.accuracy_m || 0;
          if (s.location.source === 'browser' && acc > 0 && acc < 50000) {{
            if (CIRCLES[s.call_id]) {{
              CIRCLES[s.call_id].setLatLng(ll);
              CIRCLES[s.call_id].setRadius(acc);
            }} else {{
              CIRCLES[s.call_id] = L.circle(ll, {{
                radius: acc, color: '#66ccff', weight: 1, opacity: 0.6, fillOpacity: 0.1
              }}).addTo(map);
            }}
          }}
        }}
        // Remove pins for sessions no longer active or located
        for (const cid of Object.keys(MARKERS)) {{
          if (!seen.has(cid)) {{
            map.removeLayer(MARKERS[cid]);
            delete MARKERS[cid];
            if (CIRCLES[cid]) {{ map.removeLayer(CIRCLES[cid]); delete CIRCLES[cid]; }}
          }}
        }}
        // ── Unit pins (blue diamonds) ──
        const unitsArr = Object.values(UNITS);
        document.getElementById('map-units').textContent =
          unitsArr.filter(u=>u.status!=='AVAILABLE'&&u.status!=='OUT_OF_SERVICE').length + ' units busy';
        const seenU = new Set();
        for (const u of unitsArr) {{
          // Render every unit with a real fix; skip only the (0,0) sentinel
          if ((u.cur_lat === 0 && u.cur_lon === 0)
              || u.cur_lat == null || u.cur_lon == null) continue;
          seenU.add(u.callsign);
          const ll = [u.cur_lat, u.cur_lon];
          const color = u.status === 'AVAILABLE' ? '#66ccff'
                      : u.status === 'EN_ROUTE' ? '#ffaa33'
                      : u.status === 'ON_SCENE' ? '#00ff88'
                      : u.status === 'DISPATCHED' ? '#ffcc44'
                      : u.status === 'RETURNING' ? '#bb88ff' : '#888';
          const html = `<div style="width:24px;height:24px;background:${{color}};
                        border:2px solid #fff;transform:rotate(45deg);
                        display:flex;align-items:center;justify-content:center;
                        color:#000;font:bold 9px monospace">
                          <span style="transform:rotate(-45deg)">${{u.unit_type[0]}}</span></div>`;
          const popup = `<strong>${{u.callsign}}</strong> (${{u.unit_type}})<br>
                          status: ${{u.status}}<br>
                          ${{u.assigned_call?'on call: '+u.assigned_call+'<br>':''}}
                          ${{u.eta_s?'ETA: '+Math.round(u.eta_s)+'s<br>':''}}
                          base: ${{u.base_lat.toFixed(3)}}, ${{u.base_lon.toFixed(3)}}`;
          if (UNIT_MARKERS[u.callsign]) {{
            UNIT_MARKERS[u.callsign].setLatLng(ll);
            UNIT_MARKERS[u.callsign].setIcon(L.divIcon({{
              html, className: '', iconSize: [24, 24], iconAnchor: [12, 12]}}));
            UNIT_MARKERS[u.callsign].setPopupContent(popup);
          }} else {{
            const m = L.marker(ll, {{
              icon: L.divIcon({{html, className: '', iconSize: [24, 24], iconAnchor: [12, 12]}})
            }}).addTo(map);
            m.bindPopup(popup);
            UNIT_MARKERS[u.callsign] = m;
          }}
        }}
        for (const cs of Object.keys(UNIT_MARKERS)) {{
          if (!seenU.has(cs)) {{
            map.removeLayer(UNIT_MARKERS[cs]);
            delete UNIT_MARKERS[cs];
          }}
        }}
        // Auto-fit on first marker added
        if (located.length === 1 && !window.__mapFitDone) {{
          map.setView([located[0].location.lat, located[0].location.lon], 8);
          window.__mapFitDone = true;
        }}
      }}

      // Hook map updates into existing render path
      const _origRenderFloor = renderFloor;
      renderFloor = function() {{ _origRenderFloor(); updateMap(); }};

      // Auto-select the newest active call so the operator doesn't have
      // to click — until they manually pick a different one (then we
      // honor their selection until the call ends).
      let _userSelected = false;
      const _origSelect = select;
      select = function(id) {{ _userSelected = true; _origSelect(id); }};
      function autoSelectNewest() {{
        if (_userSelected && SELECTED && SESS[SELECTED]
            && SESS[SELECTED].status === 'active') return;
        const active = Object.values(SESS).filter(s => s.status === 'active');
        if (!active.length) return;
        // Sort by started_epoch desc; pick newest
        active.sort((a,b) => (b.started_epoch||0) - (a.started_epoch||0));
        if (SELECTED !== active[0].call_id) {{
          SELECTED = active[0].call_id;
          renderDetail();
        }}
      }}

      // Initial state pull
      fetch('/api/sessions?token='+TOK).then(r=>r.json()).then(j => {{
        for (const s of j.sessions||[]) SESS[s.call_id] = s;
        renderFloor(); renderTable(); autoSelectNewest(); renderDetail();
      }});
      refreshUnits();
      setInterval(refreshUnits, 3000);   // poll roster every 3s
      // Re-render the floor every second so the elapsed clocks tick.
      // Cheap: just re-runs renderFloor() on the cached SESS map; no fetch.
      setInterval(() => {{
        try {{ renderFloor(); }} catch (e) {{}}
      }}, 1000);

      // SSE live updates
      const es = new EventSource('/api/stream?token='+TOK);
      es.addEventListener('session', ev => {{
        const m = JSON.parse(ev.data);
        const isNewActive = !SESS[m.session.call_id]
                            && m.session.status === 'active';
        SESS[m.session.call_id] = m.session;
        renderFloor(); renderTable();
        // New incoming call? Auto-jump to it (unless operator pinned a call)
        if (isNewActive && !_userSelected) {{
          SELECTED = m.session.call_id;
          renderDetail();
        }} else if (SELECTED === m.session.call_id) {{
          renderDetail();
        }}
        // If selected call ended, release the pin so next new call auto-selects
        if (SELECTED && SESS[SELECTED]
            && SESS[SELECTED].status !== 'active') {{
          _userSelected = false;
        }}
      }});
      es.addEventListener('hello', ev => console.log('stream hello', ev.data));
      es.onerror = () => console.warn('SSE disconnected, browser will auto-retry');
    </script>
    """
    return _cc_render_base('AIdispatch Console', head_extra, body)


# ── HTTP server core ─────────────────────────────────────────────────────
class _CCThreadingServer(_cc_socketserver.ThreadingMixIn, _cc_http.HTTPServer):
    daemon_threads = True
    allow_reuse_address = True


class _CCRequestHandler(_cc_http.BaseHTTPRequestHandler):
    server_version = 'AIdispatch/1.0'
    # SSE clients get registered here so the service can broadcast.
    # Class-level so all handler instances share the same registry.
    sse_clients = []
    sse_lock = threading.Lock()
    # Per-call SSE: call_id → list of client dicts
    call_sse_clients = defaultdict(list)
    call_sse_lock = threading.Lock()
    # Per-unit dispatch SSE: callsign → list of client dicts
    unit_sse_clients = defaultdict(list)
    unit_sse_lock = threading.Lock()

    # Silence default access logging — we have our own
    def log_message(self, fmt, *args):
        _cc_logger.info('http %s %s', self.address_string(), fmt % args)

    def log_error(self, fmt, *args):
        _cc_logger.warning('http err %s %s', self.address_string(), fmt % args)

    def handle(self):
        """Wrap the default keep-alive loop so client disconnects mid-SSE
        don't print a multi-page traceback to the log."""
        try:
            return super().handle()
        except (ConnectionAbortedError, ConnectionResetError, BrokenPipeError,
                TimeoutError):
            # Browser closed the SSE/HTTP connection — perfectly normal
            return None

    # ── helpers ──
    def _send(self, code, body, content_type='text/html; charset=utf-8',
              extra_headers=None):
        if isinstance(body, str):
            body = body.encode('utf-8')
        self.send_response(code)
        self.send_header('Content-Type', content_type)
        self.send_header('Content-Length', str(len(body)))
        self.send_header('Cache-Control', 'no-store')
        self.send_header('X-Content-Type-Options', 'nosniff')
        if extra_headers:
            for k, v in extra_headers.items():
                self.send_header(k, v)
        self.end_headers()
        try:
            self.wfile.write(body)
        except (BrokenPipeError, ConnectionResetError):
            pass

    def _send_json(self, code, payload):
        self._send(code, json.dumps(payload), 'application/json; charset=utf-8')

    def _read_json(self, max_bytes=64 * 1024):
        try:
            n = int(self.headers.get('Content-Length') or 0)
            if n <= 0 or n > max_bytes:
                return None
            raw = self.rfile.read(n).decode('utf-8', errors='replace')
            return json.loads(raw)
        except Exception:
            return None

    def _check_token(self):
        """Operator endpoints need ?token=... or X-Operator-Token header."""
        q = _cc_urlparse.urlparse(self.path).query
        params = _cc_urlparse.parse_qs(q)
        tok = (params.get('token', [''])[0]
               or self.headers.get('X-Operator-Token') or '')
        return _cc_secrets.compare_digest(tok, _CC_OPERATOR_TOKEN)

    def _check_unit_token(self, callsign):
        """Per-unit endpoints accept ?utoken=<derived> or X-Unit-Token."""
        q = _cc_urlparse.urlparse(self.path).query
        params = _cc_urlparse.parse_qs(q)
        tok = (params.get('utoken', [''])[0]
               or self.headers.get('X-Unit-Token') or '')
        if not tok or not callsign:
            return False
        return _cc_secrets.compare_digest(tok, _cc_unit_token(callsign))

    def _public_session(self, sess):
        """Strip nothing — caller-facing is fine; but keep this helper for symmetry."""
        return sess

    def _client_ip(self):
        """Return the requester IP, honoring X-Forwarded-For if a proxy
        terminates upstream of us. Last entry of XFF is the most-trusted hop."""
        xff = self.headers.get('X-Forwarded-For') or ''
        if xff:
            # Take the leftmost (the original client per RFC 7239 convention)
            ip = xff.split(',')[0].strip()
            if ip:
                return ip
        try:
            return self.client_address[0]
        except Exception:
            return '0.0.0.0'

    # ── routing ──
    def do_GET(self):
        try:
            parsed = _cc_urlparse.urlparse(self.path)
            path = parsed.path
            if path == '/' or path == '/index.html':
                return self._send(200, _cc_render_homepage())
            # ── HUB + standalone surfaces (each its own browser tab) ──
            if path == '/hub':
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '',
                        '<h1>Hub</h1><p>Append <code>?token=YOUR_TOKEN</code>.</p>'))
                return self._send(200, _cc_render_hub(_CC_OPERATOR_TOKEN))
            if path == '/livecalls':
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '',
                        '<h1>Auth required</h1>'))
                return self._send(200, _cc_render_livecalls_page(_CC_OPERATOR_TOKEN))
            if path == '/units':
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '', '<h1>Auth required</h1>'))
                return self._send(200, _cc_render_units_page(_CC_OPERATOR_TOKEN))
            if path == '/map':
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '', '<h1>Auth required</h1>'))
                return self._send(200, _cc_render_map_page(_CC_OPERATOR_TOKEN))
            if path == '/audit' or path.startswith('/audit/'):
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '', '<h1>Auth required</h1>'))
                cid = _cc_urlparse.unquote(path[len('/audit/'):]) if path.startswith('/audit/') else None
                return self._send(200, _cc_render_audit_page(_CC_OPERATOR_TOKEN, cid))
            if path == '/timeline' or path.startswith('/timeline/'):
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '', '<h1>Auth required</h1>'))
                cid = _cc_urlparse.unquote(path[len('/timeline/'):]) if path.startswith('/timeline/') else None
                return self._send(200, _cc_render_timeline_page(_CC_OPERATOR_TOKEN, cid))
            if path == '/internals' or path.startswith('/internals/'):
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '', '<h1>Auth required</h1>'))
                tab = path[len('/internals/'):] if path.startswith('/internals/') else None
                return self._send(200, _cc_render_internals_page(_CC_OPERATOR_TOKEN, tab))
            if path == '/netmon' or path.startswith('/netmon/'):
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '', '<h1>Auth required</h1>'))
                tab = path[len('/netmon/'):] if path.startswith('/netmon/') else None
                return self._send(200, _cc_render_netmon_page(_CC_OPERATOR_TOKEN, tab))
            if path == '/phone':
                # Quick redirect to the existing caller homepage
                return self._send(200, _cc_render_homepage())
            if path == '/console':
                if not self._check_token():
                    msg = ("<h1>Operator console</h1>"
                           "<p>Append <code>?token=YOUR_TOKEN</code> to the URL. "
                           "The token is printed on AIdispatch startup and shown in the Tk dashboard.</p>")
                    return self._send(401, _cc_render_base('Auth required', '', msg))
                return self._send(200, _cc_render_console(_CC_OPERATOR_TOKEN))
            if path.startswith('/voice/'):
                cid = _cc_urlparse.unquote(path[len('/voice/'):])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send(404, _cc_render_base(
                        'Not found', '',
                        '<h1>Call not found</h1><p><a href="/">Back</a></p>'))
                return self._send(200, _cc_render_voice_page(sess))
            if path.startswith('/text911/'):
                cid = _cc_urlparse.unquote(path[len('/text911/'):])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send(404, _cc_render_base(
                        'Not found', '',
                        '<h1>Thread not found</h1><p><a href="/">Back</a></p>'))
                return self._send(200, _cc_render_text911_page(sess))
            if path.startswith('/api/call/') and path.endswith('/stream'):
                # Per-call public SSE: pushes decision events for this call only.
                cid = _cc_urlparse.unquote(path[len('/api/call/'):-len('/stream')])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                return self._stream_call_sse(cid)
            if path == '/api/tts':
                # Server-side TTS fallback (Windows: PowerShell System.Speech).
                # Accepts ?rate=N  (-10..10) for slightly-faster emergency reads.
                # Defaults: rate=2 normal, callers should pass rate=4 for emer.
                params = _cc_urlparse.parse_qs(_cc_urlparse.urlparse(self.path).query)
                text = (params.get('text', [''])[0] or '').strip()
                if not text:
                    return self._send_json(400, {'error': 'text required'})
                try:
                    rate_i = int(params.get('rate', ['2'])[0])
                except (ValueError, TypeError):
                    rate_i = 2
                wav = _cc_synthesize_speech(text, rate=rate_i)
                if wav is None:
                    return self._send_json(503, {'error': 'tts_unavailable'})
                return self._send(200, wav, 'audio/wav')
            if path.startswith('/call/'):
                cid = _cc_urlparse.unquote(path[len('/call/'):])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send(404, _cc_render_base(
                        'Not found', '',
                        '<h1>Call not found</h1><p><a href="/">Back</a></p>'))
                return self._send(200, _cc_render_call_page(sess))
            if path == '/api/sessions':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                with call_center_service._lock:
                    sessions = list(call_center_service.sessions.values())
                return self._send_json(200, {'sessions': sessions})
            if path.startswith('/api/session/'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                cid = _cc_urlparse.unquote(path[len('/api/session/'):])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                return self._send_json(200, sess)
            if path == '/api/stream':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                return self._stream_sse()
            if path == '/api/health':
                return self._send_json(200, {
                    'status': 'ok',
                    'active_sessions': sum(
                        1 for s in call_center_service.sessions.values()
                        if s.get('status') == 'active'),
                    'total_sessions': len(call_center_service.sessions),
                    'units_total': len(unit_roster.units),
                    'units_available': len([u for u in unit_roster.snapshot()
                                              if u['status'] == 'AVAILABLE']),
                    'units_busy': len([u for u in unit_roster.snapshot()
                                        if u['status'] not in ('AVAILABLE', 'OUT_OF_SERVICE')]),
                })
            # ── CAD Unit Roster API ──
            if path == '/api/units':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                return self._send_json(200, {'units': unit_roster.snapshot()})
            if path.startswith('/api/units/'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                callsign = _cc_urlparse.unquote(path[len('/api/units/'):])
                u = unit_roster.units.get(callsign)
                if u is None:
                    return self._send_json(404, {'error': 'not_found'})
                d = u.to_dict()
                d['history'] = list(u.history)[-50:]
                return self._send_json(200, d)
            if path.startswith('/api/timeline/'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                cid = _cc_urlparse.unquote(path[len('/api/timeline/'):])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                return self._send_json(200, {
                    'call_id': cid,
                    'timeline': sess.get('timeline', []),
                })
            # ── INCIDENT TRANSCRIPT (.txt) ──
            if (path.startswith('/api/call/')
                    and path.endswith('/transcript.txt')):
                if not self._check_token():
                    return self._send(401, 'unauthorized', 'text/plain')
                cid = _cc_urlparse.unquote(
                    path[len('/api/call/'):-len('/transcript.txt')])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send(404, 'not_found', 'text/plain')
                body = CallCenterService._build_transcript_text(sess)
                return self._send(200, body, 'text/plain; charset=utf-8')
            # ── MONITOR (MedianBox) FORENSICS API ──
            # Surface the full monitor state so the operator can see what the
            # tracker actually knows about each call: GeoIP, LocationVerifier
            # (multi-method verdict), ProxyDetector, ServiceResolver, etc.
            if path == '/api/monitor/stats':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                try:
                    stats = medianbox.get_stats()
                except Exception as e:
                    stats = {'error': str(e), 'enabled': False}
                return self._send_json(200, stats)
            if path == '/api/monitor/connections':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                try:
                    conns = medianbox.get_connections_snapshot()
                except Exception as e:
                    return self._send_json(500, {'error': str(e)})
                return self._send_json(200, {'connections': conns,
                                              'count': len(conns)})
            if path.startswith('/api/monitor/call/'):
                # /api/monitor/call/<call_id>  -> forensics for one session
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                cid = _cc_urlparse.unquote(
                    path[len('/api/monitor/call/'):])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                forensics = {
                    'call_id': cid,
                    'client_ip': sess.get('client_ip'),
                    'location': sess.get('location'),
                    'loc_verification': sess.get('loc_verification'),
                }
                # Cross-reference with medianbox connection inventory
                try:
                    conns = medianbox.get_connections_snapshot() or []
                    for ce in conns:
                        if (ce.get('remote_ip') == sess.get('client_ip')
                                or ce.get('call_id') == cid):
                            forensics['connection'] = ce
                            break
                except Exception:
                    pass
                # Run a fresh LocationVerifier pass synchronously if we have IP+geo
                try:
                    if (medianbox.enabled and medianbox.loc_verifier
                            and sess.get('client_ip')
                            and sess.get('client_ip') != '127.0.0.1'):
                        loc = sess.get('location') or {}
                        v = medianbox.loc_verifier.verify(
                            sess['client_ip'],
                            {'lat': loc.get('lat') or 0,
                             'lon': loc.get('lon') or 0,
                             'city': loc.get('city') or '?',
                             'countryCode': loc.get('countryCode') or '??'})
                        forensics['live_verify'] = v
                except Exception as e:
                    forensics['live_verify_error'] = str(e)
                return self._send_json(200, forensics)
            # ── DISPATCH OUTBOX API ──
            if path == '/api/plans':
                # Public: anyone with the token can read the plan library
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                return self._send_json(200, {
                    'plans': {k: v for k, v in _TACTICAL_PLANS.items()},
                })
            if path == '/dispatch':
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '',
                        '<h1>Auth required</h1>'))
                params = _cc_urlparse.parse_qs(parsed.query)
                cid = (params.get('call', [None])[0]) or None
                return self._send(200, _cc_render_dispatch_page(
                    _CC_OPERATOR_TOKEN, cid))
            if path == '/dispatch/inboxes':
                if not self._check_token():
                    return self._send(401, _cc_render_base('Auth required', '',
                        '<h1>Auth required</h1>'))
                return self._send(200, _cc_render_inboxes_index_page(
                    _CC_OPERATOR_TOKEN))
            if path.startswith('/unit/'):
                # Per-unit receiver page
                callsign = _cc_urlparse.unquote(path[len('/unit/'):])
                # Auth either by ?token (operator) OR ?utoken (unit token)
                if not (self._check_token() or self._check_unit_token(callsign)):
                    return self._send(401, _cc_render_base('Auth required', '',
                        '<h1>Auth required</h1>'
                        '<p>Append <code>?utoken=UNIT_TOKEN</code> '
                        'or <code>?token=OPERATOR_TOKEN</code>.</p>'))
                return self._send(200, _cc_render_unit_receiver_page(
                    callsign, _CC_OPERATOR_TOKEN))
            if path.startswith('/api/unit/') and path.endswith('/inbox'):
                callsign = _cc_urlparse.unquote(
                    path[len('/api/unit/'):-len('/inbox')])
                if not (self._check_token() or self._check_unit_token(callsign)):
                    return self._send_json(401, {'error': 'unauthorized'})
                only_pending = (_cc_urlparse.parse_qs(parsed.query)
                                .get('pending', ['0'])[0] == '1')
                return self._send_json(200, {
                    'callsign': callsign,
                    'inbox': dispatch_outbox.list_for(callsign, only_pending),
                })
            if path.startswith('/api/unit/') and path.endswith('/inbox/stream'):
                callsign = _cc_urlparse.unquote(
                    path[len('/api/unit/'):-len('/inbox/stream')])
                if not (self._check_token() or self._check_unit_token(callsign)):
                    return self._send_json(401, {'error': 'unauthorized'})
                return self._stream_unit_inbox_sse(callsign)
            if path == '/api/dispatch/inboxes':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                summary = []
                for cs in dispatch_outbox.all_units():
                    pending = dispatch_outbox.list_for(cs, only_pending=True)
                    all_p = dispatch_outbox.list_for(cs)
                    summary.append({
                        'callsign': cs,
                        'pending': len(pending),
                        'total': len(all_p),
                        'last_status': (all_p[-1].get('status')
                                         if all_p else None),
                        'last_sent_at': (all_p[-1].get('sent_at')
                                          if all_p else None),
                    })
                return self._send_json(200, {'inboxes': summary})
            return self._send(404, _cc_render_base('Not found', '', '<h1>404</h1>'))
        except Exception as e:
            _cc_logger.error(f'GET {self.path} failed: {e}')
            try:
                self._send(500, f'<h1>500</h1><pre>{_cc_html.escape(str(e))}</pre>')
            except Exception:
                pass

    def do_POST(self):
        try:
            parsed = _cc_urlparse.urlparse(self.path)
            path = parsed.path
            # Public caller endpoints (no token): place a call, add a chunk, hang up.
            # Reasoning: a 911 redirector won't have the operator token; the
            # caller-facing flow must be reachable without one. The operator
            # console (which exposes ALL sessions) is token-gated.
            # ── SIP / Twilio inbound webhook ──
            # When a real telephony adapter (Twilio, Telnyx, FreePBX, SIP
            # gateway) routes an incoming call to AIdispatch, it POSTs
            # carrier-supplied caller ID here. We create a session
            # immediately so the operator sees the ring; the AI will
            # process actual speech via the existing /chunk endpoint as
            # the carrier transcribes the audio leg.
            #
            # Accepts BOTH:
            #   - JSON: {"From": "+1555...", "To": "...", "CallSid": "..."}
            #   - Twilio form-encoded: From=...&To=...&CallSid=...
            # Returns 200 + minimal TwiML pointing at /api/call/<id>/chunk
            # so a Twilio Media Streams setup can wire to it.
            if path == '/api/sip/incoming':
                data = self._read_json() or {}
                # Form-encoded fallback for Twilio/SIP gateways
                if not data:
                    try:
                        n = int(self.headers.get('Content-Length') or 0)
                        body = self.rfile.read(n).decode(errors='replace') if n else ''
                        data = dict(_cc_urlparse.parse_qsl(body))
                    except Exception:
                        data = {}
                phone = (data.get('From') or data.get('from')
                         or data.get('caller') or '').strip() or 'sip-anon'
                call_sid = data.get('CallSid') or data.get('call_sid') or ''
                cid = f'sip-{call_sid or int(time.time() * 1000)}'
                # Seed the session with a placeholder chunk so it materializes
                def _go():
                    try:
                        call_center_service.submit_call(
                            cid, phone, '[SIP call ringing]')
                    except Exception as e:
                        _cc_logger.error(f'/api/sip/incoming submit failed: {e}')
                threading.Thread(target=_go, daemon=True).start()
                deadline = time.time() + 2.0
                while time.time() < deadline:
                    if call_center_service.get_session(cid) is not None:
                        break
                    time.sleep(0.05)
                sess = call_center_service.get_session(cid) or {}
                # If client wants TwiML, return minimal greeting+stream stub
                if 'twilio' in (self.headers.get('User-Agent') or '').lower() \
                        or self.headers.get('X-Twilio-Signature'):
                    twiml = ('<?xml version="1.0" encoding="UTF-8"?>'
                             '<Response>'
                             '<Say voice="alice">You have reached AIdispatch. '
                             'Please describe your emergency.</Say>'
                             f'<Record action="/api/call/{cid}/audio" '
                             'maxLength="300" playBeep="true"/>'
                             '</Response>')
                    return self._send(200, twiml, 'application/xml')
                return self._send_json(200, {
                    'call_id': cid, 'call_number': sess.get('call_number'),
                    'ai_id': sess.get('ai_id'),
                    'location': sess.get('location'),
                })
            if path == '/api/call':
                data = self._read_json() or {}
                phone = (data.get('phone') or '').strip() or 'web-anon'
                text = (data.get('text') or '').strip()
                if not text:
                    return self._send_json(400, {'error': 'text required'})
                cid = f'web-{int(time.time() * 1000) % 1_000_000_000:09d}'
                def _go():
                    try:
                        call_center_service.submit_call(cid, phone, text)
                    except Exception as e:
                        _cc_logger.error(f'/api/call submit failed: {e}')
                threading.Thread(target=_go, daemon=True).start()
                # Wait briefly for session to materialize so the redirect lands on a real page
                deadline = time.time() + 2.0
                while time.time() < deadline:
                    if call_center_service.get_session(cid) is not None:
                        break
                    time.sleep(0.05)
                sess = call_center_service.get_session(cid) or {}
                # Capture caller's source IP and async-enrich with GeoIP
                try:
                    call_center_service.set_client_ip(cid, self._client_ip())
                except Exception:
                    pass
                # MedianBox: record this call as a tracked connection
                try:
                    rip = self._client_ip()
                    rport = self.client_address[1] if self.client_address else 0
                    lport = self.server.server_address[1]
                    medianbox.record_call_source(cid, rip, rport, lport, 'TCP')
                except Exception:
                    pass
                return self._send_json(200, {
                    'call_id': cid,
                    'call_number': sess.get('call_number'),
                    'ai_id': sess.get('ai_id'),
                })
            # ── TEXT-911: silent emergency text thread ──
            # Caller starts a session without speech and sends short SMS-style
            # messages. Same dispatch pipeline runs on every message; the
            # operator console + caller phone window see it as a normal call
            # but with channel='text'. Use this when a caller can't speak
            # safely (active intruder, ongoing assault, captivity).
            if path == '/api/text911/start':
                data = self._read_json() or {}
                phone = (data.get('phone') or '').strip() or 'sms-anon'
                cid = f'sms-{int(time.time() * 1000) % 1_000_000_000:09d}'
                # Create session with a placeholder chunk so submit_call
                # has something to score, then mark it as text-channel
                try:
                    call_center_service._ensure_session(cid, phone)
                    sess = call_center_service.get_session(cid)
                    if sess is not None:
                        sess['channel'] = 'text'
                        IncidentTimeline.append(
                            sess, IncidentTimeline.EV_OPERATOR_NOTE,
                            text='Text-911 thread opened (silent caller)',
                            by='caller')
                        call_center_service._publish_session('update', sess)
                except Exception as e:
                    _cc_logger.error(f'text911 start failed: {e}')
                # Capture caller's IP & register for medianbox tracking
                try:
                    call_center_service.set_client_ip(cid, self._client_ip())
                except Exception:
                    pass
                try:
                    rip = self._client_ip()
                    rport = self.client_address[1] if self.client_address else 0
                    lport = self.server.server_address[1]
                    medianbox.record_call_source(cid, rip, rport, lport, 'TCP')
                except Exception:
                    pass
                sess = call_center_service.get_session(cid) or {}
                return self._send_json(200, {
                    'call_id': cid,
                    'call_number': sess.get('call_number'),
                    'ai_id': sess.get('ai_id'),
                    'channel': 'text',
                })
            if path.startswith('/api/text911/') and path.endswith('/send'):
                # Caller posts a short message; we run it through the dispatch
                # pipeline like a normal chunk. Returns the AI's reply so the
                # caller's thread shows it inline.
                cid = _cc_urlparse.unquote(
                    path[len('/api/text911/'):-len('/send')])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                data = self._read_json() or {}
                text = (data.get('text') or '').strip()
                if not text:
                    return self._send_json(400, {'error': 'text required'})
                phone = sess.get('phone') or 'sms-anon'
                # Run synchronously so the caller's UI gets the AI reply now
                try:
                    trace = call_center_service.submit_call(cid, phone, text)
                except Exception as e:
                    _cc_logger.error(f'text911 send failed: {e}')
                    return self._send_json(500, {'error': str(e)})
                return self._send_json(200, {
                    'reply': trace.get('response') if trace else '',
                    'action': trace.get('action') if trace else '',
                    'priority': trace.get('priority') if trace else 0,
                    'escalation': trace.get('escalation') if trace else None,
                })
            if path.startswith('/api/call/') and path.endswith('/location'):
                # Browser-volunteered geolocation (navigator.geolocation)
                cid = _cc_urlparse.unquote(path[len('/api/call/'):-len('/location')])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                data = self._read_json() or {}
                try:
                    lat = float(data.get('lat'))
                    lon = float(data.get('lon'))
                except (TypeError, ValueError):
                    return self._send_json(400, {'error': 'lat/lon required'})
                acc = data.get('accuracy_m') or data.get('accuracy')
                source = (data.get('source') or 'browser').strip() or 'browser'
                extra = {}
                # Reverse-geocode coarsely to fill city/country if we have geoip
                # cache (we use the IP-derived data as a baseline if any).
                call_center_service.set_location(cid, lat, lon,
                                                 accuracy_m=acc, source=source,
                                                 extra=extra)
                return self._send_json(200, {'ok': True})
            if path.startswith('/api/call/') and path.endswith('/chunk'):
                cid = _cc_urlparse.unquote(path[len('/api/call/'):-len('/chunk')])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                data = self._read_json() or {}
                text = (data.get('text') or '').strip()
                if not text:
                    return self._send_json(400, {'error': 'text required'})
                phone = sess['phone']
                def _go():
                    try:
                        call_center_service.submit_call(cid, phone, text)
                    except Exception as e:
                        _cc_logger.error(f'/api/call/.../chunk failed: {e}')
                threading.Thread(target=_go, daemon=True).start()
                return self._send_json(200, {'ok': True})
            if path.startswith('/api/call/') and path.endswith('/audio'):
                # Voice fallback: browser uploaded a recorded audio blob.
                cid = _cc_urlparse.unquote(path[len('/api/call/'):-len('/audio')])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                data = self._read_json(max_bytes=8 * 1024 * 1024) or {}
                b64 = data.get('audio_b64') or ''
                mime = data.get('mime') or 'audio/webm'
                if not b64:
                    return self._send_json(400, {'error': 'audio_b64 required'})
                # Save blob to per-call audio dir
                try:
                    import base64 as _b64
                    raw = _b64.b64decode(b64)
                except Exception:
                    return self._send_json(400, {'error': 'bad_base64'})
                ext = '.webm' if 'webm' in mime else ('.ogg' if 'ogg' in mime else '.bin')
                audio_dir = os.path.join(
                    os.path.dirname(os.path.abspath(__file__)), 'call_audio')
                try:
                    os.makedirs(audio_dir, exist_ok=True)
                except Exception:
                    pass
                ts = datetime.now().strftime('%Y%m%d_%H%M%S_%f')[:-3]
                blob_path = os.path.join(audio_dir, f'{cid}_{ts}{ext}')
                try:
                    with open(blob_path, 'wb') as f:
                        f.write(raw)
                except Exception as e:
                    _cc_logger.error(f'audio save failed: {e}')
                # Background recorder uploads (bg=True) are archive-only —
                # SpeechRecognition is already feeding chunks; we don't want
                # to duplicate-transcribe.
                if data.get('bg'):
                    return self._send_json(200, {
                        'ok': True, 'archived': True, 'saved': blob_path})
                # Try server-side STT (opt-in; graceful skip if not installed)
                transcript = _cc_server_stt(blob_path, mime)
                if transcript:
                    phone = sess['phone']
                    def _go():
                        try:
                            call_center_service.submit_call(cid, phone, transcript)
                        except Exception as e:
                            _cc_logger.error(f'audio→chunk failed: {e}')
                    threading.Thread(target=_go, daemon=True).start()
                    return self._send_json(200, {
                        'ok': True, 'transcript': transcript,
                        'saved': blob_path})
                return self._send_json(200, {
                    'ok': True, 'transcript': None, 'saved': blob_path,
                    'note': 'server STT unavailable; audio saved'})
            if path.startswith('/api/call/') and path.endswith('/end'):
                cid = _cc_urlparse.unquote(path[len('/api/call/'):-len('/end')])
                sess = call_center_service.complete_call(cid, outcome='caller_hangup')
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                try:
                    medianbox.mark_call_ended(cid)
                except Exception:
                    pass
                return self._send_json(200, {'ok': True})
            if path.startswith('/api/session/') and path.endswith('/judge'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                cid = _cc_urlparse.unquote(path[len('/api/session/'):-len('/judge')])
                sess = call_center_service.get_session(cid)
                if sess is None or not sess.get('decisions'):
                    return self._send_json(404, {'error': 'not_found'})
                data = self._read_json() or {}
                key = sess['decisions'][-1].get('archive_key_used')
                if key is not None:
                    call_center_service.archive.record_outcome(
                        tuple(key), bool(data.get('confirmed')))
                return self._send_json(200, {'ok': True})
            if path.startswith('/api/call/') and path.endswith('/false_alarm'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                cid = _cc_urlparse.unquote(
                    path[len('/api/call/'):-len('/false_alarm')])
                data = self._read_json() or {}
                sess = call_center_service.mark_false_alarm(
                    cid, by=data.get('by', 'operator'))
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                return self._send_json(200, {'ok': True})
            # ── CAD: reset fleet to factory defaults ──
            if path == '/api/units/reset':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                count = unit_roster.reset_to_defaults()
                return self._send_json(200, {'ok': True, 'reset': count})
            # ── CAD: rebase the entire fleet to a region ──
            if path == '/api/units/rebase':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                data = self._read_json() or {}
                # Two modes:
                #   1. {lat, lon, radius_km}  → rebase to those coords
                #   2. {call_id}              → rebase to that call's location
                lat = data.get('lat')
                lon = data.get('lon')
                radius_km = float(data.get('radius_km', 8.0) or 8.0)
                cid = data.get('call_id')
                if cid and (lat is None or lon is None):
                    sess = call_center_service.get_session(cid)
                    if sess is None:
                        return self._send_json(404, {'error': 'call_not_found'})
                    loc = sess.get('location') or {}
                    lat = loc.get('lat')
                    lon = loc.get('lon')
                if lat is None or lon is None:
                    return self._send_json(400, {'error': 'lat/lon or call with location required'})
                moved = unit_roster.rebase_fleet(
                    lat, lon, radius_km=radius_km,
                    include_busy=bool(data.get('include_busy')))
                return self._send_json(200, {
                    'ok': True, 'moved': moved,
                    'center': {'lat': lat, 'lon': lon},
                    'radius_km': radius_km,
                })
            # ── CAD: roster management ──
            if path == '/api/units/add':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                data = self._read_json() or {}
                callsign = (data.get('callsign') or '').strip()
                unit_type = (data.get('unit_type') or '').strip().upper()
                try:
                    base_lat = float(data.get('base_lat', 0))
                    base_lon = float(data.get('base_lon', 0))
                except (TypeError, ValueError):
                    return self._send_json(400, {'error': 'bad coords'})
                if not callsign or unit_type not in ('EMS', 'POLICE', 'FIRE'):
                    return self._send_json(400, {'error': 'callsign + unit_type required'})
                if unit_roster.add_unit(callsign, unit_type, base_lat, base_lon):
                    return self._send_json(200, {'ok': True})
                return self._send_json(409, {'error': 'callsign exists'})
            if path == '/api/units/remove':
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                data = self._read_json() or {}
                callsign = (data.get('callsign') or '').strip()
                if unit_roster.remove_unit(callsign):
                    return self._send_json(200, {'ok': True})
                return self._send_json(404, {'error': 'not_found'})
            if path.startswith('/api/units/') and path.endswith('/status'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                callsign = _cc_urlparse.unquote(
                    path[len('/api/units/'):-len('/status')])
                data = self._read_json() or {}
                status = (data.get('status') or '').strip().upper()
                if not status:
                    return self._send_json(400, {'error': 'status required'})
                if unit_roster.set_status(callsign, status):
                    return self._send_json(200, {'ok': True})
                return self._send_json(404, {'error': 'not_found'})
            # ── CAD: comms log + manual operator note ──
            if path.startswith('/api/session/') and path.endswith('/comms'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                cid = _cc_urlparse.unquote(
                    path[len('/api/session/'):-len('/comms')])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                data = self._read_json() or {}
                msg = {
                    'ts': time.time(),
                    'wall': datetime.now().strftime('%H:%M:%S'),
                    'dir': data.get('dir', 'OUT'),    # OUT = dispatcher→unit
                    'from': data.get('from', 'DISPATCH'),
                    'to': data.get('to', 'ALL'),
                    'text': (data.get('text') or '').strip(),
                }
                if not msg['text']:
                    return self._send_json(400, {'error': 'text required'})
                sess.setdefault('comms', []).append(msg)
                IncidentTimeline.append(
                    sess,
                    IncidentTimeline.EV_COMMS_OUT if msg['dir'] == 'OUT'
                    else IncidentTimeline.EV_COMMS_IN,
                    **{k: v for k, v in msg.items() if k != 'ts'})
                call_center_service._publish_session('update', sess)
                return self._send_json(200, {'ok': True})
            if path.startswith('/api/session/') and path.endswith('/note'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                cid = _cc_urlparse.unquote(
                    path[len('/api/session/'):-len('/note')])
                sess = call_center_service.get_session(cid)
                if sess is None:
                    return self._send_json(404, {'error': 'not_found'})
                data = self._read_json() or {}
                text = (data.get('text') or '').strip()
                if not text:
                    return self._send_json(400, {'error': 'text required'})
                IncidentTimeline.append(
                    sess, IncidentTimeline.EV_OPERATOR_NOTE,
                    text=text, by=data.get('by', 'operator'))
                call_center_service._publish_session('update', sess)
                return self._send_json(200, {'ok': True})
            # ── DISPATCH: send tactical packet to one or more units ──
            if path.startswith('/api/call/') and path.endswith('/dispatch_unit'):
                if not self._check_token():
                    return self._send_json(401, {'error': 'unauthorized'})
                cid = _cc_urlparse.unquote(
                    path[len('/api/call/'):-len('/dispatch_unit')])
                data = self._read_json() or {}
                callsigns = data.get('callsigns') or data.get('callsign') or []
                if isinstance(callsigns, str):
                    callsigns = [c.strip() for c in callsigns.split(',') if c.strip()]
                packet = call_center_service.send_dispatch_to_unit(
                    cid,
                    callsigns,
                    plan_key=data.get('plan_key'),
                    message=data.get('message') or '',
                    attach_transcript=bool(data.get('attach_transcript', True)),
                    priority=data.get('priority'),
                    by=data.get('by', 'operator'),
                    custom_tactics=data.get('custom_tactics') or None,
                    area_only=bool(data.get('area_only')),
                    radius_km=float(data.get('radius_km') or 50.0),
                    max_units_per_type=(int(data['max_units_per_type'])
                                         if data.get('max_units_per_type') else None),
                )
                if packet is None:
                    return self._send_json(404,
                        {'error': 'call_or_unit_missing'})
                return self._send_json(200, {'ok': True, 'dispatch': packet})
            # ── UNIT: acknowledge / update status on a dispatch packet ──
            if (path.startswith('/api/unit/')
                    and '/dispatch/' in path and path.endswith('/ack')):
                # /api/unit/<callsign>/dispatch/<dispatch_id>/ack
                tail = path[len('/api/unit/'):-len('/ack')]
                if '/dispatch/' not in tail:
                    return self._send_json(400, {'error': 'bad_path'})
                callsign, _, did = tail.partition('/dispatch/')
                callsign = _cc_urlparse.unquote(callsign)
                did = _cc_urlparse.unquote(did)
                if not (self._check_token() or self._check_unit_token(callsign)):
                    return self._send_json(401, {'error': 'unauthorized'})
                data = self._read_json() or {}
                status = (data.get('status') or 'received').strip().lower()
                if status not in ('received', 'en_route', 'on_scene',
                                   'cleared', 'declined', 'pending'):
                    return self._send_json(400, {'error': 'bad_status'})
                p = dispatch_outbox.update_status(
                    callsign, did, status,
                    by=data.get('by') or callsign,
                    note=(data.get('note') or '').strip())
                if p is None:
                    return self._send_json(404, {'error': 'not_found'})
                # Mirror unit-side status onto roster status when applicable
                _ROSTER_MIRROR = {
                    'en_route': _Unit.STATUS_EN_ROUTE,
                    'on_scene': _Unit.STATUS_ON_SCENE,
                    'cleared': _Unit.STATUS_AVAILABLE,
                }
                if status in _ROSTER_MIRROR:
                    try:
                        unit_roster.set_status(callsign, _ROSTER_MIRROR[status])
                    except Exception:
                        pass
                # Mirror into call timeline + comms
                try:
                    sess = call_center_service.get_session(p.get('call_id'))
                    if sess is not None:
                        sess.setdefault('comms', []).append({
                            'ts': time.time(),
                            'wall': datetime.now().strftime('%H:%M:%S'),
                            'dir': 'IN',
                            'from': callsign,
                            'to': 'DISPATCH',
                            'text': f'{status.upper()}'
                                    + (f' :: {data.get("note","")}'
                                       if data.get('note') else ''),
                            'dispatch_id': did,
                        })
                        IncidentTimeline.append(
                            sess, IncidentTimeline.EV_COMMS_IN,
                            from_=callsign, to='DISPATCH',
                            text=f'ACK {did} status={status}',
                            dispatch_id=did)
                        call_center_service._publish_session('update', sess)
                except Exception as e:
                    _cc_logger.error(f'unit ack mirror failed: {e}')
                return self._send_json(200, {'ok': True, 'dispatch': p})
            # ── UNIT: free-form comms reply on a dispatch packet ──
            if (path.startswith('/api/unit/')
                    and '/dispatch/' in path and path.endswith('/reply')):
                tail = path[len('/api/unit/'):-len('/reply')]
                callsign, _, did = tail.partition('/dispatch/')
                callsign = _cc_urlparse.unquote(callsign)
                did = _cc_urlparse.unquote(did)
                if not (self._check_token() or self._check_unit_token(callsign)):
                    return self._send_json(401, {'error': 'unauthorized'})
                data = self._read_json() or {}
                text = (data.get('text') or '').strip()
                if not text:
                    return self._send_json(400, {'error': 'text required'})
                p = dispatch_outbox.find(callsign, did)
                if p is None:
                    return self._send_json(404, {'error': 'not_found'})
                p.setdefault('replies', []).append({
                    'ts': time.time(),
                    'wall': datetime.now().strftime('%H:%M:%S'),
                    'from': callsign, 'text': text,
                })
                dispatch_outbox._save()
                _cc_broadcast_unit_inbox(callsign, p)
                # Mirror into the call's comms log
                try:
                    sess = call_center_service.get_session(p.get('call_id'))
                    if sess is not None:
                        sess.setdefault('comms', []).append({
                            'ts': time.time(),
                            'wall': datetime.now().strftime('%H:%M:%S'),
                            'dir': 'IN',
                            'from': callsign, 'to': 'DISPATCH',
                            'text': text, 'dispatch_id': did,
                        })
                        IncidentTimeline.append(
                            sess, IncidentTimeline.EV_COMMS_IN,
                            from_=callsign, to='DISPATCH',
                            text=text, dispatch_id=did)
                        call_center_service._publish_session('update', sess)
                except Exception:
                    pass
                return self._send_json(200, {'ok': True})
            return self._send_json(404, {'error': 'not_found'})
        except Exception as e:
            _cc_logger.error(f'POST {self.path} failed: {e}')
            try:
                self._send_json(500, {'error': str(e)})
            except Exception:
                pass

    # ── SSE: server-sent events ──
    def _stream_sse(self):
        self.send_response(200)
        self.send_header('Content-Type', 'text/event-stream')
        self.send_header('Cache-Control', 'no-store')
        self.send_header('Connection', 'keep-alive')
        self.send_header('X-Accel-Buffering', 'no')
        self.end_headers()
        # Register this client
        client = {'wfile': self.wfile, 'queue': deque(maxlen=200),
                  'event': threading.Event(), 'alive': True}
        with _CCRequestHandler.sse_lock:
            _CCRequestHandler.sse_clients.append(client)
        try:
            self._sse_send_raw('hello', json.dumps({'time': time.time()}))
            # Bootstrap the client with current sessions so it doesn't have to
            # poll separately.
            with call_center_service._lock:
                sessions = list(call_center_service.sessions.values())
            for s in sessions:
                self._sse_send_raw('session', json.dumps(
                    {'event': 'snapshot', 'session': s}))
            # Stream loop
            last_ping = time.time()
            while client['alive']:
                if client['event'].wait(timeout=15.0):
                    client['event'].clear()
                    while client['queue']:
                        ev, data = client['queue'].popleft()
                        if not self._sse_send_raw(ev, data):
                            client['alive'] = False
                            break
                # heartbeat comment to keep connection open through proxies
                if time.time() - last_ping > 25.0:
                    try:
                        self.wfile.write(b': ping\n\n')
                        self.wfile.flush()
                        last_ping = time.time()
                    except Exception:
                        client['alive'] = False
                        break
        finally:
            with _CCRequestHandler.sse_lock:
                try:
                    _CCRequestHandler.sse_clients.remove(client)
                except ValueError:
                    pass

    def _sse_send_raw(self, event, data):
        try:
            self.wfile.write(f'event: {event}\n'.encode('utf-8'))
            for line in data.splitlines() or ['']:
                self.wfile.write(f'data: {line}\n'.encode('utf-8'))
            self.wfile.write(b'\n')
            self.wfile.flush()
            return True
        except Exception:
            return False

    def _stream_call_sse(self, call_id):
        """Per-call SSE: pushes 'decision' events whenever this call gets a new
        analyzed chunk, plus 'end' when the call closes. No token required —
        the caller's own browser uses this to play the AI's reply via TTS."""
        self.send_response(200)
        self.send_header('Content-Type', 'text/event-stream')
        self.send_header('Cache-Control', 'no-store')
        self.send_header('Connection', 'keep-alive')
        self.send_header('X-Accel-Buffering', 'no')
        self.end_headers()
        client = {'wfile': self.wfile, 'queue': deque(maxlen=200),
                  'event': threading.Event(), 'alive': True}
        with _CCRequestHandler.call_sse_lock:
            _CCRequestHandler.call_sse_clients[call_id].append(client)
        try:
            self._sse_send_raw('hello', json.dumps({'call_id': call_id}))
            # If the session already has decisions, replay the last one so the
            # client immediately sees current state.
            sess = call_center_service.get_session(call_id)
            if sess and sess.get('decisions'):
                last = sess['decisions'][-1]
                self._sse_send_raw('decision', json.dumps({
                    'action': last.get('action'),
                    'response': last.get('response'),
                    'aggregate': last.get('aggregate'),
                    'replay': True,
                }))
            last_ping = time.time()
            while client['alive']:
                if client['event'].wait(timeout=15.0):
                    client['event'].clear()
                    while client['queue']:
                        ev, data = client['queue'].popleft()
                        if not self._sse_send_raw(ev, data):
                            client['alive'] = False
                            break
                if time.time() - last_ping > 25.0:
                    try:
                        self.wfile.write(b': ping\n\n')
                        self.wfile.flush()
                        last_ping = time.time()
                    except Exception:
                        client['alive'] = False
                        break
        finally:
            with _CCRequestHandler.call_sse_lock:
                lst = _CCRequestHandler.call_sse_clients.get(call_id, [])
                try:
                    lst.remove(client)
                except ValueError:
                    pass
                if not lst:
                    _CCRequestHandler.call_sse_clients.pop(call_id, None)

    def _stream_unit_inbox_sse(self, callsign):
        """Per-unit SSE stream: pushes new dispatch packets + status updates."""
        self.send_response(200)
        self.send_header('Content-Type', 'text/event-stream')
        self.send_header('Cache-Control', 'no-store')
        self.send_header('Connection', 'keep-alive')
        self.send_header('X-Accel-Buffering', 'no')
        self.end_headers()
        client = {'wfile': self.wfile, 'queue': deque(maxlen=200),
                  'event': threading.Event(), 'alive': True}
        with _CCRequestHandler.unit_sse_lock:
            _CCRequestHandler.unit_sse_clients[callsign].append(client)
        try:
            self._sse_send_raw('hello', json.dumps({'callsign': callsign}))
            # Bootstrap with all pending packets
            for p in dispatch_outbox.list_for(callsign, only_pending=True):
                self._sse_send_raw('packet', json.dumps(p, default=str))
            last_ping = time.time()
            while client['alive']:
                if client['event'].wait(timeout=15.0):
                    client['event'].clear()
                    while client['queue']:
                        ev, data = client['queue'].popleft()
                        if not self._sse_send_raw(ev, data):
                            client['alive'] = False
                            break
                if time.time() - last_ping > 25.0:
                    try:
                        self.wfile.write(b': ping\n\n')
                        self.wfile.flush()
                        last_ping = time.time()
                    except Exception:
                        client['alive'] = False
                        break
        finally:
            with _CCRequestHandler.unit_sse_lock:
                lst = _CCRequestHandler.unit_sse_clients.get(callsign, [])
                try:
                    lst.remove(client)
                except ValueError:
                    pass
                if not lst:
                    _CCRequestHandler.unit_sse_clients.pop(callsign, None)


def _cc_broadcast_unit_inbox(callsign, packet):
    """Push a packet event to every connected unit SSE client for callsign."""
    try:
        data = json.dumps(packet, default=str)
        with _CCRequestHandler.unit_sse_lock:
            clients = list(_CCRequestHandler.unit_sse_clients.get(callsign) or [])
        for c in clients:
            c['queue'].append(('packet', data))
            c['event'].set()
    except Exception as e:
        _cc_logger.error(f'unit inbox broadcast failed: {e}')


try:
    dispatch_outbox.subscribe(_cc_broadcast_unit_inbox)
except Exception:
    pass


# =============================================================================
# TK VOICE PIPELINE — mic capture + STT + TTS for the Caller Phone window
# =============================================================================
# Owns three concerns:
#   (1) MIC CAPTURE   — push-to-talk via sounddevice + numpy, writes wav
#   (2) STT           — transcribe wav via Windows PowerShell SAPI grammar
#                       (no install) or SpeechRecognition lib (online, free)
#   (3) TTS           — speak AI replies via pyttsx3 (offline) or PowerShell
#                       System.Speech.Synthesis fallback (no install)
# All three degrade gracefully: if a backend is missing, voice features for
# that path become no-ops and the typed flow is unaffected.
# =============================================================================
class TkVoicePipeline:
    """Native Tk voice pipeline (mic capture + STT + TTS).

    Usage from a Tk window:
        pipe = TkVoicePipeline()
        pipe.start_recording()           # on push-to-talk press
        text = pipe.stop_recording_and_transcribe()  # on release; blocks briefly
        pipe.speak('Hello world', emergency=True)    # plays AI reply

    The TTS player runs on its own background thread so .speak() returns
    instantly. Calling .speak() again cancels the prior utterance so the
    AI's most recent decision is what the caller hears.
    """

    SAMPLE_RATE = 16000   # 16 kHz mono — what SAPI / SpeechRecognition expect
    CHANNELS = 1
    DTYPE = 'int16'

    def __init__(self):
        self._sd = None              # sounddevice module if available
        self._np = None              # numpy module if available
        self._sr_lib = None          # SpeechRecognition module if available
        self._tts_engine = None      # pyttsx3 engine if available
        self._tts_engine_lock = threading.Lock()

        self._recording = False
        self._frames = []            # collected audio chunks during a recording
        self._stream = None
        self._level = 0.0            # last-known mic peak level (0..1)
        self._level_lock = threading.Lock()

        self._tts_queue = deque()
        self._tts_thread = None
        self._tts_stop = threading.Event()
        self._tts_current_proc = None   # subprocess for PowerShell fallback

        self._init_backends()
        if self.has_tts():
            self._start_tts_worker()

    # ── Backend discovery ──────────────────────────────────────────
    def _init_backends(self):
        try:
            import sounddevice as _sd
            import numpy as _np
            self._sd = _sd
            self._np = _np
        except Exception as e:
            _cc_logger.info(f'TkVoice: sounddevice/numpy unavailable: {e} '
                            f'— mic capture disabled')

        try:
            import speech_recognition as _sr
            self._sr_lib = _sr
        except Exception:
            pass  # PowerShell SAPI fallback is still available on Windows

        try:
            import pyttsx3 as _pyttsx3
            self._tts_engine = _pyttsx3.init()
            # Slightly faster than default for active voice calls (~1.2x)
            try:
                cur_rate = self._tts_engine.getProperty('rate')
                self._tts_engine.setProperty('rate', int(cur_rate * 1.20))
            except Exception:
                pass
        except Exception as e:
            _cc_logger.info(f'TkVoice: pyttsx3 unavailable: {e} '
                            f'— will use PowerShell SAPI fallback for TTS')

    def has_mic(self):
        return self._sd is not None and self._np is not None

    def has_stt(self):
        # PowerShell SAPI works on any Windows box; SpeechRecognition lib
        # works anywhere (online via free Google recognizer)
        return self.has_mic() and (sys.platform == 'win32' or self._sr_lib is not None)

    def has_tts(self):
        return self._tts_engine is not None or sys.platform == 'win32'

    def status(self):
        """One-line capability summary for the Tk UI."""
        parts = []
        parts.append('mic ✓' if self.has_mic() else 'mic ✗ (install sounddevice)')
        if self.has_mic():
            if self._sr_lib:
                parts.append('STT: SpeechRecognition (online)')
            elif sys.platform == 'win32':
                parts.append('STT: SAPI (offline)')
            else:
                parts.append('STT ✗')
        if self._tts_engine:
            parts.append('TTS: pyttsx3 (offline)')
        elif sys.platform == 'win32':
            parts.append('TTS: SAPI (offline)')
        else:
            parts.append('TTS ✗')
        return '  ·  '.join(parts)

    # ── Mic capture ─────────────────────────────────────────────────
    def _audio_callback(self, indata, frames_count, time_info, status):
        if status:
            _cc_logger.debug(f'TkVoice mic status: {status}')
        if not self._recording:
            return
        try:
            self._frames.append(indata.copy())
            # Compute peak level for the meter (0..1)
            peak = float(self._np.abs(indata).max()) / 32768.0
            with self._level_lock:
                self._level = max(self._level * 0.6, peak)  # smooth decay
        except Exception:
            pass

    def get_level(self):
        with self._level_lock:
            v = self._level
            self._level = self._level * 0.85
            return v

    def start_recording(self):
        if not self.has_mic() or self._recording:
            return False
        self._frames = []
        self._recording = True
        try:
            self._stream = self._sd.InputStream(
                samplerate=self.SAMPLE_RATE,
                channels=self.CHANNELS,
                dtype=self.DTYPE,
                callback=self._audio_callback,
                blocksize=int(self.SAMPLE_RATE * 0.05))   # 50ms blocks
            self._stream.start()
            return True
        except Exception as e:
            _cc_logger.error(f'TkVoice: mic open failed: {e}')
            self._recording = False
            return False

    def stop_recording_and_transcribe(self, on_done=None):
        """Stop recording, save to a temp wav, transcribe in a background
        thread. on_done(text or None) is called from that thread."""
        if not self._recording:
            if on_done:
                on_done(None)
            return
        self._recording = False
        try:
            if self._stream is not None:
                self._stream.stop()
                self._stream.close()
        except Exception:
            pass
        self._stream = None
        if not self._frames:
            if on_done:
                on_done(None)
            return

        # Concatenate frames + write a 16kHz mono int16 WAV
        try:
            audio = self._np.concatenate(self._frames, axis=0)
        except Exception as e:
            _cc_logger.error(f'TkVoice: audio concat failed: {e}')
            if on_done:
                on_done(None)
            return
        self._frames = []

        # Skip ultra-short clips (< 200ms) — usually accidental taps
        if audio.shape[0] < int(self.SAMPLE_RATE * 0.2):
            if on_done:
                on_done(None)
            return

        # Write WAV
        try:
            import tempfile, wave as _wave
            tmp = tempfile.NamedTemporaryFile(suffix='.wav', delete=False)
            tmp_path = tmp.name
            tmp.close()
            with _wave.open(tmp_path, 'wb') as wf:
                wf.setnchannels(self.CHANNELS)
                wf.setsampwidth(2)   # int16
                wf.setframerate(self.SAMPLE_RATE)
                wf.writeframes(audio.tobytes())
        except Exception as e:
            _cc_logger.error(f'TkVoice: wav write failed: {e}')
            if on_done:
                on_done(None)
            return

        def _do_transcribe():
            text = self._transcribe_wav(tmp_path)
            try:
                os.unlink(tmp_path)
            except Exception:
                pass
            if on_done:
                try:
                    on_done(text)
                except Exception as e:
                    _cc_logger.error(f'TkVoice on_done callback failed: {e}')

        threading.Thread(target=_do_transcribe, daemon=True,
                         name='TkVoiceSTT').start()

    def _transcribe_wav(self, wav_path):
        """Try SpeechRecognition (online, fast, accurate) → SAPI fallback."""
        # Path 1: SpeechRecognition lib (Google free recognizer)
        if self._sr_lib is not None:
            try:
                r = self._sr_lib.Recognizer()
                with self._sr_lib.AudioFile(wav_path) as src:
                    audio = r.record(src)
                text = r.recognize_google(audio)
                if text:
                    return text.strip()
            except self._sr_lib.UnknownValueError:
                return None
            except Exception as e:
                _cc_logger.debug(f'TkVoice: recognize_google failed: {e}')
                # fall through to SAPI

        # Path 2: Windows SAPI via PowerShell (offline)
        if sys.platform == 'win32':
            try:
                ps = (
                    "Add-Type -AssemblyName System.Speech;"
                    "$r = New-Object System.Speech.Recognition.SpeechRecognitionEngine;"
                    "$r.LoadGrammar((New-Object System.Speech.Recognition.DictationGrammar));"
                    f"$r.SetInputToWaveFile('{wav_path}');"
                    "$res = $r.Recognize();"
                    "if ($res) {{ Write-Output $res.Text }}"
                ).replace('{{', '{').replace('}}', '}')
                proc = subprocess.run(
                    ['powershell', '-NoProfile', '-NonInteractive',
                     '-WindowStyle', 'Hidden', '-Command', ps],
                    timeout=20, capture_output=True, text=True,
                    creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))
                out = (proc.stdout or '').strip()
                if out:
                    return out
            except Exception as e:
                _cc_logger.debug(f'TkVoice: SAPI STT failed: {e}')

        return None

    # ── TTS ─────────────────────────────────────────────────────────
    def speak(self, text, emergency=False):
        """Queue an AI reply for speech. Cancels in-flight playback so the
        most recent decision is what the caller hears."""
        if not text or not self.has_tts():
            return
        # Cancel any in-flight utterance
        self._cancel_current_tts()
        self._tts_queue.append((text, bool(emergency)))

    def _cancel_current_tts(self):
        # pyttsx3: stop the engine
        if self._tts_engine is not None:
            try:
                self._tts_engine.stop()
            except Exception:
                pass
        # Clear the queue so we don't drain stale lines
        self._tts_queue.clear()
        # Kill any in-progress PowerShell synth process
        proc = self._tts_current_proc
        if proc is not None:
            try:
                proc.kill()
            except Exception:
                pass

    def _start_tts_worker(self):
        if self._tts_thread is not None:
            return
        self._tts_thread = threading.Thread(
            target=self._tts_worker, daemon=True, name='TkVoiceTTS')
        self._tts_thread.start()

    def _tts_worker(self):
        while not self._tts_stop.is_set():
            try:
                if not self._tts_queue:
                    time.sleep(0.05)
                    continue
                text, emergency = self._tts_queue.popleft()
                self._speak_now(text, emergency)
            except Exception as e:
                _cc_logger.error(f'TkVoice TTS worker error: {e}')
                time.sleep(0.1)

    def _speak_now(self, text, emergency):
        # Path 1: pyttsx3 (offline, fast)
        if self._tts_engine is not None:
            try:
                with self._tts_engine_lock:
                    base = self._tts_engine.getProperty('rate')
                    # Active call = 1.20x baseline; emergency = 1.30x
                    target = int(base / 1.20 * (1.30 if emergency else 1.20))
                    self._tts_engine.setProperty('rate', target)
                    self._tts_engine.say(text)
                    self._tts_engine.runAndWait()
                    self._tts_engine.setProperty('rate', base)
                return
            except Exception as e:
                _cc_logger.debug(f'TkVoice: pyttsx3 speak failed: {e}')

        # Path 2: PowerShell System.Speech.Synthesis with playback
        if sys.platform == 'win32':
            try:
                rate_i = 4 if emergency else 2
                wav = _cc_synthesize_speech(text, rate=rate_i)
                if not wav:
                    return
                import tempfile, winsound
                tmp = tempfile.NamedTemporaryFile(suffix='.wav', delete=False)
                tmp.write(wav); tmp.close()
                try:
                    winsound.PlaySound(tmp.name,
                        winsound.SND_FILENAME | winsound.SND_NODEFAULT)
                finally:
                    try:
                        os.unlink(tmp.name)
                    except Exception:
                        pass
            except Exception as e:
                _cc_logger.debug(f'TkVoice: PowerShell TTS playback failed: {e}')

    def shutdown(self):
        self._tts_stop.set()
        self._cancel_current_tts()
        try:
            if self._stream is not None:
                self._stream.stop()
                self._stream.close()
        except Exception:
            pass


# Module-level singleton — the Caller Phone window owns this
tk_voice_pipeline = TkVoicePipeline()


# ── Server-side TTS (Main_monolith PowerShell System.Speech pattern) ────
def _cc_synthesize_speech(text, rate=2):
    """Return WAV bytes via Windows System.Speech.Synthesis (PowerShell).
    Returns None on non-Windows or failure. Used as fallback for browsers
    without SpeechSynthesis (browser-side TTS is the primary path).

    `rate` is clamped to System.Speech's [-10, 10] range. Default +2 gives
    a slight speed-up that matches the voice page's ~1.20× client-side TTS.
    Pass rate=4 for emergency replies (matches client-side 1.30×)."""
    if sys.platform != 'win32':
        return None
    try:
        rate_i = max(-10, min(10, int(rate)))
    except Exception:
        rate_i = 2
    try:
        import tempfile, base64
        with tempfile.NamedTemporaryFile(suffix='.wav', delete=False) as wav_f:
            wav_path = wav_f.name
        # Pass text as base64 to avoid PowerShell quoting headaches
        b64 = base64.b64encode(text.encode('utf-8')).decode('ascii')
        ps = (
            f"$bytes = [Convert]::FromBase64String('{b64}');"
            "$txt = [System.Text.Encoding]::UTF8.GetString($bytes);"
            "Add-Type -AssemblyName System.Speech;"
            "$s = New-Object System.Speech.Synthesis.SpeechSynthesizer;"
            f"$s.Rate = {rate_i};"
            f"$s.SetOutputToWaveFile('{wav_path}');"
            "$s.Speak($txt); $s.Dispose();"
        )
        proc = subprocess.run(
            ['powershell', '-NoProfile', '-NonInteractive', '-WindowStyle', 'Hidden',
             '-Command', ps],
            timeout=15, capture_output=True,
            creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))
        if proc.returncode != 0 or not os.path.exists(wav_path):
            return None
        try:
            with open(wav_path, 'rb') as f:
                data = f.read()
        finally:
            try:
                os.unlink(wav_path)
            except Exception:
                pass
        return data
    except Exception as e:
        _cc_logger.error(f'tts synthesize failed: {e}')
        return None


# ── Optional server-side STT (Whisper / Vosk; graceful skip) ────────────
_cc_stt_state = {'tried': False, 'engine': None, 'model': None}

def _cc_server_stt(audio_path, mime):
    """Attempt to transcribe an audio blob server-side.

    Tries openai-whisper first (if installed), then vosk. Returns the
    transcript string or None. The caller treats None as 'audio saved
    but not transcribed' — the browser-side Web Speech API is the
    primary path; this exists for browsers that lack it."""
    try:
        if not _cc_stt_state['tried']:
            _cc_stt_state['tried'] = True
            try:
                import whisper as _whisper  # type: ignore
                _cc_stt_state['engine'] = 'whisper'
                _cc_stt_state['model'] = _whisper.load_model('base')
                _cc_logger.info('STT: whisper engine loaded')
            except Exception:
                try:
                    from vosk import Model as _VoskModel  # type: ignore
                    # Don't auto-download a model; require env var
                    mp = os.environ.get('VOSK_MODEL_PATH')
                    if mp and os.path.exists(mp):
                        _cc_stt_state['engine'] = 'vosk'
                        _cc_stt_state['model'] = _VoskModel(mp)
                        _cc_logger.info('STT: vosk engine loaded')
                except Exception:
                    pass
        eng = _cc_stt_state['engine']
        if eng == 'whisper':
            r = _cc_stt_state['model'].transcribe(audio_path)
            return (r.get('text') or '').strip() or None
        if eng == 'vosk':
            # Vosk needs WAV mono PCM; webm/ogg blobs would need ffmpeg.
            # If you have it, point VOSK_FFMPEG to ffmpeg.exe.
            ffmpeg = os.environ.get('VOSK_FFMPEG') or 'ffmpeg'
            wav_path = audio_path + '.wav'
            try:
                subprocess.run(
                    [ffmpeg, '-y', '-i', audio_path, '-ar', '16000', '-ac', '1',
                     '-f', 'wav', wav_path],
                    capture_output=True, timeout=30,
                    creationflags=getattr(subprocess, 'CREATE_NO_WINDOW', 0))
            except Exception:
                return None
            if not os.path.exists(wav_path):
                return None
            try:
                from vosk import KaldiRecognizer  # type: ignore
                import wave as _wave
                with _wave.open(wav_path, 'rb') as wf:
                    rec = KaldiRecognizer(_cc_stt_state['model'], wf.getframerate())
                    while True:
                        data = wf.readframes(4000)
                        if not data:
                            break
                        rec.AcceptWaveform(data)
                    final = json.loads(rec.FinalResult() or '{}')
                    return (final.get('text') or '').strip() or None
            finally:
                try:
                    os.unlink(wav_path)
                except Exception:
                    pass
    except Exception as e:
        _cc_logger.error(f'STT failed: {e}')
    return None


def _cc_broadcast_session(event, session):
    """Push a session event to all connected SSE clients (operator console)
    AND a per-call 'decision'/'end' event to call-specific listeners
    (the caller's own browser, for live AI replies + TTS)."""
    payload = json.dumps({'event': event, 'session': session})
    with _CCRequestHandler.sse_lock:
        clients = list(_CCRequestHandler.sse_clients)
    for c in clients:
        try:
            c['queue'].append(('session', payload))
            c['event'].set()
        except Exception:
            pass
    # Per-call broadcast: only the latest decision is interesting to the caller
    cid = session.get('call_id')
    if not cid:
        return
    with _CCRequestHandler.call_sse_lock:
        call_clients = list(_CCRequestHandler.call_sse_clients.get(cid, []))
    if not call_clients:
        return
    if event == 'end':
        call_payload = json.dumps({'event': 'end',
                                   'outcome': session.get('outcome')})
        ev_name = 'end'
    else:
        last = (session.get('decisions') or [None])[-1]
        if not last:
            return
        call_payload = json.dumps({
            'action':    last.get('action'),
            'response':  last.get('response'),
            'aggregate': last.get('aggregate'),
            'escalation': last.get('escalation'),
        })
        ev_name = 'decision'
    for c in call_clients:
        try:
            c['queue'].append((ev_name, call_payload))
            c['event'].set()
        except Exception:
            pass


class DispatchWebServer:
    """Embedded HTTP/SSE server bound to the call-center service."""

    def __init__(self, host=_CC_HTTP_HOST, port=_CC_HTTP_PORT):
        self.host = host
        self.port = port
        self.token = _CC_OPERATOR_TOKEN
        self._server = None
        self._thread = None
        self._started = False

    def start(self):
        if self._started:
            return
        # Try the configured port; if busy, walk up to +20.
        last_err = None
        for offset in range(0, 21):
            try:
                self._server = _CCThreadingServer(
                    (self.host, self.port + offset), _CCRequestHandler)
                self.port = self.port + offset
                last_err = None
                break
            except OSError as e:
                last_err = e
                continue
        if last_err is not None:
            _cc_logger.error(f'web server bind failed: {last_err}')
            return
        self._thread = threading.Thread(
            target=self._server.serve_forever, daemon=True,
            name='DispatchWebServer')
        self._thread.start()
        self._started = True
        # Subscribe broadcaster to the call-center service so SSE clients
        # get session start/update/end events live.
        try:
            call_center_service.subscribe_sessions(_cc_broadcast_session)
        except Exception:
            pass
        _cc_logger.info('=' * 70)
        _cc_logger.info(f'AIdispatch web server: http://{self.host}:{self.port}/')
        _cc_logger.info(f'  caller UI : http://{self.host}:{self.port}/')
        _cc_logger.info(f'  operator  : http://{self.host}:{self.port}/console?token={self.token}')
        _cc_logger.info(f'  hub       : http://{self.host}:{self.port}/hub?token={self.token}')
        _cc_logger.info(f'  health    : http://{self.host}:{self.port}/api/health')
        _cc_logger.info('=' * 70)
        # Write the token + URLs to a file so an operator who missed the
        # boot log can still get back into the console.
        try:
            tok_path = os.path.join(
                os.path.dirname(os.path.abspath(__file__)),
                'dispatch_token.txt')
            with open(tok_path, 'w', encoding='utf-8') as f:
                f.write(f'AIdispatch operator token\n')
                f.write(f'={"=" * 40}\n\n')
                f.write(f'TOKEN: {self.token}\n\n')
                f.write(f'Caller UI:  http://{self.host}:{self.port}/\n')
                f.write(f'Console:    http://{self.host}:{self.port}/console?token={self.token}\n')
                f.write(f'Hub:        http://{self.host}:{self.port}/hub?token={self.token}\n')
                f.write(f'Health:     http://{self.host}:{self.port}/api/health\n')
                f.write(f'\nGenerated: {datetime.now().isoformat()}\n')
            _cc_logger.info(f'  token file: {tok_path}')
        except Exception as e:
            _cc_logger.warning(f'token file write failed: {e}')

    def stop(self):
        if not self._started:
            return
        try:
            self._server.shutdown()
            self._server.server_close()
        except Exception:
            pass
        self._started = False

    def caller_url(self):
        return f'http://{self.host}:{self.port}/'

    def console_url(self):
        return f'http://{self.host}:{self.port}/console?token={self.token}'


# Module-level singleton — the operator owns this
dispatch_web = DispatchWebServer()



