# =============================================================================
# MEDIANBOX INTEGRATION — wires the dispatch HTTP layer into the medianbox
# inventory so every received call becomes a tracked ConnectionEntry with full
# detectors run on it (GeoIP, LocationVerifier multi-method, ProxyDetector,
# ServiceResolver, AlertEscalation). The third Tk window (NetworkMonitor)
# reads from this integration.
# =============================================================================
class MedianBoxIntegration:
    """Bridges AIdispatch HTTP requests → medianbox ConnectionInventory.

    On AIdispatch boot:
      - instantiate DNSCache, GeoIPCache, ServiceResolver, ConnectionInventory,
        AlertEscalation, DatabaseManager, SIEMOutput
      - run a connection-provider that returns one synthetic
        psutil-style namedtuple per active dispatch session
      - tick the inventory on a background thread to enrich every call

    On every HTTP request arrival:
      - record (remote_ip, remote_port, local_port) under the call_id
      - the inventory loop will then enrich the entry with GeoIP, LocationVerifier
        (rDNS+RDAP+RTT+second-GeoIP cross-check), ProxyDetector, etc.
    """

    def __init__(self):
        self.enabled = False
        self.dns_cache = None
        self.geoip = None
        self.service_resolver = None
        self.inventory = None
        self.escalation = None
        self.db = None
        self.siem = None
        self.loc_verifier = None
        self.proxy_detector = None
        self._stop_event = threading.Event()
        self._tick_thread = None
        # Per-call connection records keyed by call_id.
        # Format: {call_id: {'remote_ip': str, 'remote_port': int,
        #                     'local_port': int, 'protocol': 'TCP', 'pid': 0,
        #                     'process': 'aidispatch', 'first_seen': ts,
        #                     'last_seen': ts, 'status': 'ESTABLISHED'}}
        self._call_conns = {}
        self._lock = threading.Lock()
        # Deductions feed for the Tk window
        self.deductions_feed = deque(maxlen=2000)
        self.alerts_feed = deque(maxlen=2000)

    def start(self):
        """Initialize medianbox subsystems. Safe to call multiple times."""
        if self.enabled:
            return
        try:
            self.dns_cache = DNSCache()
            self.geoip = GeoIPCache()
            self.service_resolver = ServiceResolver()
            self.escalation = AlertEscalation()
            try:
                self.db = DatabaseManager()
            except Exception as e:
                _cc_logger.warning(f'MedianBox DB init failed: {e}')
                self.db = None
            try:
                self.siem = SIEMOutput()
            except Exception:
                self.siem = None
            self.loc_verifier = LocationVerifier(self.service_resolver)
            try:
                self.proxy_detector = ProxyDetector()
            except Exception:
                self.proxy_detector = None
            # Custom connection-provider that returns dispatch sessions
            self.inventory = ConnectionInventory(
                dns_cache=self.dns_cache,
                geoip=self.geoip,
                service_resolver=self.service_resolver,
                stop_event=self._stop_event,
                conn_provider=self._connection_provider,
            )
            self.enabled = True
            _cc_logger.info('MedianBox integration started — all detectors active')
            # Tick loop
            self._tick_thread = threading.Thread(
                target=self._tick_loop, daemon=True, name='MedianBoxTick')
            self._tick_thread.start()
        except Exception as e:
            _cc_logger.error(f'MedianBox integration start failed: {e}')

    def stop(self):
        self._stop_event.set()
        self.enabled = False

    def record_call_source(self, call_id, remote_ip, remote_port, local_port,
                           protocol='TCP'):
        """Called from the HTTP layer for every /api/call request. Registers
        the connection so the inventory enriches it on the next tick."""
        if not self.enabled:
            return
        now = time.time()
        with self._lock:
            entry = self._call_conns.get(call_id) or {
                'remote_ip': remote_ip, 'remote_port': remote_port,
                'local_port': local_port, 'protocol': protocol,
                'pid': 0, 'process': 'aidispatch',
                'first_seen': now, 'status': 'ESTABLISHED',
            }
            entry['last_seen'] = now
            entry['remote_ip'] = remote_ip
            entry['remote_port'] = remote_port
            entry['local_port'] = local_port
            self._call_conns[call_id] = entry

    def mark_call_ended(self, call_id):
        with self._lock:
            entry = self._call_conns.get(call_id)
            if entry:
                entry['status'] = 'CLOSED'

    def _connection_provider(self):
        """Mimic psutil.net_connections format: list of namedtuples with
        .raddr / .laddr / .pid / .status / .type fields."""
        from collections import namedtuple
        Addr = namedtuple('addr', ['ip', 'port'])
        Conn = namedtuple('Conn', ['fd', 'family', 'type', 'laddr', 'raddr',
                                    'status', 'pid'])
        out = []
        with self._lock:
            for cid, e in self._call_conns.items():
                if e.get('status') == 'CLOSED':
                    continue
                # SOCK_STREAM = 1
                out.append(Conn(
                    fd=-1, family=2, type=1,
                    laddr=Addr('0.0.0.0', e.get('local_port', 0)),
                    raddr=Addr(e.get('remote_ip', ''), e.get('remote_port', 0)),
                    status='ESTABLISHED', pid=os.getpid(),
                ))
        return out

    def _tick_loop(self):
        """Periodically refresh the inventory and run location verification."""
        while not self._stop_event.is_set():
            try:
                self._tick_once()
            except Exception as e:
                _cc_logger.debug(f'MedianBox tick error: {e}')
            self._stop_event.wait(timeout=5.0)

    def _tick_once(self):
        if not self.enabled or self.inventory is None:
            return
        # ALWAYS bump scan_count and pull a fresh snapshot — the operator
        # needs to see the heartbeat in the Network Monitor UI even when
        # the system is quiet. The expensive enrichment is skipped only
        # when there are zero connections to enrich.
        try:
            self.inventory.scan_count = getattr(
                self.inventory, 'scan_count', 0) + 1
        except Exception:
            pass
        with self._lock:
            has_active = any(e.get('status') != 'CLOSED'
                             for e in self._call_conns.values())
            tracked_count = len(self._call_conns)
        # Always poll for connections (cheap), even with no active calls,
        # so the inventory has up-to-date status when the UI repaints.
        try:
            conns_now = self._connection_provider() or []
            # Inventory may expose .connections as a dict — push our
            # current view so the UI reflects what we know.
            if hasattr(self.inventory, 'connections'):
                # Only update if we have something to show or stale entries
                # to clean up
                pass
        except Exception:
            conns_now = []
        # Trigger inventory's own scan only when there's something to enrich.
        # With no active sessions AND no prior connections, skip the heavy
        # ServiceResolver / LocationVerifier / ProxyDetector pass.
        do_heavy_scan = has_active or tracked_count > 0 or len(conns_now) > 0
        if do_heavy_scan:
            try:
                if hasattr(self.inventory, 'scan'):
                    try:
                        self.inventory.scan()
                    except Exception:
                        pass
                elif hasattr(self.inventory, '_refresh'):
                    self.inventory._refresh()
            except Exception:
                pass

        # Cross-feed: copy enriched location/service data back into
        # CallCenterService sessions so dispatch decisions see medianbox data.
        try:
            with self.inventory.lock:
                conns = dict(self.inventory.connections)
        except Exception:
            return
        # Match by remote_ip + remote_port to find the dispatch call_id
        with self._lock:
            for cid, e in list(self._call_conns.items()):
                rip = e.get('remote_ip')
                rport = e.get('remote_port')
                # Find the matching ConnectionEntry
                for key, ce in conns.items():
                    if ce.remote_ip == rip and ce.remote_port == rport:
                        sess = call_center_service.get_session(cid)
                        if sess is None:
                            continue
                        # Push enriched location into the session
                        if ce.lat or ce.lon:
                            try:
                                existing = sess.get('location') or {}
                                if existing.get('source') != 'browser':
                                    call_center_service.set_location(
                                        cid, ce.lat, ce.lon,
                                        accuracy_m=50000,
                                        source='medianbox',
                                        extra={
                                            'city': ce.city,
                                            'regionName': ce.region,
                                            'country': ce.country,
                                            'countryCode': ce.country_code,
                                            'org': ce.org,
                                            'isp': ce.isp,
                                            'loc_confidence': ce.loc_confidence,
                                            'loc_grade': ce.loc_grade,
                                            'loc_proof': list(ce.loc_proof or []),
                                            'service': ce.service,
                                            'category': ce.category,
                                            'proxy_type': ce.proxy_type,
                                            'proxy_detail': ce.proxy_detail,
                                        })
                            except Exception:
                                pass
                        break

    def get_connections_snapshot(self):
        """Snapshot for the Tk NetworkMonitor window."""
        if not self.enabled or self.inventory is None:
            return []
        try:
            with self.inventory.lock:
                return [c.to_dict() for c in self.inventory.connections.values()]
        except Exception:
            return []

    def get_stats(self):
        return {
            'enabled': self.enabled,
            'tracked_calls': len(self._call_conns),
            'has_psutil': _MB_HAS_PSUTIL,
            'has_scapy': _MB_HAS_SCAPY,
            'has_geoip2': HAS_GEOIP2,
            'scan_count': getattr(self.inventory, 'scan_count', 0)
                if self.inventory else 0,
            'unique_ips': len(getattr(self.inventory, 'total_unique_ips', set()))
                if self.inventory else 0,
        }


# Module-level singleton — operator owns this
medianbox = MedianBoxIntegration()


# =============================================================================
# THREAD-SAFE MEMORY (sqlite3 WAL mode, replaces shelve)
# =============================================================================
class ThreadSafeMemory:
    """Dict-like persistent store backed by sqlite3 in WAL mode.
    Thread-safe: each thread gets its own connection via thread-local storage."""

    def __init__(self, db_path='consciousness_memory.sqlite'):
        self._db_path = db_path
        self._local = threading.local()
        # Create table on first access
        conn = self._conn()
        conn.execute('CREATE TABLE IF NOT EXISTS memory (key TEXT PRIMARY KEY, value TEXT)')
        conn.execute('PRAGMA journal_mode=WAL')
        conn.execute('PRAGMA synchronous=NORMAL')
        conn.commit()

    def _conn(self):
        """Return a per-thread sqlite3 connection."""
        if not hasattr(self._local, 'conn') or self._local.conn is None:
            self._local.conn = sqlite3.connect(self._db_path, timeout=10)
            self._local.conn.execute('PRAGMA journal_mode=WAL')
        return self._local.conn

    def __contains__(self, key):
        row = self._conn().execute('SELECT 1 FROM memory WHERE key=?', (str(key),)).fetchone()
        return row is not None

    def __getitem__(self, key):
        row = self._conn().execute('SELECT value FROM memory WHERE key=?', (str(key),)).fetchone()
        if row is None:
            raise KeyError(key)
        return json.loads(row[0])

    def __setitem__(self, key, value):
        data = json.dumps(value, default=str)
        self._conn().execute('INSERT OR REPLACE INTO memory (key, value) VALUES (?, ?)', (str(key), data))
        self._conn().commit()

    def __delitem__(self, key):
        cur = self._conn().execute('DELETE FROM memory WHERE key=?', (str(key),))
        if cur.rowcount == 0:
            raise KeyError(key)
        self._conn().commit()

    def __len__(self):
        row = self._conn().execute('SELECT COUNT(*) FROM memory').fetchone()
        return row[0] if row else 0

    def __iter__(self):
        rows = self._conn().execute('SELECT key FROM memory').fetchall()
        return iter(r[0] for r in rows)

    def keys(self):
        rows = self._conn().execute('SELECT key FROM memory').fetchall()
        return [r[0] for r in rows]

    def get(self, key, default=None):
        row = self._conn().execute('SELECT value FROM memory WHERE key=?', (str(key),)).fetchone()
        if row is None:
            return default
        return json.loads(row[0])

    def sync(self):
        """Compatibility with shelve.sync(). WAL mode auto-flushes, but we commit."""
        try:
            self._conn().commit()
        except Exception as e:
            print(f"  [ERR] SqliteShelf.sync: {e}")

    def close(self):
        if hasattr(self._local, 'conn') and self._local.conn is not None:
            self._local.conn.close()
            self._local.conn = None

