def _theme_apply_ttk(root):
    """Apply theme to ttk widgets (Notebook tabs, Treeview, Scrollbar, Combobox)."""
    try:
        style = ttk.Style(root)
        try:
            style.theme_use('clam')
        except Exception:
            pass
        T = USA_THEME
        # Notebook
        style.configure('USA.TNotebook', background=T['bg'],
                        borderwidth=0, tabmargins=[2, 4, 2, 0])
        style.configure('USA.TNotebook.Tab',
                        background=T['bg_panel'], foreground=T['fg'],
                        padding=[14, 6], font=('Cambria', 10, 'bold'),
                        borderwidth=1)
        style.map('USA.TNotebook.Tab',
                  background=[('selected', T['red']),
                              ('active', T['blue'])],
                  foreground=[('selected', T['white']),
                              ('active', T['white'])])
        # Treeview
        style.configure('USA.Treeview',
                        background=T['bg_panel'],
                        fieldbackground=T['bg_panel'],
                        foreground=T['fg'],
                        rowheight=22,
                        bordercolor=T['border'],
                        font=('Consolas', 9))
        style.configure('USA.Treeview.Heading',
                        background=T['blue'], foreground=T['white'],
                        font=('Cambria', 10, 'bold'),
                        relief='flat')
        style.map('USA.Treeview',
                  background=[('selected', T['red'])],
                  foreground=[('selected', T['white'])])
        # Scrollbar
        style.configure('USA.Vertical.TScrollbar',
                        background=T['bg_panel'], troughcolor=T['bg'],
                        bordercolor=T['border'], arrowcolor=T['fg'])
        # Combobox
        style.configure('USA.TCombobox',
                        fieldbackground=T['bg_entry'],
                        background=T['bg_panel'],
                        foreground=T['fg'],
                        arrowcolor=T['fg'])
    except Exception:
        pass


def _theme_banner(parent, title='AIDISPATCH', subtitle=''):
    """Slim Old-Glory federal banner: navy canton with gold ★ + title on
    the left (fits content, no clipping), thin red center field with the
    subtitle, navy plate on the right with the federal seal mark.
    Followed by 3 thin red/white stripes (mini-flag) under a gold rule.
    Total banner height ~52px so it doesn't dominate the window."""
    T = USA_THEME

    # ── Top bar (52px) ──
    bar = tk.Frame(parent, bg=T['bg_banner'], height=52)
    bar.pack(fill=tk.X, side=tk.TOP)
    bar.pack_propagate(False)

    # LEFT: navy canton — auto-sized to content (no fixed width that can clip).
    canton = tk.Frame(bar, bg=T['blue'])
    canton.pack(side=tk.LEFT, fill=tk.Y)
    tk.Label(canton, text='★', font=('Cambria', 22, 'bold'),
             fg=T['gold_rule'], bg=T['blue']).pack(
                 side=tk.LEFT, padx=(14, 4), pady=4)
    tk.Label(canton, text=title, font=('Cambria', 16, 'bold'),
             fg=T['white'], bg=T['blue']).pack(
                 side=tk.LEFT, padx=(0, 14), pady=4)

    # CENTER: red field with single subtitle line (no duplicate agency label).
    center = tk.Frame(bar, bg=T['bg_banner'])
    center.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
    if subtitle:
        tk.Label(center, text='✦  ' + subtitle.upper() + '  ✦',
                 font=('Cambria', 11, 'bold italic'),
                 fg=T['gold_rule'], bg=T['bg_banner']).place(
                     relx=0.5, rely=0.5, anchor='center')

    # RIGHT: navy plate — auto-sized to content (was 240px → clipping).
    plate = tk.Frame(bar, bg=T['blue_dark'])
    plate.pack(side=tk.RIGHT, fill=tk.Y)
    plate_inner = tk.Frame(plate, bg=T['blue_dark'])
    plate_inner.pack(padx=14, pady=4, fill=tk.Y)
    tk.Label(plate_inner, text='⚖  OFFICIAL  ⚖',
             font=('Cambria', 11, 'bold'),
             fg=T['gold_rule'], bg=T['blue_dark']).pack()
    tk.Label(plate_inner, text='U.S. EMERGENCY DISPATCH',
             font=('Cambria', 7, 'bold'),
             fg=T['silver'], bg=T['blue_dark']).pack()

    # ── Stripe stack: thin gold rule, then 3 red+white stripes, blue base ──
    tk.Frame(parent, bg=T['gold_rule'], height=1).pack(fill=tk.X)
    for stripe_color in (T['red'], T['white'], T['red'],
                          T['white'], T['red']):
        tk.Frame(parent, bg=stripe_color, height=2).pack(fill=tk.X)
    tk.Frame(parent, bg=T['blue'], height=2).pack(fill=tk.X)
    tk.Frame(parent, bg=T['gold_rule'], height=1).pack(fill=tk.X)
    return bar


def _theme_section_header(parent, text, side=tk.TOP, anchor='w'):
    """Federal-document-style section header: gold star + serif title +
    gold-underlined rule. Use in place of plain tk.Label headers."""
    T = USA_THEME
    bg = parent.cget('bg') if hasattr(parent, 'cget') else T['bg']
    wrap = tk.Frame(parent, bg=bg)
    wrap.pack(fill=tk.X, side=side, padx=8, pady=(8, 2))
    row = tk.Frame(wrap, bg=bg)
    row.pack(fill=tk.X)
    tk.Label(row, text='★', font=('Cambria', 12, 'bold'),
             fg=T['gold_rule'], bg=bg).pack(side=tk.LEFT, padx=(0, 6))
    tk.Label(row, text=text.upper(),
             font=('Cambria', 12, 'bold'),
             fg=(T['fg_head_light'] if bg in (T['bg_alt'], T['bg_card'], T['bg_paper'])
                 else T['fg_head']),
             bg=bg, anchor=anchor).pack(side=tk.LEFT)
    # Gold rule line underneath
    tk.Frame(wrap, bg=T['gold_rule'], height=1).pack(fill=tk.X, pady=(2, 0))
    return wrap


def _theme_card(parent, **pack_kwargs):
    """Parchment card: aged-paper background with sepia-gold border.
    Use as a content container; child widgets should set bg=USA_THEME['bg_card']."""
    T = USA_THEME
    outer = tk.Frame(parent, bg=T['border_light'])  # gold-sepia border line
    outer.pack(**pack_kwargs)
    inner = tk.Frame(outer, bg=T['bg_card'])
    inner.pack(fill=tk.BOTH, expand=True, padx=2, pady=2)
    return inner


def _theme_window_switcher(parent, simulator):
    """Standard window-switcher bar at the bottom of each Tk window."""
    T = USA_THEME
    bar = tk.Frame(parent, bg=T['blue'], height=32)
    bar.pack(fill=tk.X, side=tk.BOTTOM)
    bar.pack_propagate(False)

    def _btn(text, cmd, bg=T['white'], fg=T['blue']):
        return tk.Button(bar, text=text, command=cmd,
                         bg=bg, fg=fg, font=('Cambria', 9, 'bold'),
                         activebackground=T['amber'], activeforeground=T['blue_dark'],
                         relief='flat', padx=10, pady=2, cursor='hand2')

    def _open_dashboard():
        try:
            d = getattr(simulator, 'monitoring_dashboard', None)
            if d and d.win.winfo_exists():
                d.win.deiconify(); d.win.lift(); d.win.focus_force()
        except Exception:
            pass

    def _open_netmon():
        try:
            n = getattr(simulator, 'network_monitor', None)
            if n and n.win.winfo_exists():
                n.win.deiconify(); n.win.lift(); n.win.focus_force()
            else:
                simulator.network_monitor = launch_network_monitor(simulator)
        except Exception as e:
            print(f'  [ERR] open netmon: {e}')

    def _open_phone():
        try:
            p = getattr(simulator, 'caller_phone', None)
            if p and p.win.winfo_exists():
                p.win.deiconify(); p.win.lift(); p.win.focus_force()
            else:
                simulator.caller_phone = launch_caller_phone(simulator)
        except Exception as e:
            print(f'  [ERR] open phone: {e}')

    def _open_internals():
        try:
            i = getattr(simulator, 'internals_window', None)
            if i and i.win.winfo_exists():
                i.win.deiconify(); i.win.lift(); i.win.focus_force()
            else:
                simulator.internals_window = launch_internals(simulator)
        except Exception as e:
            print(f'  [ERR] open internals: {e}')

    def _open_browser_console():
        try:
            url = simulator.dispatch_web.console_url()
            _cc_webbrowser.open_new_tab(url)
        except Exception:
            pass

    def _open_browser_caller():
        try:
            url = simulator.dispatch_web.caller_url()
            _cc_webbrowser.open_new_tab(url)
        except Exception:
            pass

    tk.Label(bar, text='🇺🇸  WINDOWS:',
             font=('Cambria', 9, 'bold'),
             fg=T['white'], bg=T['blue']).pack(side=tk.LEFT, padx=(12, 8))
    _btn('🛡 Dashboard',     _open_dashboard).pack(side=tk.LEFT, padx=2, pady=4)
    _btn('📞 Caller Phone',  _open_phone).pack(side=tk.LEFT, padx=2, pady=4)
    _btn('⬢ Network Monitor', _open_netmon).pack(side=tk.LEFT, padx=2, pady=4)
    _btn('🧠 Internals',      _open_internals).pack(side=tk.LEFT, padx=2, pady=4)
    tk.Frame(bar, width=1, bg=T['white']).pack(side=tk.LEFT, fill=tk.Y, padx=8, pady=6)
    _btn('🌐 Browser Console', _open_browser_console,
         bg=T['amber'], fg=T['blue']).pack(side=tk.LEFT, padx=2, pady=4)
    _btn('🌐 Caller UI',       _open_browser_caller,
         bg=T['amber'], fg=T['blue']).pack(side=tk.LEFT, padx=2, pady=4)
    return bar


def _safe(fn, default='—'):
    """Call fn(), return default on any error."""
    try:
        return fn()
    except Exception:
        return default


def _fmt(val, decimals=4):
    """Format a numeric value safely."""
    try:
        return f"{float(val):.{decimals}f}"
    except (TypeError, ValueError):
        return '—'


class MonitoringDashboard:
    """Creates and manages the monitoring Toplevel window."""

    # ----------------------------------------------------------------
    #  Construction
    # ----------------------------------------------------------------
    def __init__(self, simulator):
        """
        Parameters
        ----------
        simulator : ConsciousnessSimulator
            The running simulator instance to monitor.
        """
        self.sim = simulator
        self.root = simulator.root          # parent Tk
        self.chat_history = deque(maxlen=2000)
        self._update_interval = 3000        # ms between refreshes
        self._running = True

        # ── Toplevel window ──
        self.win = tk.Toplevel(self.root)
        self.win.title("🛡  AIDISPATCH — Operator Dashboard")
        self.win.geometry("1500x900")
        self.win.configure(bg=BG)
        self.win.protocol("WM_DELETE_WINDOW", self._on_close)

        # ── 🇺🇸 Theme: red/white/blue banner + ttk style ──
        _theme_apply_ttk(self.win)
        _theme_banner(self.win, title='AIDISPATCH',
                      subtitle='Operator Dashboard — Live Calls, Audit, Caller Map')

        # ── Legacy ttk styles (kept as aliases so existing tab code works) ──
        style = ttk.Style(self.win)
        T = USA_THEME
        style.configure('Dashboard.TNotebook', background=T['bg'], borderwidth=0)
        style.configure('Dashboard.TNotebook.Tab',
                        background=T['bg_panel'], foreground=T['fg'],
                        padding=[14, 6], font=('Cambria', 10, 'bold'))
        style.map('Dashboard.TNotebook.Tab',
                  background=[('selected', T['red']), ('active', T['blue'])],
                  foreground=[('selected', T['white']), ('active', T['white'])])
        style.configure('Dashboard.TFrame', background=T['bg'])
        style.configure('Panel.TLabelframe', background=T['bg_panel'],
                        foreground=T['fg_head'], font=FONT_HEAD,
                        bordercolor=T['border'])
        style.configure('Panel.TLabelframe.Label', background=T['bg_panel'],
                        foreground=T['fg_head'], font=FONT_HEAD)

        # ── Window switcher (bottom; built last so it sits at the bottom) ──
        _theme_window_switcher(self.win, simulator)

        # ── OS Control Toggle Bar ──
        self._build_os_control_bar()

        # ── Notebook ──
        self.notebook = ttk.Notebook(self.win, style='Dashboard.TNotebook')
        self.notebook.pack(fill=tk.BOTH, expand=True, padx=4, pady=4)

        # AIdispatch tabs first — they are the primary product surface.
        # ── DISPATCH-ONLY TABS ──
        # The CSv1 simulator legacy tabs (Overview/Entities/Modules/Thought/Chat
        # /Symbols/Neuron Groups/Screen/Charts) and the legacy Call Center
        # firehose are moved out to a separate Internals window — they were
        # cluttering dispatch ops. Click "🧠 Internals" in the bottom switcher
        # to open them on demand.
        self._build_livecalls_tab()      # tab 0: fabricated AIs (one per active call)
        self._build_dispatch_audit_tab() # tab 1: ultra-detail per-call reasoning
        self._build_callermap_tab()      # tab 2: world map of caller locations
        # Default to the Live Calls tab on open
        try:
            self.notebook.select(0)
        except Exception:
            pass

        # ── kick off refresh loop ──
        self._schedule_update()

    # ================================================================
    #  OS CONTROL TOGGLE BAR
    # ================================================================
    def _build_os_control_bar(self):
        """Persistent bar at the top of the dashboard for toggling OS control."""

        bar = tk.Frame(self.win, bg='#1a0000', relief='ridge', bd=2)
        bar.pack(fill=tk.X, padx=4, pady=(4, 0), ipady=4)

        # Warning icon + label
        self._os_notice = tk.Label(
            bar, text='',
            font=('Consolas', 10, 'bold'), fg=FG_WARN, bg='#1a0000', anchor='w')
        self._os_notice.pack(side=tk.LEFT, padx=(8, 4), fill=tk.X, expand=True)

        # Status indicator
        self._os_status_lbl = tk.Label(
            bar, text='', font=('Consolas', 12, 'bold'), bg='#1a0000', padx=10)
        self._os_status_lbl.pack(side=tk.LEFT, padx=4)

        # Toggle button
        self._os_toggle_btn = tk.Button(
            bar, text='', font=('Consolas', 11, 'bold'),
            relief='raised', padx=18, pady=6, cursor='hand2',
            command=self._toggle_os_control)
        self._os_toggle_btn.pack(side=tk.RIGHT, padx=(4, 12), pady=6)

        # Set initial state
        self._refresh_os_control_bar()

    def _refresh_os_control_bar(self):
        """Update the OS control bar to reflect current state."""
        enabled = CONFIG.get('os_control_enabled', False)
        env_set = os.environ.get('CS_OS_CONTROL_ENABLED', '0') == '1'
        both_on = enabled and env_set

        if both_on:
            self._os_status_lbl.config(text='OS CONTROL: ACTIVE', fg='#ff3333')
            self._os_toggle_btn.config(
                text='Disable OS Control', bg='#882222', fg='white',
                activebackground='#aa3333')
            self._os_notice.config(
                text='*NOTICE: AI can send keystrokes, move mouse, and '
                     'interact with your OS. Disable if not intended.',
                fg='#ff6644')
        else:
            self._os_status_lbl.config(text='OS CONTROL: OFF', fg=FG_GOOD)
            self._os_toggle_btn.config(
                text='Enable OS Control', bg='#224488', fg='white',
                activebackground='#3366aa')
            self._os_notice.config(
                text='*NOTICE: OS control is disabled. The AI cannot '
                     'send keystrokes or control the mouse.',
                fg=FG_DIM)

    def _toggle_os_control(self):
        """Toggle OS control on/off with a confirmation dialog."""
        currently_on = (CONFIG.get('os_control_enabled', False)
                        and os.environ.get('CS_OS_CONTROL_ENABLED', '0') == '1')

        if currently_on:
            # Turning OFF — no confirmation needed
            CONFIG['os_control_enabled'] = False
            os.environ['CS_OS_CONTROL_ENABLED'] = '0'
            self._refresh_os_control_bar()
            self._append_system_event(
                "[OS CONTROL] Disabled by user via dashboard toggle.")
        else:
            # Turning ON — require explicit confirmation
            result = messagebox.askokcancel(
                "Enable OS Control",
                "⚠  WARNING — ENABLING OS CONTROL  ⚠\n\n"
                "This will allow the AI to:\n"
                "  • Send keyboard input (keystrokes, hotkeys)\n"
                "  • Move and click the mouse\n"
                "  • Interact with any window on your desktop\n\n"
                "The AI will NOT autonomously use these capabilities\n"
                "unless explicitly commanded, but background threads\n"
                "COULD trigger OS actions if coded to do so.\n\n"
                "You can disable this at any time from the dashboard.\n\n"
                "Do you want to proceed?",
                icon='warning',
                parent=self.win)
            if result:
                CONFIG['os_control_enabled'] = True
                os.environ['CS_OS_CONTROL_ENABLED'] = '1'
                self._refresh_os_control_bar()
                self._append_system_event(
                    "[OS CONTROL] ENABLED by user via dashboard toggle. "
                    "AI can now send keystrokes and mouse events.")

    def _append_system_event(self, msg):
        """Log a system event to the chat tab if it exists."""
        try:
            timestamp = datetime.now().strftime('%H:%M:%S')
            self._append_chat(f"[{timestamp}] {msg}\n", 'system')
        except Exception:
            pass

