        self._state_frame.pack(fill=tk.X, padx=14, pady=(14, 8))
        # Gold border wrapper
        seal_border = tk.Frame(self._state_frame, bg=T['gold_rule'])
        seal_border.pack(fill=tk.X)
        seal_inner = tk.Frame(seal_border, bg=T['blue'])
        seal_inner.pack(fill=tk.X, padx=2, pady=2)
        # Top stars
        tk.Label(seal_inner, text='★  ★  ★  ★  ★',
                 font=('Cambria', 11, 'bold'),
                 fg=T['gold_rule'], bg=T['blue']).pack(pady=(6, 0))
        # State label
        self._state_label = tk.Label(
            seal_inner, text='READY  ·  PLACE A CALL TO BEGIN',
            font=('Cambria', 12, 'bold'),
            fg=T['silver'], bg=T['blue'])
        self._state_label.pack(pady=(4, 0))
        # Call number badge — large monospace digital readout
        self._call_number_label = tk.Label(
            seal_inner, text='— — —  · — — —  · — — — —',
            font=('Consolas', 26, 'bold'),
            fg=T['gold_rule'], bg=T['blue'])
